  const tutorContext = getTutorContext();
  const pedagogicalContext = `Você é um tutor financeiro brasileiro, pragmático e didático. Ensine sem economês desnecessário, priorize clareza, exemplo brasileiro, contabilidade aplicada e sempre termine com próxima ação prática quando fizer sentido. Se houver risco financeiro imediato, priorize proteção de caixa, dívida cara e reserva antes de investimento sofisticado. Regras de resposta: ${TUTOR_RESPONSE_RULES.join('; ')}.

CONTEXTO PEDAGÓGICO DA ACADEMIA:
- momento atual: ${tutorContext.currentMoment?.title || 'analisando'}
- estágio da jornada: ${tutorContext.journeyStage.title}
- descrição da jornada: ${tutorContext.journeyStage.description}
- aula recomendada: ${tutorContext.learningFocus?.title || 'nenhuma'}
- objetivo comportamental: ${tutorContext.learningFocus?.behaviorGoal || 'reforçar consistência financeira'}
- feature conectada: ${tutorContext.learningFocus?.feature || 'dashboard'}
- sinal contextual: ${tutorContext.contextSignal.signal?.title || 'sem sinal crítico no momento'}

Ao responder, você pode usar explicitamente os modos: explicar, exemplificar, comparar, mandar agir e revisar depois.`;

  const [messages, setMessages] = useState<Message[]>([
    {
      id: "1",
      role: "assistant",
      content: `Olá! Sou seu tutor financeiro inteligente. Analisei seus dados e posso ver que:

📊 **Score de Saúde Financeira:** ${insights.score}/100
💰 **Saldo Atual:** R$ ${context.balance.toLocaleString('pt-BR')}
📈 **Taxa de Poupança:** ${context.savingsRate.toFixed(1)}%

🎯 **Seu momento na Academia:** ${tutorContext.currentMoment?.title || 'analisando'}
🧭 **Estágio atual:** ${tutorContext.journeyStage.title}

${insights.summary}

${insights.alerts.length > 0 ? `\n**Alertas:**\n${insights.alerts.map(a => a.message).join('\n')}` : ''}

${tutorContext.learningFocus ? `\n**Próximo foco pedagógico:**\n${tutorContext.learningFocus.title} → ${tutorContext.learningFocus.behaviorGoal}` : ''}

Posso te ajudar em 5 modos: **explicar**, **simplificar**, **comparar**, **mandar agir** e **revisar depois**.

Como posso ajudar você a melhorar suas finanças hoje?`,
      timestamp: new Date(),
      type: "insight",
    },
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleClearChat = () => {
    setMessages([{
      id: Date.now().toString(),
      role: "assistant",
      content: "Memória volatizada. Sistema reiniciado. Como posso auditar seus fluxos agora?",
      timestamp: new Date(),
    }]);
  };

  const handleExportChat = () => {
    const chatText = messages.map(m => 
      `[${m.timestamp.toLocaleString('pt-BR')}] ${m.role === 'user' ? 'VOCÊ' : 'AI'}: ${m.content}`
    ).join('\n\n---\n\n');

    const blob = new Blob([chatText], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `meu-contador-chat-${new Date().toISOString().split('T')[0]}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: "user",
      content: input,
      timestamp: new Date(),
    };

    setMessages((prev) => [...prev, userMessage]);
    setInput("");
    setIsLoading(true);

    try {
      // STEP 1: Check for actionable intent
      const intent = parseIntent(input);

      if (
        intent.type !== "unknown" &&
        intent.type !== "query" &&
        intent.confidence > 0.7
      ) {
        const tempId = Date.now().toString() + "_temp";
        const tempMessage: Message = {
          id: tempId,
          role: "assistant",
          content: "Gravando o lançamento de dados...",
          timestamp: new Date(),
          type: "insight",
        };
        setMessages((prev) => [...prev, tempMessage]);

        const result = await executeAction(intent);

        const actionMessage: Message = {
          id: (Date.now() + 1).toString(),
          role: "assistant",
          content: result.success
            ? `✅ **AÇÃO EXECUTADA**\n\n${result.message}`
            : `❌ **ERRO**\n\n${result.message}`,
          timestamp: new Date(),
          type: result.success ? "insight" : "alert",
        };

        setMessages((prev) => [...prev.filter(m => m.id !== tempId), actionMessage]);
        setIsLoading(false);
        // Force overall dashboard refresh
        window.dispatchEvent(new Event("transaction-updated"));
        return;
      }

      // STEP 2: AI Q&A with full financial context
      const response = await fetchWithCircuitBreaker(
        "/api/ai-proxy",
        {
          method: "POST",
          credentials: "include",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            conversation: messages.map((m) => ({
              role: m.role,
              content: m.content,
            })),
            systemContext: `${aiContextString}\n\n${pedagogicalContext}`,
            userMessage: input,
            financialSnapshot: buildFinancialSnapshot(context, insights, metrics),
          }),
        },
        {
          maxRetries: 3,
          initialDelay: 1200,
          fallbackMessage: "Processando com análise local. Aguarde enquanto reconecto com o núcleo de IA.",
        }
      );

      if (!response.ok) {
        throw new Error("Falha na Rede Neural");
      }

      const data = await response.json();
      const aiResponse = data.response ?? "Não foi possível obter resposta da IA";

      let messageType: Message["type"] = "text";
      if (aiResponse.includes("recomendo") || aiResponse.includes("sugiro")) {
        messageType = "recommendation";
      } else if (aiResponse.includes("⚠") || aiResponse.includes("atenção")) {
        messageType = "alert";
      } else if (aiResponse.includes("📊") || aiResponse.includes("análise") || aiResponse.includes("Processando")) {
        messageType = "insight";
      }

      const assistantMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: "assistant",
        content: aiResponse,
        timestamp: new Date(),
        type: messageType,
      };

      setMessages((prev) => [...prev, assistantMessage]);
    } catch (error) {
      console.error("Erro no chat:", error);
      const errorMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: "assistant",
        content: "Erro ao processar. Suas finanças estão seguras, tente novamente.",
        timestamp: new Date(),
        type: "alert",
      };
      setMessages((prev) => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const suggestedQuestions = [
    "Como está minha saúde financeira?",
    "Explique sem economês onde estou errando",
    "Qual é meu próximo melhor passo financeiro?",
    "Explique como contador: meu dinheiro está saudável?",
    "Mostre em básico, prático e avançado",
    "Me explique com base na minha fase da Academia",
    "Onde posso economizar mais?",
    "Minha carteira está diversificada?",
    "Previsão do meu saldo no fim do mês",
  ];

  return (
    <div id="ai-chat-container" className="flex flex-col h-full bg-[#02040a] text-white">
      {/* High-Tech Header */}
      <div className="flex items-center justify-between p-6 border-b border-white/10 bg-gradient-to-r from-indigo-500/10 via-transparent to-purple-500/10">
        <div className="flex items-center gap-4">
          <div id="ai-context-indicator" className="relative p-3 bg-indigo-500/20 rounded-2xl ai-pulse-core">
            <Bot className="text-indigo-400" size={28} />
          </div>
          <div>
            <h3 className="font-black text-xl tracking-tighter text-glow">
              CENTRO DE INTELIGÊNCIA
            </h3>
            <div className="flex items-center gap-2">
              <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse" />
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">
                SISTEMA OPERACIONAL ATIVO
              </p>
            </div>
          </div>
        </div>
        <div style={{ display: "flex", gap: "8px" }}>
          <Button
            variant="ghost"
            size="sm"
            onClick={handleExportChat}
            className="text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-white"
          >
            Exportar
          </Button>
          <Button
            variant="ghost"
            size="sm"
            onClick={handleClearChat}
            className="text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-white"
          >
            Limpar
          </Button>
          {onClose && (
            <Button
              variant="ghost"
              size="icon"
              onClick={onClose}
              className="rounded-xl hover:bg-white/5 text-slate-400"
            >
              <X size={20} />
            </Button>
          )}
        </div>
      </div>

      {/* Messages - Immersive Layout */}
      <div
        className="flex-1 overflow-y-auto p-6 space-y-6 no-scrollbar"
        id="ai-chat-window"
      >
        <AnimatePresence initial={false}>
          {messages.map((message) => (
            <motion.div
              key={message.id}
              initial={{ opacity: 0, x: message.role === "user" ? 20 : -20 }}
              animate={{ opacity: 1, x: 0 }}
              className={`flex gap-4 ${
                message.role === "user" ? "flex-row-reverse" : ""
              }`}
            >
              <div
                className={`mt-1 h-10 w-10 shrink-0 rounded-xl flex items-center justify-center border ${
                  message.role === "user"
                    ? "bg-indigo-500/20 border-indigo-500/30 text-indigo-400"
                    : "bg-white/5 border-white/10 text-slate-400"
                }`}
              >
                {message.role === "user" ? (
                  <LucideUser size={20} />
                ) : (
                  <Bot size={20} />
                )}
              </div>

              <div
                className={`flex flex-col max-w-[85%] ${
                  message.role === "user" ? "items-end" : "items-start"
                }`}
              >
                <div
                  className={`p-5 rounded-3xl ${
                    message.role === "user"
                      ? "bg-indigo-600 text-white font-medium shadow-[0_0_30px_rgba(79,70,229,0.2)]"
                      : message.type === "insight"
                      ? "bg-gradient-to-br from-emerald-500/10 to-teal-500/10 border border-emerald-500/20 text-emerald-100"
                      : message.type === "recommendation"
                      ? "bg-gradient-to-br from-amber-500/10 to-orange-500/10 border border-amber-500/20 text-amber-100"
                      : message.type === "alert"
                      ? "bg-gradient-to-br from-rose-500/10 to-red-500/10 border border-rose-500/20 text-rose-100"
                      : "bg-white/5 border border-white/10 text-slate-300 font-sans"
                  }`}
                >
                  {message.type && message.type !== "text" && message.role === "assistant" && (
                    <div className="flex items-center gap-2 mb-3 opacity-70">
                      {message.type === "insight" && <TrendingUp size={14} />}
                      {message.type === "recommendation" && <Sparkles size={14} />}
                      {message.type === "alert" && <AlertTriangle size={14} />}
                      <span className="text-[10px] font-black uppercase tracking-widest">
                        {message.type === "insight" && "Análise"}
                        {message.type === "recommendation" && "Recomendação"}
                        {message.type === "alert" && "Alerta"}
                      </span>
                    </div>
                  )}
                  <p className="text-sm leading-relaxed whitespace-pre-wrap font-medium" dangerouslySetInnerHTML={{ 
                    __html: message.content
                      .replace(/&/g, '&')
                      .replace(/</g, '<')
                      .replace(/>/g, '>')
                      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
                      .replace(/\n/g, '<br/>')
                  }} />
                </div>
                <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mt-2 px-1">
                  {message.timestamp.toLocaleTimeString("pt-BR", {
                    hour: "2-digit",
                    minute: "2-digit",
                  })}
                </p>
              </div>
            </motion.div>
          ))}
        </AnimatePresence>

        <AnimatePresence>
          {isLoading && <AIThinkingIndicator />}
        </AnimatePresence>
        <div ref={messagesEndRef} />
      </div>

      {/* Suggested & Input */}
      <div
        className="p-6 border-t border-white/10 bg-white/[0.02]"
        id="ai-input-area"
      >
        {messages.length === 1 && (
          <>
            <div className="mb-3">
              <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Modos de aprendizagem</p>
              <div className="flex flex-wrap gap-2 mb-4">
                {LEARNING_MODES.map((mode) => (
                  <button
                    key={mode}
                    onClick={() => setInput(mode)}
                    className="px-4 py-2 rounded-xl bg-indigo-500/10 border border-indigo-500/20 text-[10px] font-black uppercase tracking-widest text-indigo-300 hover:text-white hover:bg-indigo-500/20 transition-all"
                  >
                    {mode}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex flex-wrap gap-2 mb-6">
              {suggestedQuestions.map((q) => (
                <button
                  key={q}
                  onClick={() => setInput(q)}
                  className="px-4 py-2 rounded-xl bg-white/5 border border-white/5 text-[10px] font-black uppercase tracking-widest text-slate-400 hover:text-white hover:bg-white/10 transition-all"
                >
                  {q}
                </button>
              ))}
            </div>
          </>
        )}

        <div className="flex gap-2 items-center">
          <VoiceInput
            onTranscript={(text) => setInput(text)}
            isProcessing={isLoading}
          />

          <div className="relative group flex-1">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="Comando de Auditoria..."
              className="w-full bg-black/40 border border-white/10 rounded-2xl px-6 py-4 text-white placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500/50 transition-all font-medium"
              disabled={isLoading}
            />
            <button
              onClick={handleSend}
              disabled={!input.trim() || isLoading}
              className="absolute right-2 top-2 bottom-2 px-5 bg-indigo-600 text-white rounded-xl font-black text-xs uppercase tracking-widest hover:bg-indigo-500 disabled:opacity-50 disabled:bg-slate-800 transition-all"
            >
              {isLoading ? (
                <Loader2 size={16} className="animate-spin" />
              ) : (
                <Send size={16} />
              )}
            </button>
          </div>
        </div>
        <p className="text-center text-[9px] font-black text-slate-700 uppercase tracking-[0.3em] mt-4">
          MNT-OS v2.5 • ENCRYPTED PAYLOAD
        </p>
      </div>
    </div>
  );
};

export default AIFinancialChat;

import { VoiceInput } from "@/components/ai/VoiceInput";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { useInvestments } from "@/hooks/useInvestments";
import { parseVoiceCommand, type ParsedCommand } from "@/lib/ai";
import { loadTransactions, saveTransactions } from "@/lib/storage";
import { showError, showSuccess } from "@/lib/toast";
import { Transaction } from "@/types";
import { useRole } from "@/context/AuthContext";
import { AnimatePresence, motion } from "framer-motion";
import { Check, Loader2, Sparkles, X } from "lucide-react";
import { useState } from "react";

export const VoiceCommander = () => {
  const { isViewer } = useRole();
  const [isProcessing, setIsProcessing] = useState(false);
  const [parsedResult, setParsedResult] = useState<ParsedCommand | null>(null);

  const handleTranscript = async (text: string) => {
    if (!text) return;
    setIsProcessing(true);
    try {
      const result = await parseVoiceCommand(text);
      setParsedResult(result);
    } catch (error) {
      showError("Erro ao processar comando de voz.");
    } finally {
      setIsProcessing(false);
    }
  };

  const { addAsset } = useInvestments();

  const confirmAction = () => {
    if (!parsedResult || !parsedResult.data) return;
    if (isViewer) {
      showError("Acesso negado: você é apenas visualizador");
      setParsedResult(null);
      return;
    }

    if (parsedResult.type === "transaction" && parsedResult.data) {
      const t = parsedResult.data as any;
      const newTransaction: Transaction = {
        id: Date.now().toString(),
        type: t.type || 'expense',
        amount: typeof t.amount === 'string' ? parseFloat(t.amount) : (t.amount || 0),
        description: t.description || 'Comando de voz',
        category: t.category || 'Outros',
        date: t.date || new Date().toISOString().split("T")[0],
        paymentMethod: t.paymentMethod || 'other',
        notes: "Via Comando de Voz",
        recurring: false,
        scope: "personal",
      };

      const current = loadTransactions();
      saveTransactions([...current, newTransaction]);
      showSuccess("Transação registrada!");
      window.dispatchEvent(new Event("storage-local"));
    } else if (parsedResult.type === "investment" && parsedResult.data) {
      const inv = parsedResult.data as any;
      addAsset({
        name: inv.ticker || "Ativo",
        ticker: inv.ticker || "ATIVO",
        type: inv.type || "stock",
        amount: typeof inv.amount === 'string' ? parseFloat(inv.amount) : (inv.amount || 0),
        averagePrice: typeof inv.price === 'string' ? parseFloat(inv.price) : (inv.price || 0),
        currentPrice: typeof inv.price === 'string' ? parseFloat(inv.price) : (inv.price || 0),
        sector: "Voz",
      });
      showSuccess(`Investimento em ${inv.ticker || "Ativo"} registrado!`);
    }

    setParsedResult(null);
  };

  return (
    <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-50 flex flex-col items-center gap-4">
      <AnimatePresence>
        {isProcessing && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 20 }}
            className="bg-black/80 text-white px-4 py-2 rounded-full flex items-center gap-2 backdrop-blur-md border border-white/10"
          >
            <Loader2 className="animate-spin text-indigo-400" size={16} />
            <span className="text-sm font-medium">A IA está pensando...</span>
          </motion.div>
        )}

        {parsedResult && (
          <motion.div
            initial={{ opacity: 0, scale: 0.9, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.9, y: 20 }}
            className="w-80"
          >
            <Card className="glass-premium border-indigo-500/50 shadow-2xl shadow-indigo-500/20">
              <CardContent className="p-4 space-y-4">
                <div className="flex items-start justify-between">
                  <div className="flex items-center gap-2 text-indigo-400 font-bold">
                    <Sparkles size={18} />
                    {parsedResult.type === "transaction"
                      ? "Nova Transação"
                      : "Resultado"}
                  </div>
                  <Button
                    variant="ghost"
                    size="icon"
                    className="h-6 w-6"
                    onClick={() => setParsedResult(null)}
                  >
                    <X size={14} />
                  </Button>
                </div>

                {parsedResult.type === "transaction" && parsedResult.data ? (
                  (() => {
                    const t = parsedResult.data as any;
                    return (
                      <div className="space-y-2 text-sm">
                        <div className="flex justify-between">
                          <span className="text-slate-400">Descrição:</span>
                          <span className="font-medium text-white">
                            {t.description}
                          </span>
                        </div>
                        <div className="flex justify-between">
                          <span className="text-slate-400">Valor:</span>
                          <span
                            className={`font-bold ${
                              t.type === "income"
                                ? "text-emerald-400"
                                : "text-red-400"
                            }`}
                          >
                            R$ {t.amount?.toFixed(2) || '0.00'}
                          </span>
                        </div>
                        <div className="flex justify-between">
                          <span className="text-slate-400">Categoria:</span>
                          <span className="text-white">
                            {t.category}
                          </span>
                        </div>
                      </div>
                    );
                  })()
                ) : parsedResult.type === "investment" && parsedResult.data ? (
                  (() => {
                    const inv = parsedResult.data as any;
                    return (
                      <div className="space-y-2 text-sm">
                        <div className="flex justify-between">
                          <span className="text-slate-400">Ticker:</span>
                          <span className="font-bold text-indigo-400">
                            {inv.ticker}
                          </span>
                        </div>
                        <div className="flex justify-between">
                          <span className="text-slate-400">Quantidade:</span>
                          <span className="text-white">
                            {inv.amount}
                          </span>
                        </div>
                        {inv.price && (
                          <div className="flex justify-between">
                            <span className="text-slate-400">Preço:</span>
                            <span className="text-emerald-400 font-bold">
                              R$ {inv.price?.toFixed(2) || '0.00'}
                            </span>
                          </div>
                        )}
                      </div>
                    );
                  })()
                ) : (
                  <p className="text-white text-sm">
                    {parsedResult.message || "Comando não compreendido."}
                  </p>
                )}

                <div className="flex gap-2 pt-2">
                  <Button
                    variant="ghost"
                    size="sm"
                    className="flex-1 text-slate-400"
                    onClick={() => setParsedResult(null)}
                  >
                    Cancelar
                  </Button>
                  {parsedResult.type !== "unknown" && (
                    <Button
                      size="sm"
                      className="flex-1 bg-indigo-600 hover:bg-indigo-500 text-white"
                      onClick={confirmAction}
                    >
                      <Check size={16} className="mr-1" /> Confirmar
                    </Button>
                  )}
                </div>
              </CardContent>
            </Card>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="relative group">
        <div className="absolute inset-0 bg-indigo-500/20 blur-xl rounded-full group-hover:bg-indigo-500/40 transition-all duration-500" />
        <div className="relative bg-black/90 backdrop-blur-xl p-2 rounded-full border border-white/10 shadow-xl">
          <VoiceInput
            onTranscript={handleTranscript}
            isProcessing={isProcessing}
          />
        </div>
      </div>
    </div>
  );
};

import { Button } from "@/components/ui/button";
import { Mic, MicOff, Waves } from "lucide-react";
import React, { useEffect, useState } from "react";

interface VoiceInputProps {
  onTranscript: (text: string) => void;
  isProcessing?: boolean;
}

export const VoiceInput: React.FC<VoiceInputProps> = ({
  onTranscript,
  isProcessing = false,
}) => {
  const [isListening, setIsListening] = useState(false);
  const [recognition, setRecognition] = useState<any | null>(
    null
  );
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (
      typeof window !== "undefined" &&
      ("SpeechRecognition" in window || "webkitSpeechRecognition" in window)
    ) {
      const SpeechRecognition =
        window.SpeechRecognition || window.webkitSpeechRecognition;
      const recognitionInstance = new SpeechRecognition();
      recognitionInstance.continuous = false;
      recognitionInstance.interimResults = false;
      recognitionInstance.lang = "pt-BR";

      recognitionInstance.onstart = () => {
        setIsListening(true);
        setError(null);
      };

      recognitionInstance.onend = () => {
        setIsListening(false);
      };

      recognitionInstance.onerror = (event) => {
        console.error("Speech recognition error", event.error);
        setIsListening(false);
        if (event.error === "not-allowed") {
          setError("Permissão de microfone negada.");
        } else {
          setError("Erro ao ouvir. Tente novamente.");
        }
      };

      recognitionInstance.onresult = (event: any) => {
        const transcript = event.results?.[0]?.[0]?.transcript;
        if (transcript) {
          onTranscript(transcript);
        }
      };

      setRecognition(recognitionInstance);
    } else {
      setError("Seu navegador não suporta reconhecimento de voz.");
    }
  }, [onTranscript]);

  const toggleListening = () => {
    if (!recognition) return;

    if (isListening) {
      recognition.stop();
    } else {
      recognition.start();
    }
  };

  if (error) {
    return (
      <span className="text-xs text-red-400 ml-2" title={error}>
        <MicOff size={16} />
      </span>
    );
  }

  return (
    <Button
      type="button"
      size="icon"
      variant={isListening ? "default" : "ghost"}
      onClick={toggleListening}
      disabled={isProcessing}
      className={`transition-all duration-300 ${
        isListening
          ? "bg-red-500 hover:bg-red-600 text-white shadow-[0_0_15px_rgba(239,68,68,0.5)] animate-pulse"
          : "text-slate-400 hover:text-indigo-400"
      }`}
      title={isListening ? "Parar de ouvir" : "Falar comando"}
    >
      {isListening ? <Waves className="animate-pulse" /> : <Mic />}
    </Button>
  );
};

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import type { Transaction } from "@/types";
import { api } from "@/lib/api";
import { showSuccess, showError } from "@/lib/toast";
import { Link2, FileUp } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { OFXImportModal } from "./OFXImportModal";
import { PluggyConnect } from "react-pluggy-connect";

interface BankConnectionModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: (transactions: Transaction[]) => void;
}

export const BankConnectionModal = ({ isOpen, onClose, onSuccess }: BankConnectionModalProps) => {
  const [mode, setMode] = useState<"select" | "pluggy" | "ofx">("select");
  const [connectToken, setConnectToken] = useState<string | null>(null);

  useEffect(() => {
    if (isOpen) {
      setMode("select");
      // Solicita o Token oficial da Pluggy logo no início para aquecimento
      api.get("/open-finance/token")
        .then((res: any) => setConnectToken(res.accessToken))
        .catch((err) => {
          console.error("Open Finance Token Error:", err);
          showError("Falhas na malha bancária segura. Tente mais tarde.");
        });
    } else {
      setConnectToken(null);
    }
  }, [isOpen]);

  const handlePluggySuccess = async (itemData: any) => {
    showSuccess("Banco Conectado! Baixando seu histórico...");
    try {
      await api.post(`/open-finance/sync/${itemData.item.id}`, {});
      showSuccess("Sincronização concluída com sucesso!");
      onSuccess([]); // Força reload de transactions na tela principal
      onClose();
    } catch (err) {
      showError("Sem transações recentes ou erro ao sincronizar.");
      onClose();
    }
  };

  return (
    <>
      <Dialog open={isOpen && mode === "select"} onOpenChange={onClose}>
        <DialogContent className="sm:max-w-md bg-[#020617] border-white/5 rounded-[2.5rem] p-0 overflow-hidden">
          <div className="p-8">
            <AnimatePresence mode="wait">
              {mode === "select" && (
                <motion.div
                  key="select"
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -20 }}
                  className="space-y-6"
                >
                  <DialogHeader className="space-y-3">
                    <div className="flex items-center gap-3">
                       <div className="p-2 bg-indigo-500/10 rounded-xl text-indigo-400">
                          <Link2 size={24} />
                       </div>
                       <DialogTitle className="text-2xl font-black text-white uppercase tracking-tighter">
                         Sincronizar <span className="text-indigo-400">Dados</span>
                       </DialogTitle>
                    </div>
                    <p className="text-sm text-slate-400 font-medium leading-relaxed">
                      Sincronize com máxima segurança. Suas credenciais bancárias são encriptadas (TLS 256) e nunca armazenadas.
                    </p>
                  </DialogHeader>

                  <div className="flex flex-col gap-3">
                     <button 
                        onClick={() => {
                          if (!connectToken) {
                            showError("Gerando Token SEED 256-bit, aguarde 2 segundos...");
                            return;
                          }
                          setMode("pluggy");
                        }} 
                        className="p-6 rounded-3xl bg-indigo-500/10 border border-indigo-500/20 hover:bg-indigo-500/30 transition-all flex flex-col items-center gap-3 group"
                     >
                        <span className="text-[15px] font-black text-white uppercase tracking-widest text-center leading-tight">
                           Conexão Automática
                           <br />(Open Finance)
                        </span>
                        <span className="text-xs text-indigo-300/80 font-medium text-center">Integração oficial Pluggy (Nubank, Itaú, BB).</span>
                     </button>

                     <button 
                        onClick={() => setMode("ofx")} 
                        className="p-5 rounded-3xl bg-white/5 border border-white/5 hover:bg-white/10 hover:border-white/10 shadow-lg transition-all flex flex-col items-center gap-2 mt-2 group"
                     >
                        <span className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2 group-hover:text-indigo-200 transition-colors">
                           <FileUp size={16} className="text-indigo-400" />
                           Arquivo Manual (.OFX)
                        </span>
                     </button>
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </DialogContent>
      </Dialog>

      {/* Widget Externo da API do Open Finance */}
      {mode === "pluggy" && connectToken && (
        <PluggyConnect
          connectToken={connectToken}
          includeSandbox={true}
          onSuccess={handlePluggySuccess}
          onError={(error: any) => {
             console.error("Pluggy Connect Error:", error);
             showError("Autorização bancária cancelada ou negada.");
             setMode("select");
          }}
          {...({ onClose: () => setMode("select") } as any)}
        />
      )}

      {/* Rota Manual Segura de OFX via Web */}
      <OFXImportModal
        isOpen={mode === "ofx"}
        onClose={() => setMode("select")}
        onSuccess={() => {
          setMode("select");
          onSuccess([]);
          onClose(); // Auto-fecha a UI
        }}
      />
    </>
  );
};

import { useEffect, useState } from 'react';
import { useOpenFinance } from '@/hooks/useOpenFinance';
import { PluggyConnect } from 'react-pluggy-connect';
import { Landmark, AlertCircle, RefreshCw, Plus, CheckCircle2 } from 'lucide-react';
import { showSuccess, showError } from '@/lib/toast';

export const BankConnectionsView = () => {
  const { connections, isLoading, fetchConnections, getConnectToken, forceSync } = useOpenFinance();
  const [connectToken, setConnectToken] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState<string | null>(null);

  useEffect(() => {
    fetchConnections();
  }, [fetchConnections]);

  const handleConnectNew = async () => {
    try {
      showSuccess('Gerando token seguro de conexão...');
      const token = await getConnectToken();
      setConnectToken(token);
    } catch (err: any) {
      showError(err.message || 'Erro ao conectar Open Finance');
    }
  };

  const handleSync = async (itemId: string) => {
    setIsSyncing(itemId);
    try {
      await forceSync(itemId);
      showSuccess('Sincronização concluída com sucesso!');
    } catch (err: any) {
      showError(err.message);
    } finally {
      setIsSyncing(null);
    }
  };

  const handleOnSuccess = (itemData: any) => {
    console.log("Item conectado com sucesso:", itemData);
    setConnectToken(null);
    showSuccess('Conexão estabelecida! Importando dados em plano de fundo...');
    // Pode forçar sync manual aqui ou deixar que o webhook cuide do `item/updated`
    handleSync(itemData.item.id);
  };

  const handleOnError = (error: any) => {
    console.error("Erro no Widget do Pluggy (Detalhes):", JSON.stringify(error, null, 2));
    setConnectToken(null);
    if (error?.message?.includes('closed') || error?.type === 'USER_ACTION_CANCELED') {
       // Apenas fechou
       return;
    }
    showError(`Erro Oculto do Widget: ${error?.message || 'Cancelado'}`);
  };

  return (
    <div style={{ animation: "fsu 0.25s ease" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "16px" }}>
        <div>
          <div className="eyebrow">Open Finance</div>
          <div className="page-title" style={{ margin: 0, fontSize: "20px" }}>Bancos Conectados</div>
        </div>
        <button 
          onClick={handleConnectNew}
          className="btn-p" 
          style={{ padding: "8px 14px", fontSize: "13px", display: "flex", alignItems: "center", gap: "6px" }}
        >
          <Plus size={16} /> Nova Conexão
        </button>
      </div>

      <div className="istrip" style={{ background: "rgba(74,139,255,0.08)", border: "1px solid rgba(74,139,255,0.2)", marginBottom: "20px", display: "flex", gap: "12px", alignItems: "flex-start" }}>
        <Landmark size={20} color="var(--blue)" style={{ flexShrink: 0, marginTop: "2px" }} />
        <div style={{ fontSize: "13px", color: "var(--t2)", lineHeight: 1.5 }}>
          Conecte suas contas bancárias de forma segura para importar transações e consolidar seu patrimônio automaticamente.
        </div>
      </div>

      {isLoading ? (
        <div style={{ textAlign: "center", padding: "40px 0", color: "var(--t3)", fontSize: "14px", fontFamily: "var(--mono)" }}>Carregando integrações...</div>
      ) : connections.length === 0 ? (
        <div style={{ textAlign: "center", padding: "60px 20px", background: "var(--glass2)", borderRadius: "16px", border: "1px dashed var(--border)" }}>
          <div style={{ fontSize: "40px", marginBottom: "16px" }}>🔗</div>
          <div style={{ fontSize: "15px", fontWeight: 600, color: "var(--t1)", marginBottom: "6px" }}>Nenhuma conta conectada</div>
          <div style={{ fontSize: "13px", color: "var(--t3)", marginBottom: "20px", maxWidth: "260px", margin: "0 auto 20px" }}>Inicie a jornada Open Finance para automatizar seu fluxo de caixa.</div>
          <button onClick={handleConnectNew} className="btn-p" style={{ display: "inline-flex", alignItems: "center", gap: "8px" }}>
            <Landmark size={18} /> Conectar Conta Bancária
          </button>
        </div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: "12px" }}>
          {connections.map((conn) => {


            return (
              <div key={conn.id} className="card" style={{ padding: "16px" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "12px" }}>
                  <div style={{ display: "flex", gap: "10px", alignItems: "center" }}>
                    {conn.accounts[0]?.bankImageUrl ? (
                      <img src={conn.accounts[0].bankImageUrl} alt="Bank Logo" style={{ width: "36px", height: "36px", borderRadius: "10px", border: "1px solid var(--border)" }} />
                    ) : (
                      <div style={{ width: "36px", height: "36px", borderRadius: "10px", background: "var(--glass2)", border: "1px solid var(--border)", display: "flex", alignItems: "center", justifyContent: "center", color: "var(--t3)" }}>🏦</div>
                    )}
                    <div>
                      <div style={{ fontSize: "15px", fontWeight: 700, color: "var(--t1)" }}>{conn.accounts[0]?.bankName || 'Instituição'}</div>
                      <div style={{ fontSize: "11px", color: "var(--t3)", display: "flex", alignItems: "center", gap: "4px", marginTop: "2px" }}>
                        {conn.status === 'UPDATED' ? <CheckCircle2 size={12} color="var(--green)" /> : <AlertCircle size={12} color="var(--amber)" />}
                        {conn.status}
                      </div>
                    </div>
                  </div>
                  <button 
                    onClick={() => handleSync(conn.pluggyItemId)}
                    disabled={isSyncing === conn.pluggyItemId}
                    style={{ background: "none", border: "none", color: "var(--blue)", display: "flex", alignItems: "center", gap: "6px", fontSize: "12px", fontWeight: 600, cursor: "pointer", fontFamily: "var(--font)", opacity: isSyncing === conn.pluggyItemId ? 0.5 : 1 }}
                  >
                    <RefreshCw size={14} className={isSyncing === conn.pluggyItemId ? "spin" : ""} /> Sync
                  </button>
                </div>

                <div style={{ display: "flex", flexDirection: "column", gap: "2px" }}>
                  {conn.accounts.map(acc => (
                    <div key={acc.id} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "8px 10px", background: "var(--bg)", borderRadius: "8px", border: "1px solid var(--border)" }}>
                      <div>
                        <div style={{ fontSize: "13px", fontWeight: 600, color: "var(--t1)" }}>{acc.name}</div>
                        <div style={{ fontSize: "10px", color: "var(--t3)", textTransform: "uppercase", letterSpacing: "0.05em", marginTop: "1px" }}>{acc.type} • {acc.subtype}</div>
                      </div>
                      <div style={{ fontSize: "14px", fontWeight: 700, color: "var(--t1)", fontFamily: "var(--mono)" }}>
                        {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: (acc as any).currencyCode || 'BRL' }).format(acc.balance)}
                      </div>
                    </div>
                  ))}
                </div>

                {conn.lastSyncAt && (
                  <div style={{ fontSize: "10.5px", color: "var(--t3)", marginTop: "12px", textAlign: "right" }}>
                    Última sincronização: {new Date(conn.lastSyncAt).toLocaleString('pt-BR')}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Renderiza o Widget do Pluggy se tiver hook aprovado */}
      {connectToken && (
        <PluggyConnect
          connectToken={connectToken}
          includeSandbox={true}
          onSuccess={handleOnSuccess}
          onError={handleOnError}
          {...( { onClose: () => setConnectToken(null) } as any )}
        />
      )}
    </div>
  );
};

import { useState, useRef } from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { api } from "@/lib/api";
import { showSuccess, showError } from "@/lib/toast";
import {
  FileUp,
  CheckCircle2,
  AlertCircle,
  Loader2,
  FileText,
  SkipForward,
  X,
} from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

interface OFXImportModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: (imported: number) => void;
}

interface ImportResult {
  imported: number;
  skipped: number;
  currency: string;
  period?: { from?: string; to?: string };
  message?: string;
}

export const OFXImportModal = ({
  isOpen,
  onClose,
  onSuccess,
}: OFXImportModalProps) => {
  const [stage, setStage] = useState<"idle" | "loading" | "success" | "error">(
    "idle"
  );
  const [result, setResult] = useState<ImportResult | null>(null);
  const [errorMsg, setErrorMsg] = useState("");
  const [fileName, setFileName] = useState("");
  const inputRef = useRef<HTMLInputElement>(null);

  const reset = () => {
    setStage("idle");
    setResult(null);
    setErrorMsg("");
    setFileName("");
    if (inputRef.current) inputRef.current.value = "";
  };

  const handleClose = () => {
    reset();
    onClose();
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const ext = file.name.split(".").pop()?.toLowerCase();
    if (!ext || !["ofx", "qfx", "ofc"].includes(ext)) {
      setStage("error");
      setErrorMsg(
        "Formato inválido. Use um arquivo .ofx ou .qfx exportado pelo seu banco."
      );
      return;
    }

    setFileName(file.name);
    setStage("loading");

    try {
      // Read file as text in the browser
      const rawText = await file.text();

      // Send as standard JSON
      const data = (await api.post("/banking/import-ofx", { ofxContent: rawText })) as ImportResult;

      setResult(data);
      setStage("success");

      if (data.imported > 0) {
        showSuccess(`${data.imported} transações importadas com sucesso!`);
        onSuccess(data.imported);
      }
    } catch (err: any) {
      setStage("error");
      setErrorMsg(
        err?.response?.data?.message ||
          err?.message ||
          "Erro ao processar o arquivo OFX."
      );
      showError("Falha na importação do extrato.");
    }
  };

  const fmt = (d?: string) =>
    d ? new Date(d).toLocaleDateString("pt-BR") : "—";

  return (
    <Dialog open={isOpen} onOpenChange={handleClose}>
      <DialogContent className="glass border-white/10 bg-[#0a0a0f] text-white max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2 text-lg font-black">
            <FileUp className="text-indigo-400" size={20} />
            Importar Extrato Bancário (OFX)
          </DialogTitle>
        </DialogHeader>

        <AnimatePresence mode="wait">
          {/* ─── IDLE ─── */}
          {stage === "idle" && (
            <motion.div
              key="idle"
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
              className="space-y-5"
            >
              <p className="text-sm text-slate-400 leading-relaxed">
                Exporte o extrato do seu banco no formato{" "}
                <span className="text-indigo-300 font-bold">.ofx</span> e faça
                o upload aqui. As transações serão importadas automaticamente,
                sem duplicatas.
              </p>

              <div className="grid grid-cols-3 gap-2 text-xs text-center text-slate-500">
                {["Itaú", "Bradesco", "Nubank", "BB", "Santander", "Inter"].map(
                  (b) => (
                    <div
                      key={b}
                      className="bg-white/5 rounded-xl py-2 border border-white/5"
                    >
                      {b}
                    </div>
                  )
                )}
              </div>

              <button
                onClick={() => inputRef.current?.click()}
                className="w-full border-2 border-dashed border-white/10 rounded-2xl p-8 flex flex-col items-center gap-3 hover:border-indigo-500/50 hover:bg-indigo-500/5 transition-all duration-300 group"
              >
                <FileText
                  size={40}
                  className="text-slate-600 group-hover:text-indigo-400 transition-colors"
                />
                <span className="text-sm font-bold text-slate-400 group-hover:text-white transition-colors">
                  Clique para selecionar o arquivo OFX
                </span>
                <span className="text-xs text-slate-600">
                  .ofx · .qfx · máx. 10MB
                </span>
              </button>

              <input
                ref={inputRef}
                type="file"
                accept=".ofx,.qfx,.ofc"
                className="hidden"
                onChange={handleFileChange}
              />
            </motion.div>
          )}

          {/* ─── LOADING ─── */}
          {stage === "loading" && (
            <motion.div
              key="loading"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="py-10 flex flex-col items-center gap-4"
            >
              <Loader2
                size={40}
                className="text-indigo-400 animate-spin"
              />
              <p className="text-sm font-bold text-slate-400">
                Lendo{" "}
                <span className="text-white">{fileName}</span>…
              </p>
              <p className="text-xs text-slate-600">Categorizando transações</p>
            </motion.div>
          )}

          {/* ─── SUCCESS ─── */}
          {stage === "success" && result && (
            <motion.div
              key="success"
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0 }}
              className="space-y-5"
            >
              <div className="flex flex-col items-center gap-3 py-4">
                <CheckCircle2 size={48} className="text-emerald-400" />
                <h3 className="text-xl font-black text-white">
                  Extrato importado!
                </h3>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div className="bg-emerald-500/10 border border-emerald-500/20 rounded-2xl p-4 text-center">
                  <p className="text-3xl font-black text-emerald-400">
                    {result.imported}
                  </p>
                  <p className="text-xs font-bold text-slate-400 uppercase tracking-wider mt-1">
                    Importadas
                  </p>
                </div>
                <div className="bg-white/5 border border-white/5 rounded-2xl p-4 text-center">
                  <p className="text-3xl font-black text-slate-400 flex items-center justify-center gap-1">
                    <SkipForward size={20} />
                    {result.skipped}
                  </p>
                  <p className="text-xs font-bold text-slate-500 uppercase tracking-wider mt-1">
                    Duplicatas
                  </p>
                </div>
              </div>

              {result.period?.from && (
                <p className="text-xs text-slate-500 text-center">
                  Período:{" "}
                  <span className="text-slate-300 font-bold">
                    {fmt(result.period.from)} → {fmt(result.period.to)}
                  </span>
                </p>
              )}

              {result.imported === 0 && result.message && (
                <p className="text-xs text-amber-400 text-center bg-amber-500/10 rounded-xl p-3 border border-amber-500/20">
                  {result.message}
                </p>
              )}

              <div className="flex gap-3">
                <Button
                  variant="outline"
                  className="flex-1 border-white/10"
                  onClick={reset}
                >
                  Importar outro
                </Button>
                <Button
                  className="flex-1 bg-indigo-600 hover:bg-indigo-500"
                  onClick={handleClose}
                >
                  Concluir
                </Button>
              </div>
            </motion.div>
          )}

          {/* ─── ERROR ─── */}
          {stage === "error" && (
            <motion.div
              key="error"
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
              className="space-y-5"
            >
              <div className="flex flex-col items-center gap-3 py-4">
                <AlertCircle size={48} className="text-rose-400" />
                <h3 className="text-lg font-black text-white">
                  Falha na importação
                </h3>
                <p className="text-sm text-slate-400 text-center max-w-xs">
                  {errorMsg}
                </p>
              </div>

              <div className="flex gap-3">
                <Button
                  variant="outline"
                  className="flex-1 border-white/10"
                  onClick={handleClose}
                >
                  <X size={16} className="mr-2" /> Fechar
                </Button>
                <Button
                  className="flex-1 bg-indigo-600 hover:bg-indigo-500"
                  onClick={reset}
                >
                  Tentar novamente
                </Button>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </DialogContent>
    </Dialog>
  );
};

