import { QuickSetupWizard } from "@/components/ui/QuickSetupWizard";
import { saveBudgets } from "@/lib/storage";
import { showSuccess } from "@/lib/toast";

import { CashFlowSection } from "@/components/business/CashFlowSection";
import { DRESection } from "@/components/business/DRESection";
import { InvoicesSection } from "@/components/business/InvoicesSection";
import { AnalyticsTab } from "@/components/contador/AnalyticsTab";
import { SummaryCards } from "@/components/contador/SummaryCards";
import { TransactionFilters } from "@/components/contador/TransactionFilters";
import { TransactionForm } from "@/components/contador/TransactionForm";
import { TransactionList } from "@/components/contador/TransactionList";

import { useCurrency } from "@/context/CurrencyContext";

export const BusinessFinance = () => {
  const { convert } = useCurrency();
  const [activeTab, setActiveTab] = useState("dashboard");
  const [showForm, setShowForm] = useState(false);
  const [editingTransaction, setEditingTransaction] =
    useState<Transaction | null>(null);
  const [showWizard, setShowWizard] = useState(false);

  const {
    transactions,
    filteredTransactions,
    filter,
    setFilter,
    dateFilter,
    setDateFilter,
    searchTerm,
    setSearchTerm,
    addTransaction,
    updateTransaction,
    deleteTransaction,
    totals,
    categoryData,
    getPieChartData,
    monthlyTrend,
  } = useTransactions("business");

  const handleNewTransaction = () => {
    setEditingTransaction(null);
    setShowForm(true);
  };

  const handleEdit = (transaction: Transaction) => {
    setEditingTransaction(transaction);
    setShowForm(true);
  };

  const handleSubmit = (formData: TransactionFormData, isEditing: boolean) => {
    if (isEditing && editingTransaction) {
      updateTransaction(editingTransaction.id, formData);
    } else {
      addTransaction(formData);
    }
    setShowForm(false);
    setEditingTransaction(null);
  };

  const handleCancel = () => {
    setShowForm(false);
    setEditingTransaction(null);
  };

  const handleApplyPreset = (data: any) => {
    if (data.budgets) {
      saveBudgets(data.budgets.map((b: any, i: number) => ({
        id: Date.now() + i,
        category: b.category,
        limit: b.amount,
        spent: 0,
        month: new Date().toISOString().slice(0, 7)
      })));
    }
    // Business categories are implicit in transactions/budgets here
    setShowWizard(false);
    showSuccess("Configuração empresarial aplicada!");
  };

  const incomeCount = filteredTransactions.filter(
    (t) => t.type === "income"
  ).length;
  const expenseCount = filteredTransactions.filter(
    (t) => t.type === "expense"
  ).length;

  return (
    <div className="space-y-10 animate-fade-in pb-12">
      <AnimatePresence>
        {transactions.length === 0 && !showWizard && (
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            className="premium-card p-6 bg-amber-500/10 border-amber-500/20 flex flex-col md:flex-row items-center justify-between gap-6"
          >
            <div className="flex items-center gap-4 text-center md:text-left">
              <div className="w-12 h-12 rounded-2xl bg-amber-500 flex items-center justify-center text-white shadow-lg">
                <Sparkles size={24} />
              </div>
              <div>
                <h4 className="font-black text-white uppercase tracking-tight">Setup Empresarial Rápido</h4>
                <p className="text-xs text-slate-400 font-medium">Configure categorias de MEI ou Autônomo instantaneamente.</p>
              </div>
            </div>
            <Button 
              onClick={() => setShowWizard(true)}
              className="bg-white text-black font-black uppercase tracking-widest text-[10px] h-12 px-8 rounded-xl"
            >
              Abrir Wizard
            </Button>
          </motion.div>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {showWizard && (
          <QuickSetupWizard 
            type="business" 
            onComplete={handleApplyPreset} 
            onClose={() => setShowWizard(false)} 
          />
        )}
      </AnimatePresence>
      {/* Premium Header */}
      <div className="premium-card p-6 md:p-10">
        <div className="absolute -right-20 -top-20 w-80 h-80 bg-amber-500/10 blur-[120px] rounded-full" />
        <div className="absolute -left-20 -bottom-20 w-80 h-80 bg-orange-500/5 blur-[120px] rounded-full" />

        <div className="relative z-10 flex flex-col md:flex-row items-start md:items-center justify-between gap-8">
          <div className="space-y-4">
            <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-amber-500/10 border border-white/5 text-[10px] font-black uppercase tracking-widest text-amber-400">
              <Building2 size={12} />
              Gestão Empresarial
            </div>
            <h2 className="text-4xl md:text-5xl font-black leading-tight tracking-tighter">
              Contabilidade <br />
              <span className="premium-gradient-text text-glow-amber">
                PRO Business
              </span>
            </h2>
            <p className="text-slate-400 font-medium max-w-md">
              Gestão contábil e financeira avançada com inteligência de dados
              para o seu negócio.
            </p>
          </div>

          <Button
            onClick={handleNewTransaction}
            className="bg-white text-black hover:bg-white/90 font-black rounded-2xl h-14 px-8 shadow-xl shadow-white/5 transition-all text-xs uppercase tracking-widest"
          >
            <PlusCircle size={18} className="mr-2" />
            Novo Lançamento
          </Button>

            <Button
              onClick={() => setShowWizard(true)}
              variant="outline"
              className="h-14 px-6 rounded-2xl border-white/10 text-slate-400 hover:text-white hover:bg-white/5 uppercase tracking-widest text-[10px] font-bold"
            >
              <Sparkles size={16} className="mr-2" />
              Configurar
            </Button>
          </div>
        </div>


      {/* Navigation Tabs */}
      <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
        <TabsList className="flex bg-white/5 p-1 rounded-2xl border border-white/10 w-fit mb-10 overflow-x-auto no-scrollbar">
          <TabsTrigger
            value="dashboard"
            className="px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black flex items-center gap-2"
          >
            <LayoutDashboard size={14} />
            Visão Geral
          </TabsTrigger>
          <TabsTrigger
            value="dre"
            className="px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black flex items-center gap-2"
          >
            <FileText size={14} />
            DRE
          </TabsTrigger>
          <TabsTrigger
            value="cashflow"
            className="px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black flex items-center gap-2"
          >
            <TrendingUp size={14} />
            Fluxo de Caixa
          </TabsTrigger>
          <TabsTrigger
            value="invoices"
            className="px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black flex items-center gap-2"
          >
            <Receipt size={14} />
            Notas Fiscais
          </TabsTrigger>
        </TabsList>
      </Tabs>

      {/* Transaction Form */}
      {showForm && (
        <TransactionForm
          editingTransaction={editingTransaction}
          onSubmit={handleSubmit}
          onCancel={handleCancel}
          scope="business"
        />
      )}

      {/* Tab Content */}
      {activeTab === "dashboard" && (
        <div className="space-y-6">
          <SummaryCards
            income={totals.income}
            expense={totals.expense}
            balance={totals.balance}
            transactionCount={filteredTransactions.length}
          />

          <TransactionFilters
            searchTerm={searchTerm}
            setSearchTerm={setSearchTerm}
            filter={filter}
            setFilter={setFilter}
            dateFilter={dateFilter}
            setDateFilter={setDateFilter}
          />

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <TransactionList
              transactions={filteredTransactions.slice(0, 5)}
              onEdit={handleEdit}
              onDelete={deleteTransaction}
            />
            <AnalyticsTab
              monthlyTrend={monthlyTrend}
              categoryData={categoryData}
              incomeChartData={getPieChartData("income")}
              expenseChartData={getPieChartData("expense")}
              totals={totals}
              incomeCount={incomeCount}
              expenseCount={expenseCount}
            />
          </div>
        </div>
      )}

      {activeTab === "dre" && <DRESection transactions={transactions} convert={convert} />}

      {activeTab === "cashflow" && (
        <CashFlowSection transactions={transactions} />
      )}

      {activeTab === "invoices" && <InvoicesSection />}
    </div>
  );
};

import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { useInvoices } from "@/hooks/useInvoices";
import type { Invoice } from "@/types";
import {
  AlertCircle,
  CheckCircle2,
  Clock,
  Edit2,
  FileText,
  Plus,
  Trash2,
} from "lucide-react";
import { EmptyState } from "../ui/EmptyState";
import { PrivacyValue } from "../ui/PrivacyValue";
import { FadeIn } from "../ui/skeleton";
import { useState } from "react";
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

export const InvoicesSection = () => {
  const { invoices, addInvoice, updateInvoice, deleteInvoice } = useInvoices();
  const [isOpen, setIsOpen] = useState(false);
  const [editingInv, setEditingInv] = useState<Invoice | null>(null);

  const [formData, setFormData] = useState({
    number: "",
    client: "",
    amount: "",
    status: "pending" as any,
    dueDate: new Date().toISOString().substring(0, 10),
  });

  const handleOpenChange = (open: boolean) => {
    setIsOpen(open);
    if (!open) {
      setEditingInv(null);
      setFormData({
        number: "",
        client: "",
        amount: "",
        status: "pending",
        dueDate: new Date().toISOString().substring(0, 10),
      });
    }
  };

  const handleEdit = (inv: Invoice) => {
    setEditingInv(inv);
    setFormData({
      number: inv.number,
      client: inv.client,
      amount: inv.amount.toString(),
      status: inv.status,
      dueDate: inv.dueDate,
    });
    setIsOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const data = {
      ...formData,
      amount: parseFloat(formData.amount),
    };

    if (editingInv) {
      updateInvoice(editingInv.id, data);
    } else {
      addInvoice(data);
    }
    handleOpenChange(false);
  };

  const handleDownloadPDF = (inv: Invoice) => {
    const doc = new jsPDF();
    
    // Header
    doc.setFontSize(22);
    doc.text("NOTA FISCAL DE SERVIÇOS", 105, 20, { align: "center" });
    
    doc.setFontSize(10);
    doc.text(`Número: ${inv.number}`, 20, 40);
    doc.text(`Data de Emissão: ${new Date().toLocaleDateString("pt-BR")}`, 20, 45);
    doc.text(`Vencimento: ${new Date(inv.dueDate).toLocaleDateString("pt-BR")}`, 20, 50);

    // Client Info
    doc.setFontSize(14);
    doc.text("TOMADOR DO SERVIÇO", 20, 65);
    doc.setFontSize(10);
    doc.text(`Cliente: ${inv.client}`, 20, 75);

    // Table
    autoTable(doc, {
      startY: 90,
      head: [["Descrição", "Valor Base", "Impostos", "Total"]],
      body: [
        [
          `Serviços prestados conforme NF ${inv.number}`,
          `R$ ${inv.amount.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}`,
          "R$ 0,00",
          `R$ ${inv.amount.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}`,
        ],
      ],
      theme: "grid",
      headStyles: { fillColor: [79, 70, 229] },
    });

    const finalY = (doc as any).lastAutoTable.finalY + 20;
    doc.setFontSize(12);
    doc.text(`VALOR TOTAL: R$ ${inv.amount.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}`, 140, finalY);

    doc.save(`NF_${inv.number}_${inv.client.replace(/\s+/g, "_")}.pdf`);
  };

  const statusConfig = {
    paid: {
      label: "Pago",
      color: "bg-success/10 text-success",
      icon: CheckCircle2,
    },
    pending: {
      label: "Pendente",
      color: "bg-warning/10 text-warning",
      icon: Clock,
    },
    overdue: {
      label: "Atrasado",
      color: "bg-danger/10 text-danger",
      icon: AlertCircle,
    },
  };

  return (
    <FadeIn>
      <div className="space-y-10">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="space-y-1">
            <h3 className="text-xl font-black uppercase tracking-widest text-white">
              Notas <span className="text-amber-400">Fiscais</span>
            </h3>
            <p className="text-xs text-slate-500 font-medium">
              Controle total do faturamento e recebíveis
            </p>
          </div>

          <Dialog open={isOpen} onOpenChange={handleOpenChange}>
            <DialogTrigger asChild>
              <Button className="bg-white text-black hover:bg-white/90 font-black rounded-2xl h-14 px-8 shadow-xl shadow-white/5 transition-all text-xs uppercase tracking-widest">
                <Plus size={18} className="mr-2" />
                Emitir Nova Nota
              </Button>
            </DialogTrigger>
            <DialogContent className="sm:max-w-[480px] glass-premium border-white/10 p-0 overflow-hidden">
              <div className="p-8 space-y-8">
                <DialogHeader>
                  <DialogTitle className="text-2xl font-black tracking-tight text-white">
                    {editingInv ? "Editar Nota Fiscal" : "Dados do Faturamento"}
                  </DialogTitle>
                </DialogHeader>
                <form onSubmit={handleSubmit} className="space-y-6 pt-2">
                  <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-2">
                      <Label
                        htmlFor="number"
                        className="text-[10px] font-black uppercase tracking-widest text-slate-500"
                      >
                        Número NF
                      </Label>
                      <Input
                        id="number"
                        className="bg-white/5 border-white/10 rounded-xl h-12 focus:ring-emerald-500/20"
                        value={formData.number}
                        onChange={(e) =>
                          setFormData({ ...formData, number: e.target.value })
                        }
                        placeholder="Ex: NF-2024-001"
                        required
                      />
                    </div>
                    <div className="space-y-2">
                      <Label
                        htmlFor="amount"
                        className="text-[10px] font-black uppercase tracking-widest text-slate-500"
                      >
                        Valor Bruto
                      </Label>
                      <Input
                        id="amount"
                        type="number"
                        step="0.01"
                        className="bg-white/5 border-white/10 rounded-xl h-12 focus:ring-emerald-500/20"
                        value={formData.amount}
                        onChange={(e) =>
                          setFormData({ ...formData, amount: e.target.value })
                        }
                        placeholder="0.00"
                        required
                      />
                    </div>
                  </div>
                  <div className="space-y-2">
                    <Label
                      htmlFor="client"
                      className="text-[10px] font-black uppercase tracking-widest text-slate-500"
                    >
                      Cliente / Tomador
                    </Label>
                    <Input
                      id="client"
                      className="bg-white/5 border-white/10 rounded-xl h-12 focus:ring-emerald-500/20"
                      value={formData.client}
                      onChange={(e) =>
                        setFormData({ ...formData, client: e.target.value })
                      }
                      placeholder="Nome completo ou Razão Social"
                      required
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-2">
                      <Label
                        htmlFor="date"
                        className="text-[10px] font-black uppercase tracking-widest text-slate-500"
                      >
                        Data Vencimento
                      </Label>
                      <Input
                        id="date"
                        type="date"
                        className="bg-white/5 border-white/10 rounded-xl h-12 focus:ring-emerald-500/20"
                        value={formData.dueDate}
                        onChange={(e) =>
                          setFormData({ ...formData, dueDate: e.target.value })
                        }
                        required
                      />
                    </div>
                    <div className="space-y-2">
                      <Label
                        htmlFor="status"
                        className="text-[10px] font-black uppercase tracking-widest text-slate-500"
                      >
                        Status Atual
                      </Label>
                      <Select
                        value={formData.status}
                        onValueChange={(v: "paid" | "pending" | "overdue") =>
                          setFormData({ ...formData, status: v })
                        }
                      >
                        <SelectTrigger className="bg-white/5 border-white/10 rounded-xl h-12">
                          <SelectValue placeholder="Selecione" />
                        </SelectTrigger>
                        <SelectContent className="bg-zinc-900 border-white/10 text-white">
                          <SelectItem value="pending">Pendente</SelectItem>
                          <SelectItem value="paid">Pago</SelectItem>
                          <SelectItem value="overdue">Atrasado</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                  </div>
                  <DialogFooter className="pt-6">
                    <Button
                      type="submit"
                      className="w-full bg-emerald-500 hover:bg-emerald-400 text-black font-black rounded-2xl h-14 uppercase tracking-widest transition-all"
                    >
                      {editingInv
                        ? "Atualizar Faturamento"
                        : "Registrar Nota Fiscal"}
                    </Button>
                  </DialogFooter>
                </form>
              </div>
            </DialogContent>
          </Dialog>
        </div>

        <div className="premium-card overflow-hidden">
          {invoices.length === 0 ? (
            <div className="p-12">
              <EmptyState
                icon={FileText}
                title="Nenhuma NF Registrada"
                description="Simplifique sua contabilidade registrando suas notas fiscais aqui."
                actionLabel="Começar Faturamento"
                onAction={() => setIsOpen(true)}
                tips={[
                  "A organização das notas fiscais é o segredo para uma DRE saudável.",
                  "Mantenha os dados do faturamento em dia para facilitar sua declaração de IR anual.",
                  "Notas pendentes de recebimento são ativos circulantes; monitore o fluxo de caixa.",
                ]}
              />
            </div>
          ) : (
            <div className="divide-y divide-white/5">
              {invoices.map((inv) => {
                const config = statusConfig[inv.status as keyof typeof statusConfig] || statusConfig.pending;
                const Icon = config.icon;

                return (
                  <div
                    key={inv.id}
                    className="group flex flex-col md:flex-row md:items-center justify-between p-6 hover:bg-white/[0.02] transition-colors gap-6"
                  >
                    <div className="flex items-center gap-6">
                      <div
                        className={`w-14 h-14 rounded-2xl flex items-center justify-center ${(config.color || "")
                          .split(" ")[0]
                          ?.replace("10", "20")} ${(config.color || "").split(" ")[1] || ""}`}
                      >
                        <Icon size={24} />
                      </div>
                      <div>
                        <div className="flex items-center gap-3 mb-1">
                          <p className="font-black text-lg text-white tracking-tight">
                            {inv.number}
                          </p>
                          <span
                            className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${config.color}`}
                          >
                            {config.label}
                          </span>
                        </div>
                        <p className="text-xs text-slate-500 font-bold uppercase tracking-wider">
                          {inv.client}{" "}
                          <span className="mx-2 text-slate-700">|</span>{" "}
                          <span className="text-slate-400">
                            Venc:{" "}
                            {new Date(inv.dueDate).toLocaleDateString("pt-BR")}
                          </span>
                        </p>
                      </div>
                    </div>

                    <div className="flex-1 flex justify-center md:justify-start">
                      {inv.status !== "paid" && (
                        <Button
                          size="sm"
                          variant="outline"
                          className="h-8 border-emerald-500/30 text-emerald-500 hover:bg-emerald-500/10 rounded-lg text-[10px] font-black uppercase tracking-widest px-4"
                          onClick={() => updateInvoice(inv.id, { status: "paid" })}
                        >
                          Marcar como Pago
                        </Button>
                      )}
                    </div>

                    <div className="flex items-center justify-between md:justify-end gap-10">
                      <div className="text-right">
                        <p className="text-[10px] font-black uppercase tracking-widest text-slate-600 mb-1">
                          Valor Total
                        </p>
                        <span className="font-black text-2xl text-white tracking-tighter">
                          <PrivacyValue value={inv.amount} />
                        </span>
                      </div>

                      <div className="flex items-center gap-2 opacity-100 md:opacity-0 group-hover:opacity-100 transition-all duration-300">
                        <Button
                          variant="ghost"
                          size="icon"
                          className="h-12 w-12 rounded-xl bg-white/5 hover:bg-white/10 text-slate-400 hover:text-white border border-white/5"
                          onClick={() => handleDownloadPDF(inv)}
                          title="Baixar PDF"
                        >
                          <FileText size={16} />
                        </Button>
                        <Button
                          variant="ghost"
                          size="icon"
                          className="h-12 w-12 rounded-xl bg-white/5 hover:bg-white/10 text-slate-400 hover:text-white border border-white/5"
                          onClick={() => handleEdit(inv)}
                        >
                          <Edit2 size={16} />
                        </Button>
                        <Button
                          variant="ghost"
                          size="icon"
                          className="h-12 w-12 rounded-xl bg-white/5 hover:bg-rose-500/10 text-slate-400 hover:text-rose-400 border border-white/5"
                          onClick={() => deleteInvoice(inv.id)}
                        >
                          <Trash2 size={16} />
                        </Button>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </FadeIn>
  );
};

import React from "react";
import {
  Area,
  AreaChart,
  CartesianGrid,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from "recharts";

interface Props {
  data: { month: string; value: number }[];
}

const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    const isPrivacy =
      localStorage.getItem("meu_contador_privacy_mode") === "true";

    return (
      <div className="bg-[#020617] border border-white/10 p-4 rounded-2xl shadow-2xl backdrop-blur-xl">
        <p className="text-xs font-black text-slate-500 uppercase tracking-widest mb-1">
          {label}
        </p>
        <p className="text-sm font-black text-white">
          {isPrivacy
            ? "****"
            : new Intl.NumberFormat("pt-BR", {
                style: "currency",
                currency: "BRL",
              }).format(payload[0].value)}
        </p>
      </div>
    );
  }
  return null;
};

export const NetWorthChart: React.FC<Props> = ({ data }) => {
  return (
    <div className="h-[200px] w-full items-end flex">
      <ResponsiveContainer width="100%" height="80%">
        <AreaChart data={data}>
          <defs>
            <linearGradient id="colorNetWorth" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#818cf8" stopOpacity={0.3} />
              <stop offset="95%" stopColor="#818cf8" stopOpacity={0} />
            </linearGradient>
          </defs>
          <CartesianGrid
            strokeDasharray="3 3"
            stroke="#ffffff05"
            vertical={false}
          />
          <XAxis dataKey="month" hide />
          <YAxis hide domain={["auto", "auto"]} />
          <Tooltip content={<CustomTooltip />} cursor={{ fill: "#ffffff05" }} />
          <Area
            type="monotone"
            dataKey="value"
            stroke="#818cf8"
            strokeWidth={3}
            fillOpacity={1}
            fill="url(#colorNetWorth)"
            animationDuration={2000}
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  businessCategories,
  initialTransactionFormData,
  paymentMethods,
  personalCategories,
} from "@/lib/constants";
import { SUPPORTED_CURRENCIES, currencyService } from "@/lib/currency";
import { getDefaultClassification } from "@/lib/financial-health";
import type { Transaction, TransactionFormData } from "@/types";
import { showError } from "@/lib/toast";
import { Edit2, PlusCircle, Save, X } from "lucide-react";
import { useEffect, useState } from "react";

interface TransactionFormProps {
  editingTransaction: Transaction | null;
  onSubmit: (formData: TransactionFormData, isEditing: boolean) => void;
  onCancel: () => void;
  scope?: "personal" | "business";
}

export const TransactionForm = ({
  editingTransaction,
  onSubmit,
  onCancel,
  scope = "personal",
}: TransactionFormProps) => {
  const [formData, setFormData] = useState<TransactionFormData>({
    ...initialTransactionFormData,
    currency: "BRL",
    scope,
  });

  const categories =
    scope === "personal" ? personalCategories : businessCategories;

  useEffect(() => {
    if (editingTransaction) {
      setFormData({
        ...editingTransaction,
        amount: editingTransaction.amount.toString(),
      } as any);
    } else {
      setFormData({ ...initialTransactionFormData, scope });
    }
  }, [editingTransaction, scope]);

  const handleSubmit = () => {
    if (!formData.description || !formData.amount || !formData.category) {
      showError("Por favor, preencha todos os campos obrigatórios");
      return;
    }

    const amountNum = parseFloat(formData.amount);
    if (amountNum <= 0) {
      showError("O valor deve ser maior que zero");
      return;
    }

    if (amountNum > 1000000000) {
      showError("Valor muito alto. Verifique se está correto.");
      return;
    }
    // Convert Amount if needed (Base is BRL)
    const finalAmount = currencyService.convertToBRL(
      parseFloat(formData.amount),
      (formData.currency as any) || "BRL"
    );

    // Save with original specs
    const payload = {
      ...formData,
      amount: finalAmount.toString(),
      originalAmount: parseFloat(formData.amount),
      exchangeRate: currencyService
        .getRate((formData.currency as any) || "BRL")
        .toString(),
    };

    onSubmit(payload, !!editingTransaction);
  };

  return (
    <Card className="shadow-card border-0 animate-scale-in">
      <CardHeader className="pb-4">
        <CardTitle className="flex items-center gap-2 text-xl">
          {editingTransaction ? (
            <Edit2 size={22} className="text-primary" />
          ) : (
            <PlusCircle size={22} className="text-primary" />
          )}
          {editingTransaction ? "Editar Transação" : "Nova Transação"}
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="space-y-2">
            <Label className="text-sm font-semibold">Tipo *</Label>
            <Select
              value={formData.type}
              onValueChange={(value: "income" | "expense") =>
                setFormData({ ...formData, type: value, category: "" })
              }
            >
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="income">Receita</SelectItem>
                <SelectItem value="expense">Despesa</SelectItem>
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-2">
            <Label className="text-sm font-semibold">Categoria *</Label>
            <Select
              value={formData.category}
              onValueChange={(value) =>
                setFormData({
                  ...formData,
                  category: value,
                  classification: getDefaultClassification(value),
                })
              }
            >
              <SelectTrigger>
                <SelectValue placeholder="Selecione..." />
              </SelectTrigger>
              <SelectContent>
                {categories[formData.type].map((cat) => (
                  <SelectItem key={cat} value={cat}>
                    {cat}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-2">
            <Label className="text-sm font-semibold">Valor (R$) *</Label>
            <Input
              type="number"
              step="0.01"
              value={formData.amount}
              onChange={(e) =>
                setFormData({ ...formData, amount: e.target.value })
              }
              placeholder="0,00"
            />
          </div>

          <div className="space-y-2">
            <Label className="text-sm font-semibold">Moeda</Label>
            <Select
              value={formData.currency || "BRL"}
              onValueChange={(value: any) =>
                setFormData({ ...formData, currency: value })
              }
            >
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {SUPPORTED_CURRENCIES.map((c) => (
                  <SelectItem key={c.code} value={c.code}>
                    {c.symbol} - {c.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            {formData.currency && formData.currency !== "BRL" && (
              <p className="text-[10px] text-muted-foreground">
                Cotação: 1 {formData.currency} ={" "}
                {currencyService
                  .getRate(formData.currency as any)
                  .toFixed(2)}{" "}
                BRL
              </p>
            )}
          </div>

          <div className="md:col-span-2 space-y-2">
            <Label className="text-sm font-semibold">Descrição *</Label>
            <Input
              type="text"
              value={formData.description}
              onChange={(e) =>
                setFormData({ ...formData, description: e.target.value })
              }
              placeholder={
                scope === "personal"
                  ? "Ex: Supermercado"
                  : "Ex: Venda de produtos"
              }
            />
          </div>

          <div className="space-y-2">
            <Label className="text-sm font-semibold">Data *</Label>
            <Input
              type="date"
              value={formData.date || new Date().toISOString().substring(0, 10)}
              onChange={(e) =>
                setFormData({ ...formData, date: e.target.value })
              }
            />
          </div>

          <div className="space-y-2">
            <Label className="text-sm font-semibold">Forma de Pagamento</Label>
            <Select
              value={formData.paymentMethod}
              onValueChange={(value) =>
                setFormData({ ...formData, paymentMethod: value })
              }
            >
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {paymentMethods.map((method) => (
                  <SelectItem key={method} value={method.toLowerCase()}>
                    {method}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {scope === "personal" && (
            <div className="space-y-2">
              <Label className="text-sm font-semibold">
                Classificação (50-30-20)
              </Label>
              <Select
                value={formData.classification}
                onValueChange={(value: any) =>
                  setFormData({ ...formData, classification: value })
                }
              >
                <SelectTrigger>
                  <SelectValue placeholder="Selecione..." />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="necessity">Necessidade (50%)</SelectItem>
                  <SelectItem value="want">Desejo (30%)</SelectItem>
                  <SelectItem value="investment">Investimento (20%)</SelectItem>
                  <SelectItem value="debt">Dívida / Outros</SelectItem>
                </SelectContent>
              </Select>
            </div>
          )}

          <div className="md:col-span-2 space-y-2">
            <Label className="text-sm font-semibold">Observações</Label>
            <Input
              type="text"
              value={formData.notes}
              onChange={(e) =>
                setFormData({ ...formData, notes: e.target.value })
              }
              placeholder="Informações adicionais..."
            />
          </div>

          <div className="flex items-center gap-4 md:col-span-2 p-4 bg-muted/30 rounded-lg border border-border/50">
            <div className="flex items-center gap-2">
              <input
                type="checkbox"
                id="recurring"
                checked={formData.recurring}
                onChange={(e) =>
                  setFormData({ ...formData, recurring: e.target.checked })
                }
                className="w-4 h-4 rounded border-gray-300 text-primary focus:ring-primary"
              />
              <Label
                htmlFor="recurring"
                className="text-sm font-semibold cursor-pointer"
              >
                Transação Recorrente
              </Label>
            </div>

            {formData.recurring && (
              <Select
                value={formData.recurrenceInterval || "monthly"}
                onValueChange={(
                  value: "monthly" | "weekly" | "bi-weekly" | "yearly"
                ) => setFormData({ ...formData, recurrenceInterval: value })}
              >
                <SelectTrigger className="w-[180px] h-8 bg-background">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="weekly">Semanal</SelectItem>
                  <SelectItem value="bi-weekly">Quinzenal</SelectItem>
                  <SelectItem value="monthly">Mensal</SelectItem>
                  <SelectItem value="yearly">Anual</SelectItem>
                </SelectContent>
              </Select>
            )}
          </div>
        </div>

        <div className="flex gap-3 pt-2">
          <Button
            onClick={handleSubmit}
            className="flex-1 gradient-primary border-0 text-primary-foreground font-semibold h-12"
          >
            <Save size={18} className="mr-2" />
            {editingTransaction ? "Salvar Alterações" : "Adicionar Transação"}
          </Button>
          <Button
            variant="secondary"
            onClick={onCancel}
            className="px-8 h-12 font-semibold"
          >
            <X size={18} className="mr-2" />
            Cancelar
          </Button>
        </div>
      </CardContent>
    </Card>
  );
};

import { useMemo, useState } from "react";
import { useAuth } from "@/context/AuthContext";
import { useDebts } from "@/hooks/useDebts";
import { useGoals } from "@/hooks/useGoals";
import { useInvestments } from "@/hooks/useInvestments";

import { EDUCATION_MODULES, ACADEMY_RITUALS, AULAS_TRILHAS, getLessonDependencyInfo, getLessonObjective, getLessonOutcomeType, getPrimaryTrailForProfile } from "@/data/educationData";
import { useEducation } from "@/hooks/useEducation";
import { LessonDetailView } from "./LessonDetailView";
import { showSuccess } from "@/lib/toast";
import type { TabType } from "@/types/navigation";

export const EducationSection = ({ onBack: _onBack, onNavigate }: { onBack?: () => void; onNavigate?: (tab: TabType) => void } = {}) => {
  const { user } = useAuth();
  const [activeLessonId, setActiveLessonId] = useState<string | null>(null);
  const [activeTrilha, setActiveTrilha] = useState<string>('todas');
  const [showPanorama, setShowPanorama] = useState(false);
  const [showLibrary, setShowLibrary] = useState(false);
  const [showJourney, setShowJourney] = useState(false);
  const [showMissions, setShowMissions] = useState(false);

  const primaryTrailId = getPrimaryTrailForProfile(user || undefined);
  const { debts } = useDebts();
  const { goals } = useGoals();
  const { assets } = useInvestments();

  // Estado para rituais interativos
  const [ritualChecked, setRitualChecked] = useState<Record<string, Record<number, boolean>>>({});

  const educationProfile = useMemo(() => ({
    ...(user || {}),
    debtBalance: debts.reduce((sum: number, debt: any) => sum + Number(debt.balance || debt.remainingAmount || 0), 0),
    goalsCount: goals.filter((goal: any) => !goal.completed).length,
    hasInvestments: assets.length > 0,
  }), [assets.length, debts, goals, user]);

  const { state, completeModule, saveLessonProgress, isModuleCompleted, getModuleProgress, getNextRecommendedLesson, getContextualRecommendation, getJourneyStage, getProgressPct, getReviewRecommendation, getMaturityRoadmap } = useEducation(educationProfile);

  // ✅ Todos os hooks declarados ANTES de qualquer return condicional
