        </div>
        <div style={{ fontSize: "14px", fontWeight: 700, color: "var(--t1)", marginBottom: "6px" }}>
          {journeyStage.title}
        </div>
        <div style={{ background: "var(--glass2)", borderRadius: "999px", height: "8px", overflow: "hidden", marginBottom: "6px" }}>
          <div style={{ width: `${progressPct}%`, height: "100%", background: "linear-gradient(90deg,#2F62D9,#5048E8)" }} />
        </div>
      </div>

      {/* ── MISSÃO DA SEMANA ─────────────────────────────── */}
      <div className="card" style={{ padding: "16px", marginBottom: "14px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "8px" }}>
          <div style={{ fontSize: "10px", color: "var(--t3)", textTransform: "uppercase", letterSpacing: "0.1em", fontWeight: 700 }}>
            Missão e ritual
          </div>
          <div style={{ fontSize: "11px", color: "var(--purple)" }} onClick={() => setShowMissions(!showMissions)}>
            {showMissions ? "fechar" : "ver tudo ▼"}
          </div>
        </div>
        <div style={{ fontSize: "14px", fontWeight: 700, color: "var(--t1)", marginBottom: "6px" }}>
          {weeklyMission.title}
        </div>
        <div style={{ fontSize: "12px", color: "var(--t2)", lineHeight: 1.5, marginBottom: "12px" }}>
          {weeklyMission.desc}
        </div>
        <button className="btn-p" style={{ marginTop: 0 }} onClick={() => weeklyMission.lessonId && setActiveLessonId(weeklyMission.lessonId)}>
          {weeklyMission.cta}
        </button>

        {/* Rituais interativos */}
        {showMissions && (
          <div style={{ marginTop: "16px", borderTop: "1px solid var(--border)", paddingTop: "12px" }}>
            {ACADEMY_RITUALS.map((ritual) => {
              const ritualKey = ritual.id;
              const checkedItems = ritualChecked[ritualKey] || {};
              const allChecked = ritual.checklist.every((_, idx) => checkedItems[idx]);
              return (
                <div key={ritual.id} style={{ marginBottom: "16px" }}>
                  <div style={{ display: "flex", alignItems: "center", gap: "6px", marginBottom: "8px" }}>
                    <span style={{ fontSize: "12px" }}>{ritual.period === 'semana' ? '📅' : '📆'}</span>
                    <div style={{ fontSize: "13px", fontWeight: 700, color: "var(--t1)" }}>{ritual.title}</div>
                  </div>
                  <div style={{ fontSize: "11px", color: "var(--t2)", marginBottom: "8px" }}>{ritual.description}</div>
                  {ritual.checklist.map((item, idx) => (
                    <div
                      key={idx}
                      onClick={() => {
                        setRitualChecked(prev => ({
                          ...prev,
                          [ritualKey]: { ...prev[ritualKey], [idx]: !prev[ritualKey]?.[idx] }
                        }));
                      }}
                      style={{
                        display: "flex", alignItems: "flex-start", gap: "8px", padding: "6px 0",
                        cursor: "pointer", opacity: checkedItems[idx] ? 0.5 : 1,
                      }}
                    >
                      <div style={{
                        width: "16px", height: "16px", borderRadius: "4px", flexShrink: 0, marginTop: "1px",
                        border: checkedItems[idx] ? "none" : "1.5px solid var(--t3)",
                        background: checkedItems[idx] ? "var(--green)" : "transparent",
                        display: "flex", alignItems: "center", justifyContent: "center",
                        color: "#fff", fontSize: "10px", fontWeight: 900,
                      }}>
                        {checkedItems[idx] && "✓"}
                      </div>
                      <div style={{ fontSize: "11px", color: "var(--t2)", textDecoration: checkedItems[idx] ? "line-through" : "none" }}>
                        {item}
                      </div>
                    </div>
                  ))}
                  {allChecked && (
                    <div style={{ fontSize: "10px", color: "var(--green)", fontWeight: 600, marginTop: "4px" }}>
                      ✅ Ritual completo — boa disciplina!
                    </div>
                  )}
                  <button
                    className="btn-p"
                    style={{ marginTop: "8px", fontSize: "11px", padding: "6px 12px" }}
                    onClick={() => {
                      if (onNavigate) onNavigate(ritual.targetTab as TabType);
                    }}
                  >
                    {ritual.actionLabel}
                  </button>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* ── Panorama de Maturidade ─────────────────────────── */}
      <div className="card" style={{ padding: "16px", marginBottom: "14px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "10px" }}>
          <div style={{ fontSize: "10px", color: "var(--t3)", textTransform: "uppercase", letterSpacing: "0.1em", fontWeight: 700 }}>
            Panorama de maturidade
          </div>
          <div style={{ fontSize: "11px", color: "var(--blue)" }} onClick={() => setShowPanorama(!showPanorama)}>
            {showPanorama ? "fechar" : "ver mapa ▼"}
          </div>
        </div>
        {showPanorama && (
          <div style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
            {maturityRoadmap.map((stage) => (
              <div key={stage.id} style={{ display: "flex", alignItems: "center", gap: "10px" }}>
                <div style={{
                  width: "28px", height: "28px", borderRadius: "50%", flexShrink: 0,
                  display: "flex", alignItems: "center", justifyContent: "center",
                  fontSize: "11px", fontWeight: 800,
                  background: stage.progressPct === 100 ? "linear-gradient(135deg, #00D991, #00B87A)" : stage.progressPct > 0 ? "linear-gradient(135deg, #2F62D9, #5048E8)" : "var(--glass2)",
                  color: stage.progressPct > 0 ? "#fff" : "var(--t3)",
                }}>
                  {stage.progressPct === 100 ? "✓" : `${stage.progressPct}%`}
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: "12px", fontWeight: 700, color: "var(--t1)" }}>{stage.title}</div>
                  <div style={{ fontSize: "10px", color: "var(--t3)" }}>{stage.description}</div>
                  <div style={{ background: "var(--glass2)", borderRadius: "999px", height: "4px", overflow: "hidden", marginTop: "4px" }}>
                    <div style={{
                      width: `${stage.progressPct}%`, height: "100%",
                      background: stage.progressPct === 100 ? "linear-gradient(90deg,#00D991,#00B87A)" : "linear-gradient(90deg,#2F62D9,#5048E8)",
                    }} />
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* ── BIBLIOTECA ─────────────────────────────── */}
      <div className="card" style={{ padding: "16px", marginBottom: "14px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "8px" }}>
          <div style={{ fontSize: "10px", color: "var(--t3)", textTransform: "uppercase", letterSpacing: "0.1em", fontWeight: 700 }}>
            Biblioteca completa
          </div>
          <div style={{ fontSize: "11px", color: "var(--green)" }} onClick={() => setShowLibrary(!showLibrary)}>
            {showLibrary ? "fechar" : "abrir ▼"}
          </div>
        </div>

        {showLibrary && (
          <div style={{ marginTop: "8px" }}>
            <div style={{ display: "flex", gap: "8px", overflowX: "auto", scrollbarWidth: "none", margin: "0 -16px", padding: "0 16px 12px" }}>
              <div
                className={`tpill ${activeTrilha === 'todas' ? 'active' : ''}`}
                style={activeTrilha === 'todas' ? { background: "linear-gradient(135deg, #2F62D9, #5048E8)", borderColor: "transparent" } : {}}
                onClick={() => setActiveTrilha('todas')}
              >
                🗂️ Todas
              </div>
              {(AULAS_TRILHAS as { id: string; label: string; emoji: string; color: string }[]).map(t => (
                <div
                  key={t.id}
                  className={`tpill ${activeTrilha === t.id ? 'active' : ''}`}
                  style={activeTrilha === t.id ? { background: t.color, borderColor: "transparent" } : { color: t.color, borderColor: `${t.color}44` }}
                  onClick={() => setActiveTrilha(t.id)}
                >
                  {t.emoji} {t.label}
                </div>
              ))}
            </div>

            {/* ── Lições ─────────────────────────────── */}
            {filteredLessons.map((l) => {
              const moduleProgress = getModuleProgress(l.id);
              const isCompleted = isModuleCompleted(l.id);
              const globalIdx: number = EDUCATION_MODULES.findIndex(m => m.id === l.id);
              const dependencyInfo = getLessonDependencyInfo(l.id);
              const hardDependencyIds: string[] = dependencyInfo.hardPrerequisites
                .filter((item: string) => item.startsWith('lesson:'))
                .map((item: string) => item.replace('lesson:', ''));
              const missingHardDependencies: string[] = hardDependencyIds.filter((id: string) => !isModuleCompleted(id));
              const isLocked = !isCompleted && missingHardDependencies.length > 0;
              const previousLesson = globalIdx > 0 ? EDUCATION_MODULES[globalIdx - 1] : null;
              const isPrimaryTrail = l.trilha === primaryTrailId;

              const tr = AULAS_TRILHAS.find(t => t.id === l.trilha);
              const conceptsCount = l.passos.filter(p => p.tipo !== 'quiz').length;

              return (
                <div
                  key={l.id}
                  className="lcard"
                  onClick={() => {
                    if (isLocked) {
                      showSuccess('🔒 Complete as lições anteriores primeiro');
                    } else {
                      setActiveLessonId(l.id);
                    }
                  }}
                  style={{ opacity: isLocked ? 0.5 : 1 }}
                >
                  <div className="lbanner" style={{ background: l.grad }}>
                    <span style={{ fontSize: "36px", filter: isLocked ? "grayscale(1)" : "none" }}>{l.emoji}</span>
                    {isCompleted ? (
                      <span className="lbadge" style={{ background: "var(--green-d)", color: "var(--green)", border: "1px solid rgba(0,217,145,0.3)" }}>✓ Concluída</span>
                    ) : isLocked ? (
                      <span className="lbadge" style={{ background: "rgba(0,0,0,0.4)", color: "var(--t3)", border: "1px solid var(--border)" }}>🔒 Bloqueada</span>
                    ) : isPrimaryTrail ? (
                      <span className="lbadge" style={{ background: "rgba(0,217,145,0.16)", color: "var(--green)", border: "1px solid rgba(0,217,145,0.3)" }}>Trilha principal</span>
                    ) : (
                      <span className="lbadge" style={{ background: "rgba(74,139,255,0.2)", color: "var(--blue)", border: "1px solid rgba(74,139,255,0.3)" }}>Nova</span>
                    )}
                    {isCompleted && (
                      <div style={{ position: "absolute", bottom: "8px", left: "14px", display: "flex", gap: "3px" }}>⭐⭐⭐</div>
                    )}
                  </div>
                  <div className="lbody">
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                      <div>
                        <div style={{ fontSize: "14.5px", fontWeight: 700, color: "var(--t1)", marginBottom: "2px" }}>{l.title}</div>
                        <div style={{ fontSize: "11.5px", color: "var(--t2)" }}>{l.sub}</div>
                      </div>
                      <div style={{ textAlign: "right", flexShrink: 0 }}>
                        <div style={{ fontSize: "11px", color: "var(--blue)", fontWeight: 700, fontFamily: "var(--mono)" }}>+{l.xp} XP</div>
                        <div style={{ fontSize: "10px", color: "var(--t3)", marginTop: "1px" }}>⏱ {l.dur}</div>
                      </div>
                    </div>
                    <div style={{ display: "flex", gap: "6px", marginTop: "8px", alignItems: "center" }}>
                      <span style={{ fontSize: "10px", fontWeight: 600, padding: "3px 8px", borderRadius: "20px", background: tr?.bg || 'var(--glass2)', color: tr?.color || 'var(--t2)' }}>
                        {tr?.emoji} {tr?.label}
                      </span>
                      <span style={{ fontSize: "10px", fontWeight: 700, padding: "3px 8px", borderRadius: "20px", background: "rgba(255,255,255,0.05)", color: "var(--amber)" }}>
                        foco: {getLessonOutcomeType(l)}
                      </span>
                      <span style={{ fontSize: "10px", color: "var(--t3)" }}>
                        {conceptsCount} conceitos · {moduleProgress.totalSteps} passos
                      </span>
                    </div>
                    <div style={{ marginTop: "8px" }}>
                      <div style={{ background: "var(--glass2)", borderRadius: "999px", height: "6px", overflow: "hidden" }}>
                        <div style={{ width: `${moduleProgress.progressPct}%`, height: "100%", background: isCompleted ? "linear-gradient(90deg,#00D991,#00B87A)" : "linear-gradient(90deg,#2F62D9,#5048E8)" }} />
                      </div>
                      <div style={{ marginTop: "6px", fontSize: "10px", color: moduleProgress.hasStarted ? "var(--blue)" : "var(--t3)", fontWeight: moduleProgress.hasStarted ? 600 : 400 }}>
                        {isCompleted
                          ? `Checkpoint finalizado · ${moduleProgress.totalSteps}/${moduleProgress.totalSteps} passos`
                          : moduleProgress.hasStarted
                            ? `${moduleProgress.checkpointLabel}`
                            : `Progresso do módulo · 0/${moduleProgress.totalSteps} passos`}
                      </div>
                    </div>
                    <div style={{ marginTop: "8px", fontSize: "10px", color: isLocked ? "var(--amber)" : "var(--t3)" }}>
                      {globalIdx === 0
                        ? "Ponto de partida recomendado da jornada"
                        : isLocked && missingHardDependencies.length > 0
                          ? `Pré-requisito por competência: conclua "${EDUCATION_MODULES.find((lesson) => lesson.id === missingHardDependencies[0])?.title || previousLesson?.title}"`
                          : previousLesson
                            ? `Continuação de: ${previousLesson.title}`
                            : ""}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* ── Revisão Pendente ─────────────────────────── */}
      {reviewRecommendation.lesson && (
        <div className="card" style={{ padding: "16px", marginBottom: "14px", border: "1px solid rgba(155,127,255,0.22)", background: "linear-gradient(135deg, rgba(155,127,255,0.08), rgba(74,139,255,0.06))" }}>
          <div style={{ fontSize: "10px", color: "var(--purple)", textTransform: "uppercase", letterSpacing: "0.1em", fontWeight: 800, marginBottom: "6px" }}>
            Revisão espaçada pendente
          </div>
          <div style={{ fontSize: "14px", fontWeight: 700, color: "var(--t1)", marginBottom: "4px" }}>
            {reviewRecommendation.lesson.emoji} {reviewRecommendation.lesson.title}
          </div>
          <div style={{ fontSize: "12px", color: "var(--t2)", lineHeight: 1.5, marginBottom: "10px" }}>
            {reviewRecommendation.reason}
          </div>
          <button className="btn-p" style={{ marginTop: 0, background: "linear-gradient(135deg, #9B7FFF, #5048E8)" }} onClick={() => setActiveLessonId(reviewRecommendation.lesson!.id)}>
            Revisar agora
          </button>
        </div>
      )}

      {/* ── Conquistas ─────────────────────────── */}
      <div className="sec-hd"><span className="sec-title">Conquistas</span></div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(150px, 1fr))", gap: "10px", marginBottom: "16px" }}>
        {dynamicAchievements.map((c, idx) => (
          <div key={idx} className="card" style={{ opacity: c.ok ? 1 : 0.45, display: "flex", alignItems: "center", gap: "10px", padding: "12px" }}>
            <div className="ach" style={{ background: c.ok ? "rgba(255,173,59,0.12)" : "var(--glass2)" }}>{c.emoji}</div>
            <div>
              <div style={{ fontSize: "12px", fontWeight: 700, color: "var(--t1)" }}>{c.nome}</div>
              <div style={{ fontSize: "10.5px", color: "var(--t3)", marginTop: "1px" }}>{c.desc}</div>
              {c.ok ? (
                <div style={{ fontSize: "10px", color: "var(--amber)", fontWeight: 600, marginTop: "2px" }}>✓ Desbloqueada</div>
              ) : (
                <div style={{ fontSize: "10px", color: "var(--t3)", marginTop: "2px" }}>🔒 Bloqueada</div>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, ChevronRight, Sparkles } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useEmotionalJournal } from '@/hooks/useEmotionalJournal';
import type { EmotionType, PurchaseMotivation } from '@/types/emotional';
import { EMOTION_CONFIG, MOTIVATION_CONFIG, EMOTIONAL_TRIGGERS } from '@/types/emotional';

interface EmotionalCheckInProps {
  isOpen: boolean;
  onClose: () => void;
  transactionAmount?: number;
  transactionCategory?: string;
  onComplete?: (entry: any) => void;
}

export function EmotionalCheckIn({
  isOpen,
  onClose,
  transactionAmount,
  transactionCategory,
  onComplete,
}: EmotionalCheckInProps) {
  const { addEntry } = useEmotionalJournal();
  const [step, setStep] = useState<'emotion' | 'motivation' | 'triggers' | 'regret'>('emotion');
  const [selectedEmotion, setSelectedEmotion] = useState<EmotionType | null>(null);
  const [selectedMotivation, setSelectedMotivation] = useState<PurchaseMotivation | null>(null);
  const [selectedTriggers, setSelectedTriggers] = useState<string[]>([]);
  const [regretLevel, setRegretLevel] = useState<number>(3);
  const [satisfactionLevel, setSatisfactionLevel] = useState<number>(3);
  const [notes, setNotes] = useState('');

  const handleEmotionSelect = (emotion: EmotionType) => {
    setSelectedEmotion(emotion);
    setStep('motivation');
  };

  const handleMotivationSelect = (motivation: PurchaseMotivation) => {
    setSelectedMotivation(motivation);
    setStep('triggers');
  };

  const handleTriggerToggle = (trigger: string) => {
    setSelectedTriggers((prev) =>
      prev.includes(trigger) ? prev.filter((t) => t !== trigger) : [...prev, trigger]
    );
  };

  const handleTriggersComplete = () => {
    setStep('regret');
  };

  const handleComplete = () => {
    if (!selectedEmotion || !selectedMotivation) return;

    const entry = addEntry({
      emotion: selectedEmotion,
      motivation: selectedMotivation,
      triggers: selectedTriggers,
      regretLevel,
      satisfactionLevel,
      notes: notes.trim() || undefined,
      amount: transactionAmount,
      category: transactionCategory,
    });

    onComplete?.(entry);
    handleClose();
  };

  const handleClose = () => {
    setStep('emotion');
    setSelectedEmotion(null);
    setSelectedMotivation(null);
    setSelectedTriggers([]);
    setRegretLevel(3);
    setSatisfactionLevel(3);
    setNotes('');
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[200] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
      <motion.div
        initial={{ opacity: 0, scale: 0.95, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95, y: 20 }}
        className="w-full max-w-md bg-[#0a0f1a] border border-white/10 rounded-3xl overflow-hidden"
      >
        {/* Header */}
        <div className="p-6 border-b border-white/10 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-500/20 rounded-xl">
              <Sparkles size={20} className="text-indigo-400" />
            </div>
            <div>
              <h3 className="font-bold text-white">Check-in Emocional</h3>
              <p className="text-xs text-slate-500">
                {step === 'emotion' && 'Como você se sente?'}
                {step === 'motivation' && 'O que motivou esta compra?'}
                {step === 'triggers' && 'O que causou essa emoção?'}
                {step === 'regret' && 'Nível de satisfação'}
              </p>
            </div>
          </div>
          <button
            onClick={handleClose}
            className="p-2 hover:bg-white/5 rounded-xl transition-colors"
          >
            <X size={20} className="text-slate-400" />
          </button>
        </div>

        {/* Content */}
        <div className="p-6 min-h-[300px]">
          <AnimatePresence mode="wait">
            {/* Step 1: Emotion */}
            {step === 'emotion' && (
              <motion.div
                key="emotion"
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -20 }}
                className="grid grid-cols-2 gap-3"
              >
                {(Object.entries(EMOTION_CONFIG) as [EmotionType, typeof EMOTION_CONFIG[EmotionType]][]).map(
                  ([key, config]) => (
                    <button
                      key={key}
                      onClick={() => handleEmotionSelect(key)}
                      className={`p-4 rounded-2xl border transition-all text-left ${
                        selectedEmotion === key
                          ? 'border-indigo-500 bg-indigo-500/10'
                          : 'border-white/5 hover:border-white/10 hover:bg-white/5'
                      }`}
                    >
                      <span className="text-2xl block mb-2">{config.emoji}</span>
                      <span className="text-sm font-medium text-white">{config.label}</span>
                    </button>
                  )
                )}
              </motion.div>
            )}

            {/* Step 2: Motivation */}
            {step === 'motivation' && (
              <motion.div
                key="motivation"
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -20 }}
                className="space-y-3"
              >
                {(Object.entries(MOTIVATION_CONFIG) as [PurchaseMotivation, typeof MOTIVATION_CONFIG[PurchaseMotivation]][]).map(
                  ([key, config]) => (
                    <button
                      key={key}
                      onClick={() => handleMotivationSelect(key)}
                      className={`w-full p-4 rounded-2xl border transition-all text-left flex items-center gap-4 ${
                        selectedMotivation === key
                          ? 'border-indigo-500 bg-indigo-500/10'
                          : 'border-white/5 hover:border-white/10 hover:bg-white/5'
                      }`}
                    >
                      <span className="text-2xl">{config.emoji}</span>
                      <div className="flex-1">
                        <p className="font-medium text-white">{config.label}</p>
                        <p className="text-xs text-slate-500">{config.description}</p>
                      </div>
                      <div
                        className={`w-2 h-2 rounded-full ${
                          config.riskLevel === 'high'
                            ? 'bg-rose-500'
                            : config.riskLevel === 'medium'
                            ? 'bg-amber-500'
                            : 'bg-emerald-500'
                        }`}
                      />
                    </button>
                  )
                )}
              </motion.div>
            )}

            {/* Step 3: Triggers */}
            {step === 'triggers' && (
              <motion.div
                key="triggers"
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -20 }}
              >
                <p className="text-sm text-slate-400 mb-4">
                  Selecione o que causou essa emoção (opcional):
                </p>
                <div className="flex flex-wrap gap-2 mb-6">
                  {EMOTIONAL_TRIGGERS.map((trigger) => (
                    <button
                      key={trigger}
                      onClick={() => handleTriggerToggle(trigger)}
                      className={`px-3 py-2 rounded-xl text-xs font-medium transition-all ${
                        selectedTriggers.includes(trigger)
                          ? 'bg-indigo-500 text-white'
                          : 'bg-white/5 text-slate-400 hover:bg-white/10 hover:text-white'
                      }`}
                    >
                      {trigger}
                    </button>
                  ))}
                </div>
                <Button
                  onClick={handleTriggersComplete}
                  className="w-full bg-indigo-600 hover:bg-indigo-500 rounded-xl"
                >
                  Continuar
                  <ChevronRight size={16} className="ml-2" />
                </Button>
              </motion.div>
            )}

            {/* Step 4: Regret/Satisfaction */}
            {step === 'regret' && (
              <motion.div
                key="regret"
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -20 }}
                className="space-y-6"
              >
                {/* Satisfaction */}
                <div>
                  <Label className="text-sm font-medium text-slate-300 mb-3 block">
                    Nível de satisfação com esta compra:
                  </Label>
                  <div className="flex gap-2">
                    {[1, 2, 3, 4, 5].map((level) => (
                      <button
                        key={level}
                        onClick={() => setSatisfactionLevel(level)}
                        className={`flex-1 py-3 rounded-xl font-bold transition-all ${
                          satisfactionLevel === level
                            ? level <= 2
                              ? 'bg-rose-500 text-white'
                              : level === 3
                              ? 'bg-amber-500 text-white'
                              : 'bg-emerald-500 text-white'
                            : 'bg-white/5 text-slate-500 hover:bg-white/10'
                        }`}
                      >
                        {level}
                      </button>
                    ))}
                  </div>
                  <div className="flex justify-between text-[10px] text-slate-600 mt-1">
                    <span>Insatisfeito</span>
                    <span>Muito satisfeito</span>
                  </div>
                </div>

                {/* Regret */}
                <div>
                  <Label className="text-sm font-medium text-slate-300 mb-3 block">
                    Nível de arrependimento:
                  </Label>
                  <div className="flex gap-2">
                    {[1, 2, 3, 4, 5].map((level) => (
                      <button
                        key={level}
                        onClick={() => setRegretLevel(level)}
                        className={`flex-1 py-3 rounded-xl font-bold transition-all ${
                          regretLevel === level
                            ? level >= 4
                              ? 'bg-rose-500 text-white'
                              : level === 3
                              ? 'bg-amber-500 text-white'
                              : 'bg-emerald-500 text-white'
                            : 'bg-white/5 text-slate-500 hover:bg-white/10'
                        }`}
                      >
                        {level}
                      </button>
                    ))}
                  </div>
                  <div className="flex justify-between text-[10px] text-slate-600 mt-1">
                    <span>Sem arrependimento</span>
                    <span>Muito arrependido</span>
                  </div>
                </div>

                {/* Notes */}
                <div>
                  <Label className="text-sm font-medium text-slate-300 mb-2 block">
                    Notas (opcional):
                  </Label>
                  <Input
                    value={notes}
                    onChange={(e) => setNotes(e.target.value)}
                    placeholder="Ex: Comprei por impulso depois de ver stories..."
                    className="bg-white/5 border-white/10 text-white rounded-xl"
                  />
                </div>

                {/* Complete */}
                <Button
                  onClick={handleComplete}
                  className="w-full bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 rounded-xl font-bold"
                >
                  Salvar Registro Emocional
                </Button>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        {/* Footer */}
        <div className="px-6 py-4 border-t border-white/5 bg-white/[0.02]">
          <p className="text-center text-[10px] text-slate-600 uppercase tracking-widest">
            Journaling Emocional • Meu Contador
          </p>
        </div>
      </motion.div>
    </div>
  );
}

import { useState } from "react";
import type { TabType } from "@/types/navigation";
import { useTransactions } from "@/hooks/useTransactions";
import { useDebts } from "@/hooks/useDebts";
import { useInvestments } from "@/hooks/useInvestments";
import { ArrowLeft, Droplet, TrendingUp, TrendingDown, Network, Target, Brain, ShieldCheck, ChevronDown, ChevronRight } from "lucide-react";

import { AreaTutorialButton } from "@/components/ui/AreaTutorialButton";

const STRESS_LABELS = ["Crítico (Ansiedade)", "Alto (Desconforto)", "Moderado", "Leve", "Tranquilidade Plena"];
const COLOR_MAP: Record<string, string> = { g: "var(--green)", b: "var(--blue)", a: "var(--amber)", r: "var(--red)" };
const BG_MAP: Record<string, string> = { g: "var(--green-d)", b: "var(--blue3)", a: "var(--amber-d)", r: "var(--red-d)" };

function scoreColor(s: number) {
  if (s >= 80) return "g";
  if (s >= 60) return "b";
  if (s >= 40) return "a";
  return "r";
}

interface HealthSectionProps {
  onBack?: (tab: TabType) => void;
  onNavigate?: (tab: TabType) => void;
}

interface HealthDimension {
  em: JSX.Element;
  nm: string;
  ds: string;
  sc: number;
  cl: string;
}

export const HealthSection = ({ onBack, onNavigate }: HealthSectionProps = {}) => {
  const [selectedStress, setSelectedStress] = useState<number | null>(null);
  const [expandedDim, setExpandedDim] = useState<string | null>(null);

  const { transactions, totals: txTotals } = useTransactions("personal");
  const { debts, totals: debtTotals } = useDebts();
  const { assets, totals: investTotals } = useInvestments();

  // --- Real financial metric calculations ---
  const monthlyExpenses = txTotals.expense || (transactions.filter(t => t.type === "expense").reduce((s, t) => s + t.amount, 0)) || 1;
  const monthlyIncome = txTotals.income || (transactions.filter(t => t.type === "income").reduce((s, t) => s + t.amount, 0)) || 1;
  const netWorth = txTotals.balance + investTotals.currentValue - debtTotals.totalBalance;

  // --- Persistence for Stress ---
  useState(() => {
    const saved = localStorage.getItem("health_stress_index");
    if (saved !== null && selectedStress === null) {
      setSelectedStress(parseInt(saved));
    }
    return null;
  });

  const handleSetStress = (val: number) => {
    setSelectedStress(val);
    localStorage.setItem("health_stress_index", val.toString());
  };

  // 1. Liquidez — com validação NaN/Infinity
  const reserva = investTotals.currentValue;
  const safeMonthlyExpenses = monthlyExpenses > 0 && isFinite(monthlyExpenses) ? monthlyExpenses : 1;
  const liquidezMeses = reserva > 0 ? Math.min(12, reserva / safeMonthlyExpenses) : 0;
  const liquidezScore = isFinite(liquidezMeses) ? Math.min(100, Math.round(liquidezMeses / 6 * 100)) : 0;

  // 2. Poupança — com validação NaN/Infinity
  const safeMonthlyIncome = monthlyIncome > 0 && isFinite(monthlyIncome) ? monthlyIncome : 1;
  const savingRate = ((safeMonthlyIncome - safeMonthlyExpenses) / safeMonthlyIncome) * 100;
  const poupancaScore = isFinite(savingRate) ? Math.max(0, Math.min(100, Math.round(savingRate * 3))) : 0;

  // 3. Dívidas — com validação NaN/Infinity
  const debtRatio = netWorth > 0 && isFinite(netWorth) 
    ? (debtTotals.totalBalance / netWorth) * 100 
    : (debtTotals.totalBalance > 0 ? 100 : 0);
  const dividaScore = isFinite(debtRatio) ? Math.max(0, Math.round(100 - debtRatio * 5)) : 0;

  // 4. Diversificação — Real logic based on asset types
  const assetTypes = new Set(assets.filter(a => a.amount > 0).map(a => a.type));
  const uniqueAssetTypes = assetTypes.size;
  const diversScore = Math.min(100, uniqueAssetTypes * 25);

  // 5. Proteção — Real logic based on transaction keywords
  const insuranceKeywords = ["seguro", "unimed", "bradesco saude", "sulamerica", "previdência", "porto seguro"];
  const hasInsurance = transactions.some(t => 
    insuranceKeywords.some(k => 
      (t.description || "").toLowerCase().includes(k) || 
      (t.category || "").toLowerCase().includes(k)
    )
  );
  const protecaoScore = hasInsurance ? 100 : 45;

  // 6. Trajetória F.I.R.E — com validação NaN/Infinity
  const fireProb = isFinite(savingRate) ? Math.max(0, Math.min(100, Math.round(savingRate * 2.5))) : 0;
  const trajetoriaScore = isFinite(fireProb) ? Math.max(10, Math.round(fireProb * 0.8)) : 0;

  // 7. Bem-estar
  const bemEstarScore = selectedStress !== null ? ([20, 35, 55, 75, 95][selectedStress] ?? 55) : 55;

  const getAction = (dim: string, score: number) => {
    if (score >= 80) return { title: "Excelente! Manutenção sugerida", text: "Continue com a estratégia atual. Você está no quartil superior nesta métrica.", act: "" };
    switch(dim) {
      case "Reserva de Emergência":
        return { title: "Crie um colchão de liquidez", text: "Você precisa guardar de 6 a 12 meses do seu custo mensal. Comece cortando gastos não essenciais.", act: "investments", actText: "Ver Investimentos" };
      case "Acumulação Corrente":
        return { title: "Aumente sua taxa de poupança", text: "O ideal é poupar 20% ou mais da sua renda. Tente usar a regra 50-30-20.", act: "planning", actText: "Ajustar Orçamento" };
      case "Alavancagem":
        return { title: "Riscos de endividamento", text: "Priorize quitar dívidas com juros altos (cartão, cheque especial) antes de investir.", act: "debts", actText: "Gerenciar Dívidas" };
      case "Diversificação":
        return { title: "Espalhe o risco", text: "Sua carteira está concentrada. Busque alocar em renda fixa, ETFs globais e fundos imobiliários.", act: "investments", actText: "Explorar Ativos" };
      case "Mitigação de Riscos":
        return { title: "Seguro de vida e saúde", text: "Proteger seu patrimônio contra imprevistos de saúde ou fatalidades é essencial para não quebrar.", act: "insurance_planner", actText: "Planejar Seguros" };
      case "Modelagem F.I.R.E":
        return { title: "Rever matemática da aposentadoria", text: "Com o ritmo atual, sua aposentadoria não está garantida. Faça simulações para ver onde cortar.", act: "retire_fire", actText: "Calculadora F.I.R.E" };
      case "Status Biopsicossocial":
        return { title: "Estresse Financeiro", text: "Faça o check-in de bem-estar abaixo regularmente. A ansiedade pode boicotar bons investimentos.", act: "", actText: "" };
      default: return { title: "", text: "", act: "" };
    }
  };

  const DIMS: HealthDimension[] = [
    { em: <Droplet size={18} strokeWidth={2.5} color="var(--t2)"/>, nm: "Reserva de Emergência", ds: liquidezMeses > 0 ? liquidezMeses.toFixed(1) + " meses de sobrevida" : "Em risco", sc: liquidezScore, cl: scoreColor(liquidezScore) },
    { em: <TrendingUp size={18} strokeWidth={2.5} color="var(--t2)"/>, nm: "Acumulação Corrente", ds: savingRate > 0 ? "Poupança: " + savingRate.toFixed(1) + "%" : "Renda consumida", sc: poupancaScore, cl: scoreColor(poupancaScore) },
    { em: <TrendingDown size={18} strokeWidth={2.5} color="var(--t2)"/>, nm: "Alavancagem", ds: debts.length > 0 ? debtRatio.toFixed(1) + "% comprometido" : "Zero dívidas", sc: dividaScore, cl: scoreColor(dividaScore) },
    { em: <Network size={18} strokeWidth={2.5} color="var(--t2)"/>, nm: "Diversificação", ds: uniqueAssetTypes + " classes de ativos", sc: diversScore, cl: scoreColor(diversScore) },
    { em: <ShieldCheck size={18} strokeWidth={2.5} color="var(--t2)"/>, nm: "Mitigação de Riscos", ds: hasInsurance ? "Cobertura OK" : "Sem seguros conhecidos", sc: protecaoScore, cl: scoreColor(protecaoScore) },
    { em: <Target size={18} strokeWidth={2.5} color="var(--t2)"/>, nm: "Modelagem F.I.R.E", ds: fireProb + "% de chance de IF", sc: trajetoriaScore, cl: scoreColor(trajetoriaScore) },
    { em: <Brain size={18} strokeWidth={2.5} color="var(--t2)"/>, nm: "Status Biopsicossocial", ds: selectedStress !== null ? (STRESS_LABELS[selectedStress] || "Dados insuficientes") : "Dados insuficientes", sc: bemEstarScore, cl: scoreColor(bemEstarScore) },
  ];

  const score = Math.round(DIMS.reduce((s, d) => s + d.sc, 0) / DIMS.length);
  const historyPoints = [
    Math.max(0, Math.round(score - 9)),
    Math.max(0, Math.round(score - 5)),
    Math.max(0, Math.round(score - 2)),
    score,
  ];
  const r = 56;
  const circumference = 2 * Math.PI * r;
  const offset = circumference * (1 - score / 100);

  const scoreLabel = score >= 80 ? "Excelente" : score >= 65 ? "Boa" : score >= 50 ? "Regular" : "Precisa melhorar";
  const scoreColor2 = score >= 80 ? "var(--green)" : score >= 65 ? "var(--blue)" : score >= 50 ? "var(--amber)" : "var(--red)";

  return (
    <div style={{ animation: "fsu 0.26s ease", paddingBottom: "100px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 20, paddingTop: "10px" }}>
        {onBack && (
          <button className="back-btn" onClick={() => onBack("inicio")}>
            <ArrowLeft size={16} />
          </button>
        )}
        <div style={{ flex: 1 }}>
          <div className="eyebrow" style={{ marginBottom: 4 }}>Score 360°</div>
          <div className="page-title" style={{ margin: 0 }}>Saúde Financeira</div>
        </div>
        <AreaTutorialButton area="futuro" onNavigate={onNavigate} />
      </div>

      {/* Score ring */}
      <div id="health-score" className="hero" style={{ textAlign: "center", padding: "28px 20px 22px", marginBottom: 16 }}>
        <svg style={{ width: 140, height: 140, margin: "0 auto 16px" }} viewBox="0 0 140 140">
          <circle cx="70" cy="70" r={r} fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="11" />
          <circle
            cx="70" cy="70" r={r}
            fill="none"
            stroke="url(#sg-health)"
            strokeWidth="11"
            strokeDasharray={circumference}
            strokeDashoffset={offset}
            transform="rotate(-90 70 70)"
            strokeLinecap="round"
            style={{ transition: "stroke-dashoffset 1s ease-out" }}
          />
          <defs>
            <linearGradient id="sg-health" x1="0%" y1="0%" x2="100%" y2="0%">
              <stop offset="0%" stopColor="#4A8BFF" />
              <stop offset="100%" stopColor="#00D991" />
            </linearGradient>
          </defs>
          <text x="70" y="64" textAnchor="middle" fontSize="32" fontWeight="700" fill="#F0F4FF" fontFamily="DM Mono">
            {score}
          </text>
          <text x="70" y="81" textAnchor="middle" fontSize="11" fill="#8899C4" fontFamily="DM Sans">
            de 100
          </text>
        </svg>
        <div style={{ fontSize: 17, fontWeight: 700, color: "var(--t1)" }}>Saúde financeira {scoreLabel.toLowerCase()}</div>
        <div style={{ fontSize: 12, color: scoreColor2, marginTop: 4 }}>Score calculado dinamicamente base nos seus dados</div>
        <div style={{ fontSize: 11, color: "var(--t3)", marginTop: 8, lineHeight: 1.5 }}>
          O score é heurístico e orientativo. Ele ajuda a priorizar ações, mas não substitui planejamento financeiro profissional.
        </div>
      </div>

      {/* Modigliani Life-Cycle Hypothesis Alert */}
      {score < 70 && (
        <div className="glass-panel border-amber-500/30 bg-amber-500/5 p-4 mb-4 flex items-start gap-3">
          <div className="w-8 h-8 rounded-full bg-amber-500/20 flex items-center justify-center text-amber-500 flex-shrink-0 mt-1">
             <Target size={16} />
          </div>
          <div>
            <h4 className="text-[13px] font-black text-amber-500 uppercase tracking-widest mb-1">Alerta Modigliani</h4>
            <p className="text-[11px] text-white/70 leading-relaxed font-medium">
              Sua taxa de consumo atual ({(100 - savingRate).toFixed(0)}%) pode não sustentar seu padrão de vida futuro. A <strong>Hipótese do Ciclo de Vida (Modigliani)</strong> sugere poupar hoje para suavizar o consumo na aposentadoria. Considere reduzir custos fixos.
            </p>
          </div>
        </div>
      )}

      {/* Credit Score Interno */}
      <div className="sec-hd flex justify-between items-center w-full">
         <span className="sec-title">Score Interno de Crédito</span>
         <span className="text-[10px] text-white/30 uppercase tracking-widest">Modelo Neural</span>
      </div>
      <div className="card" style={{ marginBottom: 16, padding: '20px' }}>
         <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-2">
               <ShieldCheck size={20} className={score >= 70 ? "text-emerald-500" : "text-amber-500"} />
               <span className="text-[14px] font-bold text-white">Trust Score</span>
            </div>
            <span className="text-2xl font-black font-mono tracking-tighter" style={{ color: scoreColor2 }}>
               {Math.round(score * 10)}
            </span>
         </div>
         <div className="h-2 w-full bg-white/5 rounded-full overflow-hidden flex mb-2">
            <div className="h-full bg-rose-500" style={{ width: '30%' }} />
            <div className="h-full bg-amber-500" style={{ width: '40%' }} />
            <div className="h-full bg-emerald-500" style={{ width: '30%' }} />
            {/* Indicator Dot */}
            <div 
               className="absolute h-4 w-4 rounded-full bg-white shadow-lg border-2 border-slate-900 border-solid mt-[-4px]" 
               style={{ marginLeft: `${score}%`, transition: 'all 1s ease' }} 
            />
         </div>
         <div className="flex justify-between text-[9px] text-white/40 uppercase font-bold tracking-widest mt-2">
            <span>Alto Risco</span>
            <span>Estável</span>
            <span>Prime</span>
         </div>
         <div className="mt-4 pt-4 border-t border-white/5 text-[11px] text-white/50 leading-relaxed">
            Seu score atual de <strong>{Math.round(score * 10)}/1000</strong> simula a avaliação de crédito do mercado baseada na sua liquidez ({(liquidezMeses).toFixed(1)} meses), índice de alavancagem financeira e consistência de pagamentos.
         </div>
      </div>

      {/* Histórico orientativo */ }
      <div className="sec-hd"><span className="sec-title">Evolução da Saúde</span></div>
      <div className="card" style={{ marginBottom: 16, padding: '14px 16px' }}>
        <div style={{ display: 'flex', alignItems: 'flex-end', gap: 6 }}>
        {historyPoints.map((v, i, arr) => (
          <div key={i} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 4 }}>
            <div style={{ fontSize: 10, color: i === arr.length - 1 ? 'var(--blue)' : 'var(--t3)', fontWeight: i === arr.length - 1 ? 700 : 500 }}>{v}</div>
            <div style={{ width: '100%', height: v * 0.8, background: i === arr.length - 1 ? 'var(--blue)' : 'var(--glass2)', borderRadius: '4px 4px 0 0', opacity: i === arr.length - 1 ? 1 : 0.6 }} />
          </div>
        ))}
        </div>
        <div style={{ fontSize: 10, color: 'var(--t3)', marginTop: 10, lineHeight: 1.5 }}>
          Sequência estimada com base na fotografia atual dos seus dados. Quando houver histórico persistido, esta faixa passará a mostrar evolução real por período.
        </div>
      </div>

      <div className="sec-hd"><span className="sec-title">7 Dimensoẽs (Toque p/ ações)</span></div>
      <div id="health-dimensions" className="card">
        {DIMS.map((d) => (
          <div key={d.nm} style={{ borderBottom: "1px solid var(--border)", paddingBottom: expandedDim === d.nm ? 16 : 0, marginBottom: expandedDim === d.nm ? 16 : 0, transition: 'all 0.2s' }}>
            <button
              type="button"
              className="row w-full text-left"
              style={{ cursor: "pointer", borderBottom: "none", marginBottom: 0, paddingBottom: 12 }}
              onClick={() => setExpandedDim(expandedDim === d.nm ? null : d.nm)}
              aria-expanded={expandedDim === d.nm}
              aria-label={`Alternar detalhes de ${d.nm}`}
            >
              <div className="row-ico flex items-center justify-center" style={{ background: BG_MAP[d.cl] }}>{d.em}</div>
              <div className="row-main">
                <div className="row-title">{d.nm}</div>
                <div className="row-sub">{d.ds}</div>
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 10, flexShrink: 0 }}>
                <div style={{ fontSize: 14, fontWeight: 700, color: COLOR_MAP[d.cl], width: 28, textAlign: "right", fontFamily: "var(--mono)" }}>
                  {d.sc}
                </div>
                <ChevronDown size={14} color="var(--t3)" style={{ transform: expandedDim === d.nm ? "rotate(180deg)" : "rotate(0)", transition: "0.2s" }} />
              </div>
            </button>

            {/* Accordion content with AI Recommendation */}
            {expandedDim === d.nm && (() => {
              const action = getAction(d.nm, d.sc);
              return (
                <div style={{ marginTop: 8, padding: "12px", background: "var(--glass1)", borderRadius: "10px", borderLeft: `3px solid ${COLOR_MAP[d.cl]}` }}>
                  <div style={{ fontSize: 12, fontWeight: 700, color: COLOR_MAP[d.cl], marginBottom: 4 }}>Diagnóstico & Ação</div>
                  <div style={{ fontSize: 13, color: "var(--t1)", lineHeight: 1.4 }}>
                    <strong>{action.title}:</strong> {action.text}
                  </div>
                  {action.act && d.sc < 80 && (
                    <button className="btn-secondary" style={{ marginTop: 12, width: '100%', padding: '8px', fontSize: 12 }} onClick={() => onNavigate?.(action.act as any)}>
                      {action.actText} <ChevronRight size={12} />
                    </button>
                  )}
                </div>
              );
            })()}
          </div>
        ))}
        {/* Fix empty border on last element */}
        <div style={{ height: 16 }} />
      </div>

      {/* Stress check-in */}
      <div className="sec-hd"><span className="sec-title">Check-in Biopsicossocial</span></div>
      <div className="card">
        <div style={{ fontSize: 13, color: "var(--t1)", marginBottom: 16, lineHeight: 1.4 }}>
          A ansiedade financeira reduz a capacidade cognitiva. Como você está se sentindo ao olhar suas contas hoje?
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(62px, 1fr))", gap: 6 }}>
          {[1, 2, 3, 4, 5].map((val, i) => (
            <button
              type="button"
              key={i}
              onClick={() => handleSetStress(i)}
              aria-pressed={selectedStress === i}
              aria-label={`Registrar humor ${STRESS_LABELS[i]}`}
              style={{ flex: 1, textAlign: "center", cursor: "pointer", padding: "16px 4px 10px", borderRadius: 14, border: `1px solid ${selectedStress === i ? "var(--blue)" : "var(--border)"}`, background: selectedStress === i ? "var(--blue3)" : "var(--bg)", transition: "all 0.15s", boxShadow: selectedStress === i ? "0 4px 12px rgba(89,143,249,0.15)" : "none" }}
            >
              <div style={{ fontSize: 18, color: selectedStress === i ? "var(--blue)" : "var(--t3)", fontWeight: 800 }}>M{val}</div>
              <div style={{ fontSize: 9, color: selectedStress === i ? "var(--t1)" : "var(--t3)", marginTop: 6, lineHeight: 1.2, fontWeight: selectedStress === i ? 700 : 500 }}>
                {STRESS_LABELS[i]}
              </div>
            </button>
          ))}
        </div>
        {selectedStress !== null && (
          <div style={{ marginTop: 12, fontSize: 12, color: "var(--t2)", textAlign: "center" }}>
            ✓ Check-in registrado: <strong>{STRESS_LABELS[selectedStress]}</strong>. Impacto visualizado no seu Score 360°.
          </div>
        )}
      </div>
    </div>
  );
};

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import type { Investment } from "@/types";
import { AnimatePresence, motion } from "framer-motion";
import {
  ArrowLeft,
  ArrowRight,
  Bitcoin,
  Building2,
  Check,
  Coins,
  DollarSign,
  TrendingUp,
} from "lucide-react";
import { useState } from "react";

interface Props {
  onComplete: (asset: Omit<Investment, "id">) => void;
  onClose: () => void;
}

const STEPS = [
  { id: "type", title: "Tipo de Ativo" },
  { id: "details", title: "Identificação" },
  { id: "financials", title: "Valores" },
  { id: "allocation", title: "Alocação" },
];

const ASSET_TYPES = [
  {
    id: "stock",
    label: "Ações / Stocks",
    icon: TrendingUp,
    color: "bg-indigo-500",
  },
  { id: "fii", label: "FIIs", icon: Building2, color: "bg-emerald-500" },
  { id: "crypto", label: "Cripto", icon: Bitcoin, color: "bg-orange-500" },
  {
    id: "fixed_income",
    label: "Renda Fixa",
    icon: Coins,
    color: "bg-blue-500",
  },
];

export const AddAssetWizard = ({ onComplete, onClose }: Props) => {
  const [step, setStep] = useState(0);
  const [data, setData] = useState<Partial<Investment>>({
    currency: "BRL",
    type: "stock",
  });

  const handleNext = () => {
    if (step < STEPS.length - 1) setStep(step + 1);
    else {
      // Finalize
      const allocationNum = Number(data.targetAllocation) || 0;
      if (allocationNum > 100) {
        alert("A alocação não pode ser maior que 100%");
        return;
      }

      onComplete({
        name: data.name!,
        ticker: data.ticker!.toUpperCase(),
        type: data.type!,
        amount: Number(data.amount),
        averagePrice: Number(data.averagePrice),
        currentPrice: Number(data.averagePrice), // Start with same price
        currency: data.currency!,
        sector: data.sector || "Geral",
        targetAllocation: allocationNum,
      } as any);
    }
  };

  const isValidStep = () => {
    switch (step) {
      case 0:
        return !!data.type;
      case 1:
        return !!data.ticker && !!data.name;
      case 2:
        return !!data.amount && !!data.averagePrice;
      case 3:
        return true; // Optional
      default:
        return false;
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        exit={{ opacity: 0, scale: 0.95 }}
        className="w-full max-w-lg bg-[#0a0a0f] border border-white/10 rounded-3xl overflow-hidden shadow-2xl"
      >
        {/* Header */}
        <div className="p-6 border-b border-white/5 bg-white/[0.02]">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-xl font-black text-white">Novo Investimento</h2>
            <div className="text-xs font-bold text-slate-500 uppercase tracking-widest">
              Passo {step + 1} de {STEPS.length}
            </div>
          </div>
          {/* Progress Bar */}
          <div className="h-1 bg-white/5 rounded-full overflow-hidden">
            <motion.div
              className="h-full bg-indigo-500"
              initial={{ width: 0 }}
              animate={{ width: `${((step + 1) / STEPS.length) * 100}%` }}
            />
          </div>
        </div>

        {/* Content */}
        <div className="p-6 h-[400px] overflow-y-auto custom-scrollbar">
          <AnimatePresence mode="wait">
            {step === 0 && (
              <motion.div
                key="step0"
                initial={{ x: 20, opacity: 0 }}
                animate={{ x: 0, opacity: 1 }}
                exit={{ x: -20, opacity: 0 }}
                className="grid grid-cols-2 gap-4"
              >
                {ASSET_TYPES.map((type) => (
                  <button
                    key={type.id}
                    onClick={() => {
                      setData({ ...data, type: type.id as any });
                      handleNext();
                    }}
                    className={`
                      flex flex-col items-center justify-center p-6 rounded-2xl border transition-all gap-4 group
                      ${
                        data.type === type.id
                          ? "bg-white/10 border-indigo-500 ring-1 ring-indigo-500"
                          : "bg-white/5 border-white/5 hover:bg-white/10 hover:border-white/10"
                      }
                    `}
                  >
                    <div
                      className={`w-12 h-12 rounded-xl ${type.color} flex items-center justify-center text-white shadow-lg group-hover:scale-110 transition-transform`}
                    >
                      <type.icon size={24} />
                    </div>
                    <span className="font-bold text-white text-sm">
                      {type.label}
                    </span>
                  </button>
                ))}
              </motion.div>
            )}

            {step === 1 && (
              <motion.div
                key="step1"
                initial={{ x: 20, opacity: 0 }}
                animate={{ x: 0, opacity: 1 }}
                exit={{ x: -20, opacity: 0 }}
                className="space-y-6"
              >
                <div className="space-y-2">
                  <Label className="uppercase text-[10px] font-black tracking-widest text-slate-400">
                    Ticker / Código
                  </Label>
                  <Input
                    autoFocus
                    value={data.ticker}
                    onChange={(e) =>
                      setData({ ...data, ticker: e.target.value.toUpperCase() })
                    }
                    placeholder="Ex: PETR4, BTC, CDB..."
                    className="h-14 bg-white/5 border-white/10 rounded-xl text-lg font-bold tracking-wider placeholder:font-normal"
                  />
                  <p className="text-[10px] text-slate-500">
                    O código usado na bolsa ou banco.
                  </p>
                </div>
                <div className="space-y-2">
                  <Label className="uppercase text-[10px] font-black tracking-widest text-slate-400">
                    Nome do Ativo
                  </Label>
                  <Input
                    value={data.name}
                    onChange={(e) => setData({ ...data, name: e.target.value })}
                    placeholder="Ex: Petrobras PN"
                    className="h-14 bg-white/5 border-white/10 rounded-xl"
                  />
                </div>
              </motion.div>
            )}

            {step === 2 && (
              <motion.div
                key="step2"
                initial={{ x: 20, opacity: 0 }}
                animate={{ x: 0, opacity: 1 }}
                exit={{ x: -20, opacity: 0 }}
                className="space-y-6"
              >
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label className="uppercase text-[10px] font-black tracking-widest text-slate-400">
                      Quantidade
                    </Label>
                    <Input
                      type="number"
                      step="any"
                      autoFocus
                      value={data.amount}
                      onChange={(e) =>
                        setData({ ...data, amount: e.target.value as any })
                      }
                      className="h-14 bg-white/5 border-white/10 rounded-xl text-lg font-bold"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label className="uppercase text-[10px] font-black tracking-widest text-slate-400">
                      Moeda
                    </Label>
                    <Select
                      value={data.currency}
                      onValueChange={(v) =>
                        setData({ ...data, currency: v as any })
                      }
                    >
                      <SelectTrigger className="h-14 bg-white/5 border-white/10 rounded-xl">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent className="bg-slate-900 border-white/10 text-white">
                        <SelectItem value="BRL">BRL (R$)</SelectItem>
                        <SelectItem value="USD">USD ($)</SelectItem>
                        <SelectItem value="EUR">EUR (€)</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>
                <div className="space-y-2">
                  <Label className="uppercase text-[10px] font-black tracking-widest text-slate-400">
                    Preço Médio (Custo)
                  </Label>
                  <div className="relative">
                    <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500">
                      <DollarSign size={16} />
                    </div>
                    <Input
                      type="number"
                      step="0.01"
                      value={data.averagePrice}
                      onChange={(e) =>
                        setData({ ...data, averagePrice: e.target.value as any })
                      }
                      className="h-14 bg-white/5 border-white/10 rounded-xl pl-10 text-lg font-bold"
                    />
                  </div>
                </div>
              </motion.div>
            )}

            {step === 3 && (
              <motion.div
                key="step3"
                initial={{ x: 20, opacity: 0 }}
                animate={{ x: 0, opacity: 1 }}
                exit={{ x: -20, opacity: 0 }}
                className="space-y-6 text-center"
              >
                <div className="w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mx-auto mb-4 border border-emerald-500/20">
                  <Check className="text-emerald-500" size={32} />
                </div>
                <h3 className="text-2xl font-black text-white">Quase lá!</h3>
                <p className="text-slate-400">
                  Defina uma meta de alocação para este ativo (opcional).
                </p>

                <div className="max-w-[200px] mx-auto space-y-2">
                  <Label className="uppercase text-[10px] font-black tracking-widest text-slate-400">
                    Meta Ideal (%)
                  </Label>
                  <Input
                    type="number"
                    placeholder="0%"
                    value={data.targetAllocation}
                    onChange={(e) =>
                      setData({ ...data, targetAllocation: e.target.value as any })
                    }
                    className="h-14 bg-white/5 border-white/10 rounded-xl text-center text-xl font-black"
                  />
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        {/* Footer */}
        <div className="p-6 border-t border-white/5 bg-white/[0.02] flex justify-between">
          <Button
            variant="ghost"
            onClick={step === 0 ? onClose : () => setStep(step - 1)}
            className="text-slate-400 hover:text-white"
          >
            {step === 0 ? "Cancelar" : <ArrowLeft size={18} />}
          </Button>

          {step > 0 && (
            <Button
              onClick={handleNext}
              disabled={!isValidStep()}
              className="bg-white text-black hover:bg-white/90 font-bold px-8 rounded-xl"
            >
              {step === STEPS.length - 1 ? "Concluir" : "Próximo"}
              {step < STEPS.length - 1 && <ArrowRight size={18} className="ml-2" />}
            </Button>
          )}
        </div>
      </motion.div>
    </div>
  );
};

import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

import { Skeleton } from "@/components/ui/skeleton";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { QuickSetupWizard } from "@/components/ui/QuickSetupWizard";
import { useCurrency } from "@/context/CurrencyContext";
import { useInvestments } from "@/hooks/useInvestments";
import { formatCurrency } from "@/lib/formatters";
import { loadProfile } from "@/lib/storage";
import type { Investment, Currency } from "@/types";
import { AnimatePresence, motion } from "framer-motion";
import {
  Briefcase,
  LineChart,
  Plus,
  RefreshCcw,
  Sparkles,
  AlertCircle,
} from "lucide-react";
import { useState } from "react";
import { AssetAllocationChart } from "./AssetAllocationChart";
import { DividendForecast } from "./DividendForecast";
import { DividendList } from "./DividendList";
import { PortfolioAnalysis } from "./PortfolioAnalysis";
import { PortfolioTable } from "./PortfolioTable";
import { RebalancingPanel } from "./RebalancingPanel";
import { AddAssetWizard } from "./AddAssetWizard";
import { PrivacyValue } from "@/components/ui/PrivacyValue";
import { useRole } from "@/context/AuthContext";
import { showError } from "@/lib/toast";


import { MarketDataWidget } from "./MarketDataWidget";
import { CDIBenchmark } from "./CDIBenchmark";

const container = {
  hidden: { opacity: 0 },
  show: {
    opacity: 1,
    transition: {
      staggerChildren: 0.1,
    },
  },
};

const item = {
  hidden: { opacity: 0, y: 20 },
  show: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.5, ease: [0.22, 1, 0.36, 1] },
  },
};

export const InvestmentsDashboard = () => {
  const {
    assets,
    loading,
    error,
    addAsset,
    deleteAsset,
    updateAsset,
    addSale,
    getTaxIndicators,
    syncPrices,
  } = useInvestments();
  const { convert } = useCurrency();
  const { isViewer } = useRole();
  const [isOpen, setIsOpen] = useState(false);
  const [sellAmount, setSellAmount] = useState("");
  const [sellPrice, setSellPrice] = useState("");
  const showRealGain = false; // default to false if not toggleable for now
  const [showWizard, setShowWizard] = useState(false);
  const [profile] = useState(loadProfile()); // Load profile safely
  const IPCA_ANUAL = 0.045; // 4.5% sample IPCA for Brazil context

  // ... (keeping existing logic functions)

  const handleSync = () => {
    if (isViewer) return showError("Somente leitura");
    let token = localStorage.getItem("brapi_token");
    if (!token) {
      token = window.prompt(
        "Para cotações em tempo real, insira sua API Key da Brapi.dev:"
      );
      if (token) {
        localStorage.setItem("brapi_token", token);
      }
    }
    syncPrices(token || undefined);
  };


  const totalInvested = assets.reduce(
    (acc, curr) =>
      acc +
      convert(curr.amount * curr.averagePrice, (curr.currency || "BRL") as Currency, "BRL"),
    0
  );
  const totalValue = assets.reduce(
    (acc, curr) =>
      acc +
      convert(curr.amount * curr.currentPrice, curr.currency || "BRL", "BRL"),
    0
  );
  const profit = totalValue - totalInvested;
  const profitPercentage =
    totalInvested > 0 ? (profit / totalInvested) * 100 : 0;

  // State for Edit/Sell Dialogs
  const [sellDialogOpen, setSellDialogOpen] = useState(false);
  const [editDialogOpen, setEditDialogOpen] = useState(false);
  const [selectedAsset, setSelectedAsset] = useState<Investment | null>(null);
  const [editingAsset, setEditingAsset] = useState<Investment | null>(null);
  
  const [editName, setEditName] = useState("");
  const [editTicker, setEditTicker] = useState("");
  const [editAmount, setEditAmount] = useState("");
  const [editPrice, setEditPrice] = useState("");

  const handleOpenSell = (asset: Investment) => {
    setSelectedAsset(asset);
    setSellPrice(asset.currentPrice.toString());
    setSellDialogOpen(true);
  };
 
  const overrideAddAsset = (assetData: Omit<Investment, "id">) => {
      addAsset(assetData);
      setIsOpen(false); // Close wizard
  };

  const handleApplyPreset = (data: any) => {
    if (data && data.assets) {
      data.assets.forEach((asset: any) => {
        addAsset({
          name: asset.ticker || "",
          ticker: asset.ticker || "",
          type: asset.type || "stock",
          amount: asset.amount || 0,
          averagePrice: asset.averagePrice || 0,
          currency: asset.currency || "BRL",
          currentPrice: asset.averagePrice || 0,
          sector: "Geral",
        } as Omit<Investment, "id">);
      });
    }
    setShowWizard(false);
  };

  return (
    <motion.div
      initial="hidden"
      animate="show"
      variants={container}
      className="space-y-12 pb-12"
    >
      <AnimatePresence>
        {assets.length === 0 && !showWizard && (
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            className="premium-card p-6 bg-amber-500/10 border-amber-500/20 flex flex-col md:flex-row items-center justify-between gap-6"
          >
            <div className="flex items-center gap-4 text-center md:text-left">
              <div className="w-12 h-12 rounded-2xl bg-amber-500 flex items-center justify-center text-white shadow-lg">
                <Sparkles size={24} />
              </div>
              <div>
                <h4 className="font-black text-white uppercase tracking-tight">Comece sua Carteira</h4>
                <p className="text-xs text-slate-400 font-medium">Use um modelo de carteira conservadora ou agressiva para começar rápido.</p>
              </div>
            </div>
            <Button 
              onClick={() => setShowWizard(true)}
              disabled={isViewer}
              className="bg-white text-black font-black uppercase tracking-widest text-[10px] h-12 px-8 rounded-xl disabled:opacity-50"
            >
              Abrir Wizard
            </Button>
          </motion.div>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {showWizard && (
          <QuickSetupWizard 
            type="investments" 
            onComplete={handleApplyPreset} 
            onClose={() => setShowWizard(false)} 
          />
        )}
      </AnimatePresence>
      {/* Header / Summary - Obsidian Style */}
      <motion.div variants={item} className="space-y-8">
        <div className="card-obsidian relative overflow-hidden p-8 md:p-10 group">
         <div className="absolute top-0 right-0 w-[400px] h-[400px] bg-emerald-600/10 blur-[100px] rounded-full opacity-50 group-hover:opacity-70 transition-opacity" />
         
         <div className="relative z-10 flex flex-col md:flex-row items-start md:items-center justify-between gap-6">
            <div className="space-y-2">
               <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20">
                  <Sparkles size={12} className="text-emerald-400" />
                  <span className="text-[10px] font-bold uppercase tracking-widest text-emerald-300">Wealth Management</span>
               </div>
               <h1 className="text-4xl md:text-5xl font-heading font-bold text-white tracking-tight">
                  Meus <span className="text-emerald-400">Investimentos</span>
               </h1>
            </div>

            <div className="flex items-center gap-3">
               <Button
                  onClick={handleSync}
                  variant="outline"
                  className="rounded-full border-zinc-700 hover:bg-zinc-800 text-zinc-300 hover:text-white"
               >
                  <RefreshCcw size={16} className={`mr-2 ${loading ? 'animate-spin' : ''}`} />
                  Sincronizar
               </Button>
               <Button
                  onClick={() => isViewer ? showError("Somente leitura") : setIsOpen(true)}
                  disabled={isViewer}
                  className="rounded-full bg-emerald-600 hover:bg-emerald-500 text-white font-bold shadow-lg shadow-emerald-500/20 disabled:opacity-50"
               >
                  <Plus size={18} className="mr-2" />
                  Novo Aporte
               </Button>
            </div>
         </div>
      </div>{/* Main Add Asset Wizard Overlay */}
            <AnimatePresence>
                {isOpen && (
                    <AddAssetWizard 
                        onClose={() => setIsOpen(false)}
                        onComplete={overrideAddAsset}
                    />
                )}
            </AnimatePresence>

            {/* Sell Dialog (Lifted State) */}
            <Dialog open={sellDialogOpen} onOpenChange={setSellDialogOpen}>
              <DialogContent className="glass-premium border-white/10 text-white">
                <DialogHeader>
                  <DialogTitle className="text-xl font-black">
                    Vender {selectedAsset?.ticker}
                  </DialogTitle>
                </DialogHeader>
                <div className="space-y-4 pt-4">
                  <div className="space-y-2">
                     <Label className="text-slate-400 uppercase text-[10px] font-black tracking-widest">
                       Quantidade (Disponível: {selectedAsset?.amount})
                     </Label>
                     <Input
                       type="number"
                       className="bg-white/5 h-12 rounded-xl"
                       value={sellAmount}
                       onChange={(e) => setSellAmount(e.target.value)}
                       max={selectedAsset?.amount || 0}
                     />
                  </div>
                  <div className="space-y-2">
                     <Label className="text-slate-400 uppercase text-[10px] font-black tracking-widest">
                       Preço de Venda
                     </Label>
                     <Input
                       type="number"
                       className="bg-white/5 h-12 rounded-xl"
                       value={sellPrice}
                       onChange={(e) => setSellPrice(e.target.value)}
                     />
                  </div>
                  <Button
                    className="w-full h-14 rounded-2xl bg-amber-600 hover:bg-amber-500 font-black disabled:opacity-50"
                    disabled={isViewer}
                    onClick={() => {
                       if (isViewer) return showError("Somente leitura");
                       if (selectedAsset && sellAmount) {
                          addSale(selectedAsset.id, {
                             amount: parseFloat(sellAmount),
                             price: parseFloat(sellPrice),
                             date: new Date().toISOString()
                          });
                          setSellDialogOpen(false);
                          setSellAmount("");
                       }
                    }}
                  >
                     Confirmar Venda
                  </Button>
                </div>
              </DialogContent>
            </Dialog>

            {/* Edit Dialog */}
            <Dialog open={editDialogOpen} onOpenChange={setEditDialogOpen}>
              <DialogContent className="glass-premium border-white/10 text-white">
                <DialogHeader>
                  <DialogTitle className="text-xl font-black">
                    Editar Ativo
                  </DialogTitle>
                </DialogHeader>
                <div className="space-y-4 pt-4">
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label className="text-slate-400 uppercase text-[10px] font-black tracking-widest">Ticker</Label>
                      <Input value={editTicker} onChange={e => setEditTicker(e.target.value)} className="bg-white/5" />
                    </div>
                    <div className="space-y-2">
                       <Label className="text-slate-400 uppercase text-[10px] font-black tracking-widest">Nome</Label>
                       <Input value={editName} onChange={e => setEditName(e.target.value)} className="bg-white/5" />
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                       <Label className="text-slate-400 uppercase text-[10px] font-black tracking-widest">Quantidade</Label>
                       <Input type="number" value={editAmount} onChange={e => setEditAmount(e.target.value)} className="bg-white/5" />
                    </div>
                    <div className="space-y-2">
                       <Label className="text-slate-400 uppercase text-[10px] font-black tracking-widest">P. Médio</Label>
                       <Input type="number" value={editPrice} onChange={e => setEditPrice(e.target.value)} className="bg-white/5" />
                    </div>
                  </div>
                  <Button
                    className="w-full h-14 rounded-2xl bg-indigo-600 hover:bg-indigo-500 font-black"
                    onClick={() => {
                        if (editingAsset && editAmount && editPrice) {
                          updateAsset(editingAsset.id, {
                            name: editName,
                            ticker: editTicker,
                            amount: parseFloat(editAmount),
                            averagePrice: parseFloat(editPrice)
                          });
                          setEditDialogOpen(false);
                        }
                    }}
                  >
                    Salvar Alterações
                  </Button>
                </div>
              </DialogContent>
            </Dialog>
      </motion.div>

        <motion.div
          variants={container}
          className="grid grid-cols-1 md:grid-cols-3 gap-6 mt-12 pt-12 border-t border-white/5"
        >
          {[
            { label: "Patrimônio", value: totalValue, type: "currency" },
            {
              label: showRealGain ? "Lucro Real (Líquido)" : "Lucro Bruto",
              value: showRealGain
                ? profit - totalInvested * IPCA_ANUAL
                : profit,
              type: "profit",
            },
            {
              label: showRealGain ? "Rendimento Real" : "Performance",
              value: showRealGain
                ? profitPercentage - IPCA_ANUAL * 100
                : profitPercentage,
              type: "percent",
            },
          ].map((stat) => (
            <motion.div
              key={stat.label}
              variants={item}
              className="p-6 bg-white/[0.03] rounded-3xl border border-white/5 transition-all hover:bg-white/[0.06] hover:border-white/10 group"
            >
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mb-2 group-hover:text-slate-400 transition-colors">
                {stat.label}
              </p>
              <div
                className={`text-3xl font-black tracking-tight ${
                  stat.type === "profit" || stat.type === "percent"
                    ? stat.value >= 0
                      ? "text-emerald-400"
                      : "text-rose-400"
                    : "text-white"
                }`}
              >
                {stat.type === "currency" ? (
                  <PrivacyValue value={stat.value as number} />
                ) : (
                  <>
                    {(stat.value as number) >= 0 ? "+" : ""}
                    {stat.type === "percent" ? (
                      `${(stat.value as number).toFixed(2)}%`
                    ) : (
                      <PrivacyValue value={stat.value as number} />
                    )}
                  </>
                )}
              </div>
            </motion.div>
          ))}
        </motion.div>

      <motion.div variants={item}>
        <Tabs defaultValue="portfolio" className="w-full">
          <TabsList className="flex bg-white/[0.03] p-1.5 rounded-2xl border border-white/10 w-fit mb-10">
            <TabsTrigger
              value="portfolio"
              className="px-8 py-3 rounded-xl text-xs font-bold uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black data-[state=active]:shadow-lg active:scale-95"
            >
              Carteira
            </TabsTrigger>
            <TabsTrigger
              value="dividends"
              className="px-8 py-3 rounded-xl text-xs font-bold uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black data-[state=active]:shadow-lg active:scale-95"
            >
              Proventos
            </TabsTrigger>
            <TabsTrigger
              value="rebalance"
              className="px-8 py-3 rounded-xl text-xs font-bold uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black data-[state=active]:shadow-lg active:scale-95"
            >
              Rebalancear
            </TabsTrigger>
            <TabsTrigger
              value="forecast"
              className="px-8 py-3 rounded-xl text-xs font-bold uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black data-[state=active]:shadow-lg active:scale-95"
            >
              Projeção
            </TabsTrigger>
            <TabsTrigger
              value="analysis"
              className="px-8 py-3 rounded-xl text-xs font-bold uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black data-[state=active]:shadow-lg active:scale-95"
            >
              Análise
            </TabsTrigger>
            <TabsTrigger
              value="fiscal"
              className="px-8 py-3 rounded-xl text-xs font-bold uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black data-[state=active]:shadow-lg active:scale-95"
            >
              Fiscal
            </TabsTrigger>
          </TabsList>

          <TabsContent value="portfolio" className="mt-0 outline-none">
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
              {/* Metrics & Allocation Column */}
              <div className="flex flex-col gap-6">
                <AssetAllocationChart 
                  assets={assets} 
                  loading={loading} 
                  convert={convert} 
                />
                
