import { useState, useEffect, useMemo, useRef } from "react";
import { fetchStockQuote } from "@/lib/market-data";

interface StockQuote {
  symbol: string;
  price: number;
  name: string;
  logo?: string;
}

interface RealTimeQuotesProps {
  tickers?: string[];
}

// Constante fora do componente para evitar array novo a cada render
const DEFAULT_TICKERS = ["BOVA11", "IVVB11", "HGLG11"];

export const RealTimeQuotes = ({ tickers = DEFAULT_TICKERS }: RealTimeQuotesProps) => {
  const [quotes, setQuotes] = useState<StockQuote[]>([]);
  const [loading, setLoading] = useState(true);
  const [lastUpdate, setLastUpdate] = useState<string>("");
  // Guard anti-StrictMode: garante que o effect não execute duas vezes em dev
  const didFetch = useRef(false);

  const fmt = (n: number) => "R$\u00a0" + n.toFixed(2).replace(".", ",");

  // Memoizar chave para que arrays inline não causem re-fetch
  const tickerKey = tickers.join(",");
  const stableTickers = useMemo(() => tickers, [tickerKey]);

  useEffect(() => {
    if (didFetch.current) return;
    didFetch.current = true;

    const loadQuotes = async () => {
      setLoading(true);
      try {
        const results: StockQuote[] = [];
        for (let i = 0; i < stableTickers.length; i += 2) {
          const batch = stableTickers.slice(i, i + 2);
          const batchResults = await Promise.all(
            batch.map(async (ticker) => {
              const quote = await fetchStockQuote(ticker);
              return quote || { symbol: ticker, price: 0, name: ticker };
            })
          );
          results.push(...(batchResults.filter(Boolean) as StockQuote[]));

          if (i + 2 < stableTickers.length) {
            await new Promise((resolve) => setTimeout(resolve, 600));
          }
        }

        setQuotes(results);
        setLastUpdate(
          new Date().toLocaleTimeString("pt-BR", { hour: "2-digit", minute: "2-digit" })
        );
      } catch (error) {
        console.error("Error loading quotes:", error);
      } finally {
        setLoading(false);
      }
    };

    loadQuotes();
    // Atualizar a cada 15 min; resetar flag para permitir próxima busca
    const interval = setInterval(() => {
      didFetch.current = false;
      loadQuotes();
    }, 15 * 60 * 1000);
    return () => clearInterval(interval);
  }, [stableTickers]);

  if (loading && quotes.length === 0) {
    return (
      <div className="card" style={{ padding: "16px" }}>
        <div style={{ display: "flex", alignItems: "center", gap: "8px", marginBottom: "12px" }}>
          <div style={{ width: "8px", height: "8px", borderRadius: "50%", background: "var(--amber)", animation: "pulse 2s infinite" }} />
          <span style={{ fontSize: "11px", color: "var(--text3)", textTransform: "uppercase", letterSpacing: "0.1em", fontWeight: 600 }}>
            Carregando cotações...
          </span>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(2, 1fr)", gap: "8px" }}>
          {[1, 2, 3].map((i) => (
            <div key={i} style={{ height: "60px", background: "var(--surface)", borderRadius: "10px", animation: "pulse 1.5s infinite" }} />
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="card" style={{ padding: "16px" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "12px" }}>
        <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
          <div style={{ width: "8px", height: "8px", borderRadius: "50%", background: "var(--green)", animation: "pulse 2s infinite" }} />
          <span style={{ fontSize: "11px", color: "var(--text3)", textTransform: "uppercase", letterSpacing: "0.1em", fontWeight: 600 }}>
            Cotações ao vivo
          </span>
        </div>
        <span style={{ fontSize: "10px", color: "var(--text3)" }}>{lastUpdate}</span>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(2, 1fr)", gap: "8px" }}>
        {quotes.map((quote) => {
          const price = quote.price || 0;
          return (
            <div
              key={quote.symbol}
              style={{
                background: "var(--surface)",
                borderRadius: "10px",
                padding: "12px",
                cursor: "pointer",
                transition: "all 0.2s",
                border: "1px solid var(--border)",
              }}
            >
              <div style={{ display: "flex", alignItems: "center", gap: "8px", marginBottom: "8px" }}>
                {quote.logo ? (
                  <img src={quote.logo} alt={quote.symbol} style={{ width: "20px", height: "20px", borderRadius: "4px" }} />
                ) : (
                  <div style={{ width: "20px", height: "20px", borderRadius: "4px", background: "var(--blue-dim)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "10px", fontWeight: 700, color: "var(--accent)" }}>
                    {quote.symbol.substring(0, 2)}
                  </div>
                )}
                <span style={{ fontSize: "11px", fontWeight: 600, color: "var(--text1)" }}>{quote.symbol}</span>
              </div>
              <div style={{ fontSize: "14px", fontWeight: 700, color: "var(--text1)", fontFamily: "var(--mono)" }}>
                {price > 0 ? fmt(price) : "—"}
              </div>
              <div style={{ fontSize: "10px", color: "var(--text3)", marginTop: "2px" }}>
                {quote.name}
              </div>
            </div>
          );
        })}
      </div>

      <div style={{ marginTop: "12px", padding: "8px", background: "var(--surface)", borderRadius: "8px", fontSize: "10px", color: "var(--text3)", textAlign: "center" }}>
        Dados: brapi.dev · Atualização a cada 15 min
      </div>
    </div>
  );
};

import { useState, useEffect } from "react";

interface TesouroTitle {
  nome: string;
  vencimento: string;
  taxa: number;
  preco: number;
  tipo: "IPCA+" | "Prefixado" | "Selic";
}

export const TesouroDiretoRates = () => {
  const [titles, setTitles] = useState<TesouroTitle[]>([]);
  const [loading, setLoading] = useState(true);

  const fallbackTitles: TesouroTitle[] = [
    { nome: "Tesouro IPCA+ 2035", vencimento: "15/05/2035", taxa: 6.12, preco: 3215.45, tipo: "IPCA+" },
    { nome: "Tesouro Prefixado 2029", vencimento: "01/01/2029", taxa: 11.85, preco: 892.30, tipo: "Prefixado" },
    { nome: "Tesouro Selic 2029", vencimento: "01/03/2029", taxa: 0.15, preco: 13145.67, tipo: "Selic" },
    { nome: "Tesouro IPCA+ 2045", vencimento: "15/05/2045", taxa: 6.25, preco: 2890.2, tipo: "IPCA+" },
    { nome: "Tesouro Prefixado 2033", vencimento: "01/01/2033", taxa: 12.1, preco: 745.8, tipo: "Prefixado" },
  ];

  const fmt = (n: number) => "R$\u00a0" + n.toFixed(2).replace(".", ",");
  const fmtPct = (n: number) => n.toFixed(2) + "% a.a.";

  useEffect(() => {
    const loadTesouroData = async () => {
      setLoading(true);

      // Não existe rota backend para este recurso neste ambiente local.
      // Em dev, usamos fallback silencioso para evitar 404 no console.
      if (import.meta.env.DEV) {
        setTitles(fallbackTitles);
        setLoading(false);
        return;
      }

      try {
        // Try to fetch from API via proxy or backend
        const response = await fetch("/api/tesouro-direto", {
          signal: AbortSignal.timeout(5000),
        });

        if (response.ok) {
          const data = await response.json();
          if (data.response && data.response.TrsrBdTradgList) {
            const formatted = data.response.TrsrBdTradgList.map((item: any) => ({
              nome: item.TrsrBd?.nm || "Título",
              vencimento: item.TrsrBd?.mtrtyDt || "N/A",
              taxa: parseFloat(item.TrsrBd?.anulInvstmtRate) || 0,
              preco: parseFloat(item.TrsrBd?.untrInvstmtVal) || 0,
              tipo: item.TrsrBd?.bd?.cd === "NTN-B" ? "IPCA+" : 
                    item.TrsrBd?.bd?.cd === "LTN" ? "Prefixado" : "Selic",
            }));
            setTitles(formatted.slice(0, 6));
            return;
          }
        }
        throw new Error("API not available");
      } catch (error) {
        // Use fallback data on any error (CORS, timeout, etc.)
        setTitles(fallbackTitles);
      } finally {
        setLoading(false);
      }
    };

    loadTesouroData();
  }, []);

  if (loading) {
    return (
      <div className="card" style={{ padding: "16px" }}>
        <div style={{ fontSize: "11px", color: "var(--text3)", textTransform: "uppercase", letterSpacing: "0.1em", fontWeight: 600, marginBottom: "12px" }}>
          Tesouro Direto
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
          {[1, 2, 3].map((i) => (
            <div key={i} style={{ height: "60px", background: "var(--surface)", borderRadius: "10px", animation: "pulse 1.5s infinite" }} />
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="card" style={{ padding: "16px" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "12px" }}>
        <span style={{ fontSize: "11px", color: "var(--text3)", textTransform: "uppercase", letterSpacing: "0.1em", fontWeight: 600 }}>
          Tesouro Direto
        </span>
        <span style={{ fontSize: "10px", color: "var(--text3)" }}>taxas de hoje</span>
      </div>

      <div style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
        {titles.map((title, idx) => (
          <div
            key={idx}
            style={{
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
              padding: "12px",
              background: "var(--surface)",
              borderRadius: "10px",
              border: "1px solid var(--border)",
              cursor: "pointer",
              transition: "all 0.2s",
            }}
          >
            <div>
              <div style={{ fontSize: "13px", fontWeight: 600, color: "var(--text1)", marginBottom: "2px" }}>
                {title.nome}
              </div>
              <div style={{ display: "flex", gap: "8px", alignItems: "center" }}>
                <span className={`badge ${title.tipo === "IPCA+" ? "badge-green" : title.tipo === "Prefixado" ? "badge-blue" : "badge-amber"}`}>
                  {title.tipo}
                </span>
                <span style={{ fontSize: "10px", color: "var(--text3)" }}>Venc: {title.vencimento}</span>
              </div>
            </div>
            <div style={{ textAlign: "right" }}>
              <div style={{ fontSize: "14px", fontWeight: 700, color: "var(--green)", fontFamily: "var(--mono)" }}>
                {fmtPct(title.taxa)}
              </div>
              <div style={{ fontSize: "11px", color: "var(--text3)", fontFamily: "var(--mono)" }}>
                {fmt(title.preco)}
              </div>
            </div>
          </div>
        ))}
      </div>

      <div style={{ marginTop: "12px", padding: "8px", background: "var(--green-dim)", borderRadius: "8px", fontSize: "10px", color: "var(--green)", textAlign: "center" }}>
        ✓ Dados simulados · Atualizados diariamente
      </div>
    </div>
  );
};

