import { Button } from "@/components/ui/button";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useTransactions } from "@/hooks/useTransactions";
import { STORAGE_EVENT, STORAGE_KEYS, loadGoals, saveBudgets, saveGoals } from "@/lib/storage";
import { QuickSetupWizard } from "@/components/ui/QuickSetupWizard";
import type { SavingsGoal, Transaction, TransactionFormData } from "@/types";
import {
  AlertCircle,
  BarChart3,
  Bell,
  Brain,
  Camera,
  Download,
  FileSpreadsheet,
  LayoutDashboard,
  PlusCircle,
  Sparkles,
  Target,
  TrendingUp,
  Upload,
  Link2,
} from "lucide-react";
import { HelpButton } from "@/components/ui/HelpButton";
import { BankConnectionModal } from "@/components/banking/BankConnectionModal";
import { AnimatePresence, motion } from "framer-motion";
import { useEffect, useRef, useState } from "react";
import { DashboardTab } from "@/features/personal/components/DashboardTab";
import { BudgetsTab } from "@/features/personal/components/BudgetsTab";
import { GoalsTab } from "@/features/personal/components/GoalsTab";
import { RemindersTab } from "@/features/personal/components/RemindersTab";
import { AnalyticsTab as AnalyticsTabComponent } from "@/features/personal/components/AnalyticsTab";
import { InsightsTab } from "@/features/personal/components/InsightsTab";
import { DebtsTab } from "@/features/personal/components/DebtsTab";

import { TransactionForm } from "@/components/contador/TransactionForm";
import { ReceiptScanner } from "@/components/receipts/ReceiptScanner";
import { exportFullMonthlyReport } from "@/lib/pdf-export";
import { exportTransactionsToCSV, importTransactions } from "@/lib/storage";
import { showError, showSuccess } from "@/lib/toast";
import { useRole } from "@/context/AuthContext";

export const PersonalFinance = () => {

  const [activeTab, setActiveTab] = useState("dashboard");
  const [showForm, setShowForm] = useState(false);
  const [showReceiptScanner, setShowReceiptScanner] = useState(false);
  const [editingTransaction, setEditingTransaction] =
    useState<Transaction | null>(null);
  const [showWizard, setShowWizard] = useState(false);
  const [showBankModal, setShowBankModal] = useState(false);
  const { isViewer } = useRole();

  const {
    transactions,
    filteredTransactions,
    filter,
    setFilter,
    dateFilter,
    setDateFilter,
    searchTerm,
    setSearchTerm,
    addTransaction,
    updateTransaction,
    deleteTransaction,
    totals,
    categoryData,
    getPieChartData,
    monthlyTrend,
  } = useTransactions("personal");

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [goals, setGoals] = useState<SavingsGoal[]>(() => loadGoals());

  useEffect(() => {
    const handleStorageChange = (e: Event) => {
      const detail = (e as CustomEvent).detail;
      if (detail?.key === STORAGE_KEYS.GOALS) {
        setGoals(detail.data);
      }
    };
    window.addEventListener(STORAGE_EVENT, handleStorageChange);
    return () =>
      window.removeEventListener(STORAGE_EVENT, handleStorageChange);
  }, []);

  const handleExport = () => {
    // exportTransactions(transactions); // CSV
    exportFullMonthlyReport("Relatório Mensal", transactions, totals);
    showSuccess("Relatório PDF gerado!");
  };

  const handleImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const imported = await importTransactions(file);
      if (
        window.confirm(
          `Deseja importar ${imported.length} transações? Isso substituirá seus dados atuais.`
        )
      ) {
        window.location.reload(); // Reload to refresh transactions
      }
    } catch (error) {
      showError(error instanceof Error ? error.message : "Erro ao importar");
    }
  };

  const handleBankSyncSuccess = (newTransactions: Partial<Transaction>[]) => {
    newTransactions.forEach(t => {
      addTransaction(t as any);
    });
  };

  const handleNewTransaction = () => {
    setEditingTransaction(null);
    setShowForm(true);
  };

  const handleEdit = (transaction: Transaction) => {
    setEditingTransaction(transaction);
    setShowForm(true);
  };

  const handleSubmit = (formData: TransactionFormData, isEditing: boolean) => {
    if (isEditing && editingTransaction) {
      updateTransaction(editingTransaction.id, formData);
    } else {
      addTransaction(formData);
    }
    setShowForm(false);
    setEditingTransaction(null);
  };

  const handleCancel = () => {
    setShowForm(false);
    setEditingTransaction(null);
  };

  const handleApplyPreset = (data: { 
    budgets?: { category: string; amount: number }[]; 
    goals?: { name: string; targetAmount: number; icon: string }[] 
  }) => {
    if (data.budgets) {
      saveBudgets(data.budgets.map((b, i) => ({
        id: (Date.now() + i).toString(),
        category: b.category,
        limit: b.amount,
        spent: 0,
        month: new Date().toISOString().slice(0, 7)
      })));
    }
    if (data.goals) {
      saveGoals(data.goals.map((g, i) => ({
        id: (Date.now() + i + 100).toString(),
        name: g.name,
        targetAmount: g.targetAmount,
        currentAmount: 0,
        deadline: new Date(Date.now() + 365 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
        icon: g.icon,
        color: "from-indigo-500 to-purple-600"
      })));
    }
    setShowWizard(false);
  };

  const incomeCount = filteredTransactions.filter(
    (t) => t.type === "income"
  ).length;
  const expenseCount = filteredTransactions.filter(
    (t) => t.type === "expense"
  ).length;

  return (
    <div className="space-y-10 animate-fade-in pb-12">
      <AnimatePresence>
        {transactions.length === 0 && !showWizard && (
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            className="premium-card p-6 bg-indigo-500/10 border-indigo-500/20 flex flex-col md:flex-row items-center justify-between gap-6"
          >
            <div className="flex items-center gap-4 text-center md:text-left">
              <div className="w-12 h-12 rounded-2xl bg-indigo-500 flex items-center justify-center text-white shadow-lg">
                <Sparkles size={24} />
              </div>
              <div>
                <h4 className="font-black text-white uppercase tracking-tight">Configure com um clique</h4>
                <p className="text-xs text-slate-400 font-medium">Use presets inteligentes para não precisar configurar tudo manualmente.</p>
              </div>
            </div>
            <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
              <Button
                onClick={() => setShowBankModal(true)}
                className="w-full sm:w-auto h-12 px-6 bg-indigo-500/10 border border-indigo-500/20 text-indigo-400 font-black uppercase tracking-widest rounded-xl hover:bg-indigo-500/20 transition-all"
              >
                <Link2 size={18} className="mr-2" />
                Conectar Banco
              </Button>

              <Button
                onClick={() => setShowWizard(true)}
                disabled={isViewer}
                className="bg-white text-black font-black uppercase tracking-widest text-[10px] h-12 px-8 rounded-xl disabled:opacity-50"
              >
                Abrir Wizard
              </Button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <BankConnectionModal 
        isOpen={showBankModal}
        onClose={() => setShowBankModal(false)}
        onSuccess={handleBankSyncSuccess}
      />

      <AnimatePresence>
        {showWizard && (
          <QuickSetupWizard 
            type="personal" 
            onComplete={handleApplyPreset} 
            onClose={() => setShowWizard(false)} 
          />
        )}
      </AnimatePresence>
      {/* Premium Header */}
      <div className="premium-card p-6 md:p-10">
        <div className="absolute -right-20 -top-20 w-80 h-80 bg-indigo-500/10 blur-[120px] rounded-full" />
        <div className="absolute -left-20 -bottom-20 w-80 h-80 bg-blue-500/5 blur-[120px] rounded-full" />

        <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-8 text-center md:text-left">
          <div className="space-y-4 flex flex-col items-center md:items-start">
            <HelpButton tooltipText="Gerencie suas finanças pessoais: lançamentos, orçamentos, metas e lembretes" />
            <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-indigo-500/10 border border-white/5 text-[10px] font-black uppercase tracking-widest text-indigo-400">
              <Sparkles size={12} />
              Gestão Financeira
            </div>
            <h2 className="text-4xl md:text-5xl font-black leading-tight tracking-tighter">
              Fluxo <br className="hidden md:block" />
              <span className="premium-gradient-text">Pessoal Master</span>
            </h2>
            <p className="text-slate-400 font-medium max-w-md hidden md:block">
              Acompanhe seu fluxo de caixa pessoal com precisão matemática em
              tempo real.
            </p>
          </div>

          <div className="flex flex-col sm:flex-row items-center gap-3 w-full md:w-auto">
            <input
              type="file"
              ref={fileInputRef}
              onChange={handleImport}
              accept=".json"
              className="hidden"
            />

            <div className="flex items-center gap-2 w-full sm:w-auto justify-center">
              <Button
                variant="glossy"
                size="icon"
                onClick={() => exportTransactionsToCSV(transactions)}
                title="Exportar para Excel"
              >
                <FileSpreadsheet size={18} />
              </Button>
              <Button
                variant="glossy"
                size="icon"
                onClick={handleExport}
                title="Exportar para JSON"
              >
                <Download size={18} />
              </Button>
              <Button
                variant="glossy"
                size="icon"
                onClick={() => isViewer ? showError("Somente leitura") : fileInputRef.current?.click()}
                disabled={isViewer}
                title="Importar transações"
              >
                <Upload size={18} />
              </Button>
            </div>

            <div className="grid grid-cols-2 gap-2 w-full sm:flex sm:w-auto">
               <Button
                variant="glossy"
                size="lg"
                onClick={() => isViewer ? showError("Somente leitura") : setShowReceiptScanner(true)}
                disabled={isViewer}
                className="font-black text-[10px] md:text-xs uppercase tracking-widest"
              >
                <Camera size={18} className="mr-2 hidden sm:block" />
                Escanear
              </Button>
              <Button
                variant="default"
                size="lg"
                onClick={() => isViewer ? showError("Somente leitura") : handleNewTransaction()}
                disabled={isViewer}
                className="font-black text-[10px] md:text-xs uppercase tracking-widest"
              >
                <PlusCircle size={18} className="mr-2 hidden sm:block" />
                Novo Lançamento
              </Button>
            </div>
          </div>
        </div>
      </div>

      {/* Navigation Tabs */}
      <div className="relative group">
        <div className="absolute right-0 top-0 bottom-0 w-12 bg-gradient-to-l from-black/20 to-transparent pointer-events-none z-10 md:hidden" />
        <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
          <TabsList className="flex bg-white/5 p-1 rounded-2xl border border-white/10 w-full md:w-fit mb-10 overflow-x-auto no-scrollbar scroll-smooth">
            <TabsTrigger
              value="dashboard"
              className="px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black flex items-center gap-2 whitespace-nowrap"
            >
              <LayoutDashboard size={14} />
              Dashboard
            </TabsTrigger>
            <TabsTrigger
              value="budgets"
              className="px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black flex items-center gap-2 whitespace-nowrap"
            >
              <Target size={14} />
              Orçamentos
            </TabsTrigger>
            <TabsTrigger
              value="goals"
              className="px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black flex items-center gap-2 whitespace-nowrap"
            >
              <TrendingUp size={14} />
              Metas
            </TabsTrigger>
            <TabsTrigger
              value="reminders"
              className="px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black flex items-center gap-2 whitespace-nowrap"
            >
              <Bell size={14} />
              Lembretes
            </TabsTrigger>
            <TabsTrigger
              value="analytics"
              className="px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black flex items-center gap-2 whitespace-nowrap"
            >
              <BarChart3 size={14} />
              Análises
            </TabsTrigger>
            <TabsTrigger
              value="insights"
              className="px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-black flex items-center gap-2 whitespace-nowrap"
            >
              <Brain size={14} />
              IA Insights
            </TabsTrigger>
            <TabsTrigger
              value="debts"
              className="px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all data-[state=active]:bg-rose-500 data-[state=active]:text-white flex items-center gap-2 whitespace-nowrap"
            >
              <AlertCircle size={14} />
              Dívidas
            </TabsTrigger>
          </TabsList>
        </Tabs>
      </div>

      {/* Transaction Form */}
      {showForm && (
        <TransactionForm
          editingTransaction={editingTransaction}
          onSubmit={handleSubmit}
          onCancel={handleCancel}
          scope="personal"
        />
      )}

      {/* Tab Content */}
      {activeTab === "dashboard" && (
        <DashboardTab
            transactions={transactions}
            filteredTransactions={filteredTransactions}
            totals={totals}
            searchTerm={searchTerm}
            setSearchTerm={setSearchTerm}
            filter={filter}
            setFilter={setFilter}
            dateFilter={dateFilter}
            setDateFilter={setDateFilter}
            onEdit={handleEdit}
            onDelete={deleteTransaction}
            onExport={() => {
                const month = new Date().toLocaleDateString("pt-BR", {
                  month: "long",
                  year: "numeric",
                });
                exportFullMonthlyReport(month, transactions, totals);
            }}
        />
      )}

      {activeTab === "budgets" && <BudgetsTab transactions={transactions} />}

      {activeTab === "goals" && <GoalsTab />}

      {activeTab === "reminders" && <RemindersTab />}

      {activeTab === "analytics" && (
        <AnalyticsTabComponent
          monthlyTrend={monthlyTrend}
          categoryData={categoryData}
          incomeChartData={getPieChartData("income")}
          expenseChartData={getPieChartData("expense")}
          totals={totals}
          incomeCount={incomeCount}
          expenseCount={expenseCount}
        />
      )}

      {activeTab === "insights" && (
        <InsightsTab transactions={transactions} goals={goals} totals={totals} />
      )}

      {activeTab === "debts" && <DebtsTab />}

      {/* Receipt Scanner Modal */}
      {showReceiptScanner && (
        <ReceiptScanner
          onClose={() => setShowReceiptScanner(false)}
          onTransactionCreated={() => {
            // Auto-refresh handled by storage events
          }}
        />
      )}
    </div>
  );
};

import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { personalCategories } from "@/lib/constants";
import { formatCurrency } from "@/lib/formatters";
import {
  STORAGE_EVENT,
  STORAGE_KEYS,
  loadReminders,
  saveReminders,
} from "@/lib/storage";
import type { BillReminder } from "@/types";
import { Bell, Check, Pencil, Plus, Trash2 } from "lucide-react";
import { useEffect, useState } from "react";

export const RemindersSection = () => {
  const [reminders, setReminders] = useState<BillReminder[]>([]);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingReminder, setEditingReminder] = useState<BillReminder | null>(
    null
  );
  const [formData, setFormData] = useState<{
    name: string;
    amount: number;
    dueDate: string;
    category: string;
    recurring: "monthly" | "yearly" | "once";
  }>({
    name: "",
    amount: 0,
    dueDate: "",
    category: "",
    recurring: "monthly",
  });

  const today = new Date();

  useEffect(() => {
    setReminders(loadReminders());

    const handleStorageChange = (e: any) => {
      if (e.detail?.key === STORAGE_KEYS.REMINDERS) {
        setReminders(e.detail.data);
      }
    };

    window.addEventListener(STORAGE_EVENT as any, handleStorageChange);
    return () =>
      window.removeEventListener(STORAGE_EVENT as any, handleStorageChange);
  }, []);

  const handleSave = () => {
    if (!formData.name || formData.amount <= 0 || !formData.dueDate) return;

    let updatedReminders: BillReminder[];
    if (editingReminder) {
      updatedReminders = reminders.map((r) =>
        r.id === editingReminder.id
          ? {
              ...r,
              name: formData.name,
              amount: formData.amount,
              dueDate: formData.dueDate,
              category: formData.category,
              recurring: formData.recurring,
            }
          : r
      );
    } else {
      const newReminder: BillReminder = {
        id: Date.now().toString(),
        name: formData.name,
        amount: formData.amount,
        dueDate: formData.dueDate,
        category: formData.category,
        isPaid: false,
        recurring: formData.recurring,
      };
      updatedReminders = [...reminders, newReminder];
    }

    setReminders(updatedReminders);
    saveReminders(updatedReminders);
    setIsDialogOpen(false);
    setEditingReminder(null);
    setFormData({
      name: "",
      amount: 0,
      dueDate: "",
      category: "",
      recurring: "monthly",
    });
  };

  const handleEdit = (reminder: BillReminder) => {
    setEditingReminder(reminder);
    setFormData({
      name: reminder.name ?? "",
      amount: reminder.amount,
      dueDate: reminder.dueDate,
      category: reminder.category,
      recurring: reminder.recurring,
    });
    setIsDialogOpen(true);
  };

  const handleDelete = (id: string) => {
    const updatedReminders = reminders.filter((r) => r.id !== id);
    setReminders(updatedReminders);
    saveReminders(updatedReminders);
  };

  const handleTogglePaid = (reminder: BillReminder) => {
    const updatedReminders = reminders.map((r) =>
      r.id === reminder.id ? { ...r, isPaid: !r.isPaid } : r
    );
    setReminders(updatedReminders);
    saveReminders(updatedReminders);
  };

  const openNewDialog = () => {
    setEditingReminder(null);
    // Set default due date to next month same day
    const nextMonth = new Date();
    nextMonth.setMonth(nextMonth.getMonth() + 1);
    setFormData({
      name: "",
      amount: 0,
      dueDate: nextMonth.toISOString().split("T")[0] || "",
      category: "",
      recurring: "monthly",
    });
    setIsDialogOpen(true);
  };

  const formatDate = (d: string) => new Date(d).toLocaleDateString("pt-BR");

  // Sort reminders: unpaid first, then by due date
  const sortedReminders = [...reminders].sort((a, b) => {
    if (a.isPaid !== b.isPaid) return a.isPaid ? 1 : -1;
    return new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime();
  });

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="flex justify-between items-center bg-white/5 p-4 rounded-3xl border border-white/5">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-rose-500/10 rounded-xl text-rose-400">
            <Bell size={20} />
          </div>
          <h3 className="text-xs font-black uppercase tracking-[0.2em] text-slate-400">
            Gestão de <span className="text-white">Pagamentos</span>
          </h3>
        </div>
        <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
          <DialogTrigger asChild>
            <Button
              onClick={openNewDialog}
              className="h-10 px-6 rounded-xl bg-white text-black hover:bg-white/90 font-black text-[10px] uppercase tracking-widest shadow-lg shadow-white/5 transition-all hover:scale-105 active:scale-95"
            >
              <Plus size={14} className="mr-2" />
              Novo Lembrete
            </Button>
          </DialogTrigger>
          <DialogContent className="glass-premium border-white/10 text-white max-w-md">
            <DialogHeader>
              <DialogTitle className="text-2xl font-black tracking-tight">
                {editingReminder ? "Editar" : "Novo"}{" "}
                <span className="premium-gradient-text">Lembrete</span>
              </DialogTitle>
            </DialogHeader>
            <div className="space-y-6 pt-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">
                  Nome da Conta
                </label>
                <Input
                  value={formData.name}
                  onChange={(e) =>
                    setFormData({ ...formData, name: e.target.value })
                  }
                  placeholder="Ex: Aluguel, Internet..."
                  className="h-14 bg-white/5 border-white/10 rounded-2xl focus:ring-rose-500/20 text-white font-medium px-6"
                />
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">
                    Valor (R$)
                  </label>
                  <Input
                    type="number"
                    value={formData.amount || ""}
                    onChange={(e) =>
                      setFormData({
                        ...formData,
                        amount: Number(e.target.value),
                      })
                    }
                    placeholder="0"
                    className="h-14 bg-white/5 border-white/10 rounded-2xl focus:ring-rose-500/20 text-white px-6"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">
                    Vencimento
                  </label>
                  <Input
                    type="date"
                    value={formData.dueDate}
                    onChange={(e) =>
                      setFormData({ ...formData, dueDate: e.target.value })
                    }
                    className="h-14 bg-white/5 border-white/10 rounded-2xl focus:ring-rose-500/20 text-white px-6"
                  />
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">
                  Categoria
                </label>
                <Select
                  value={formData.category}
                  onValueChange={(v) =>
                    setFormData({ ...formData, category: v })
                  }
                >
                  <SelectTrigger className="h-14 bg-white/5 border-white/10 rounded-2xl focus:ring-rose-500/20 text-white">
                    <SelectValue placeholder="Selecione uma categoria" />
                  </SelectTrigger>
                  <SelectContent className="bg-slate-900 border-white/10 text-white">
                    {personalCategories.expense.map((cat) => (
                      <SelectItem
                        key={cat}
                        value={cat}
                        className="focus:bg-white/10 focus:text-white"
                      >
                        {cat}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">
                  Frequência
                </label>
                <Select
                  value={formData.recurring}
                  onValueChange={(v: "monthly" | "yearly" | "once") =>
                    setFormData({ ...formData, recurring: v })
                  }
                >
                  <SelectTrigger className="h-14 bg-white/5 border-white/10 rounded-2xl focus:ring-rose-500/20 text-white">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent className="bg-slate-900 border-white/10 text-white">
                    <SelectItem value="monthly">Mensal</SelectItem>
                    <SelectItem value="yearly">Anual</SelectItem>
                    <SelectItem value="once">Uma única vez</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="flex gap-4 pt-4">
                <Button
                  variant="ghost"
                  onClick={() => setIsDialogOpen(false)}
                  className="flex-1 h-12 rounded-xl text-slate-400 font-bold"
                >
                  Descartar
                </Button>
                <Button
                  onClick={handleSave}
                  className="flex-1 h-12 rounded-xl bg-white text-black hover:bg-white/90 font-black uppercase tracking-widest"
                >
                  Confirmar
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      {reminders.length === 0 ? (
        <div className="premium-card p-20 text-center">
          <Bell className="mx-auto text-white/5 mb-6" size={64} />
          <h4 className="text-xl font-black text-white mb-2 tracking-tight">
            Nenhuma Conta Pendente
          </h4>
          <p className="text-sm text-slate-500 mb-8 max-w-sm mx-auto">
            Organize seus boletos e pagamentos recorrentes para evitar multas e
            juros.
          </p>
          <Button
            onClick={openNewDialog}
            className="px-10 h-14 rounded-2xl bg-white text-black font-black uppercase tracking-[0.2em] transform transition-all hover:scale-105"
          >
            Agendar Pagamento
          </Button>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {sortedReminders.map((r) => {
            const due = new Date(r.dueDate);
            const isOverdue = !r.isPaid && due < today;
            const isDueSoon =
              !r.isPaid &&
              due <= new Date(today.getTime() + 3 * 24 * 60 * 60 * 1000);

            return (
              <div
                key={r.id}
                className={`premium-card group transition-all duration-500 ${
                  r.isPaid ? "opacity-40 grayscale-[0.8]" : "hover:scale-[1.02]"
                }`}
              >
                <div className="p-6 md:p-8 flex items-center justify-between gap-6">
                  <div className="flex items-center gap-5 flex-1 min-w-0">
                    <button
                      onClick={() => handleTogglePaid(r)}
                      className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${
                        r.isPaid
                          ? "bg-emerald-500 text-black scale-90"
                          : isOverdue
                          ? "bg-rose-500/10 text-rose-500 border border-rose-500/20"
                          : "bg-white/5 text-slate-400 hover:bg-white/10 border border-white/5"
                      }`}
                    >
                      <Check size={20} strokeWidth={r.isPaid ? 3 : 2} />
                    </button>

                    <div className="min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <h4
                          className={`font-black tracking-tight truncate ${
                            r.isPaid ? "text-slate-500" : "text-white"
                          }`}
                        >
                          {r.name}
                        </h4>
                        {r.category && (
                          <span className="text-[8px] font-black uppercase tracking-widest text-slate-500 px-1.5 py-0.5 bg-white/5 rounded">
                            {r.category}
                          </span>
                        )}
                      </div>
                      <p className="text-[10px] font-black uppercase tracking-widest text-slate-500 flex items-center gap-2">
                        {isOverdue ? "Venceu" : "Vence"}:{" "}
                        <span
                          className={
                            isOverdue ? "text-rose-500" : "text-slate-300"
                          }
                        >
                          {formatDate(r.dueDate)}
                        </span>
                        {r.recurring !== "once" && (
                          <span className="flex items-center gap-1 opacity-50">
                            • {r.recurring === "monthly" ? "Mensal" : "Anual"}
                          </span>
                        )}
                      </p>
                    </div>
                  </div>

                  <div className="text-right flex items-center gap-4">
                    <div className="space-y-1">
                      <p
                        className={`text-xl font-black tracking-tighter ${
                          r.isPaid
                            ? "text-slate-500 line-through"
                            : "text-white"
                        }`}
                      >
                        {formatCurrency(r.amount)}
                      </p>
                      <div className="flex justify-end">
                        {r.isPaid ? (
                          <div className="px-2 py-0.5 rounded-full bg-emerald-500/10 text-emerald-500 text-[8px] font-black uppercase tracking-widest border border-emerald-500/10">
                            Confirmado
                          </div>
                        ) : isOverdue ? (
                          <div className="px-2 py-0.5 rounded-full bg-rose-500/10 text-rose-500 text-[8px] font-black uppercase tracking-widest border border-rose-500/10 animate-pulse">
                            Atrasado
                          </div>
                        ) : isDueSoon ? (
                          <div className="px-2 py-0.5 rounded-full bg-amber-500/10 text-amber-500 text-[8px] font-black uppercase tracking-widest border border-amber-500/10">
                            Prioridade
                          </div>
                        ) : null}
                      </div>
                    </div>

                    <div className="flex flex-col gap-1.5 opacity-0 group-hover:opacity-100 transition-all transform translate-x-2 group-hover:translate-x-0">
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8 rounded-lg bg-white/5 hover:bg-white/10 text-slate-400 hover:text-white"
                        onClick={() => handleEdit(r)}
                      >
                        <Pencil size={12} />
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8 rounded-lg bg-rose-500/5 hover:bg-rose-500/10 text-rose-500"
                        onClick={() => handleDelete(r.id)}
                      >
                        <Trash2 size={12} />
                      </Button>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

import { Button } from "@/components/ui/button";
import { formatCurrency } from "@/lib/formatters";
import { detectPatterns } from "@/lib/recurring-detector";
import { useInvestments } from "@/hooks/useInvestments";
import { addReminder, loadReminders } from "@/lib/storage";
import { showSuccess } from "@/lib/toast";
import type { SavingsGoal, Transaction } from "@/types";
import { motion } from "framer-motion";
import { PieChart, Sparkles, TrendingUp, Zap } from "lucide-react";
import { useState } from "react";
import { PrivacyValue } from "../ui/PrivacyValue";
import { EmptyState } from "../ui/EmptyState";

interface Props {
  transactions: Transaction[];
  goals: SavingsGoal[];
  onNavigate?: (tab: any) => void;
}

export const SmartInsights = ({ transactions, goals, onNavigate }: Props) => {
  const [reminders, setReminders] = useState(() => loadReminders());
  const { assets } = useInvestments();

  const patterns = detectPatterns(transactions, reminders);

  if (!transactions || transactions.length === 0) {
    return (
      <EmptyState
        icon={Zap}
        title="Insights Congelados ❄️"
        description="A inteligência artificial precisa de dados. Registre movimentos financeiros para que possamos traçar seus padrões, linha do tempo de riqueza e metas FIRE."
      />
    );
  }

  const handleAddReminder = async (p: any) => {
    // Set next month as default due date
    const nextMonth = new Date();
    nextMonth.setMonth(nextMonth.getMonth() + 1);

    await addReminder({
      name: p.description,
      amount: p.amount,
      category: p.category ?? "Outros",
      dueDate: nextMonth.toISOString().split("T")[0] || "",
      recurring: "monthly",
    });

    setReminders(loadReminders());
    showSuccess(`${p.description} adicionado aos lembretes!`);
  };

  const totalInvested = assets.reduce(
    (acc, a) => acc + (a.amount * (a.currentPrice || 1)),
    0
  );

  // Basic Wealth Timeline Logic
  const monthlyExpenses =
    transactions
      .filter((t) => t.type === "expense")
      .reduce((acc, t) => acc + t.amount, 0) /
    (transactions.length > 30 ? 3 : 1); // rough monthly avg

  const monthlySurplus =
    transactions.reduce(
      (acc, t) => acc + (t.type === "income" ? t.amount : -t.amount),
      0
    ) / (transactions.length > 30 ? 3 : 1);

  // FIRE Calculation (4% Rule)
  // Required Capital = Monthly Expenses * 12 / 0.04
  const annualExpenses = monthlyExpenses * 12;
  const fireTarget = annualExpenses > 0 ? annualExpenses / 0.04 : 1;
  const firePercentage = fireTarget > 0 ? Math.min((totalInvested / fireTarget) * 100, 100) : 0;

  // Years to FIRE (Simplified simple interest/no growth for conservative estimate)
  const monthlySaving = Math.max(monthlySurplus, 0);
  const yearsToFire =
    monthlySaving > 0
      ? (fireTarget - totalInvested) / (monthlySaving * 12)
      : Infinity;

  // Expense Optimization logic
  const wantTotal = transactions
    .filter((t) => t.type === "expense" && t.classification === "want")
    .reduce((acc, t) => acc + t.amount, 0);

  const potentialSavings10yr = wantTotal * 12 * 10 * 1.5; // Roughly 50% growth total for teaser math

  return (
    <div className="space-y-8 pb-10">
      {/* Patterns Section */}
      {patterns.length > 0 && (
        <div className="space-y-6">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-amber-500/10 rounded-xl text-amber-400">
              <Zap size={20} />
            </div>
            <h3 className="text-xs font-black uppercase tracking-[0.2em] text-slate-400">
              Padrões <span className="text-white">Detectados</span> 🕵️‍♂️
            </h3>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {patterns.map((p, i) => (
              <motion.div
                key={i}
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: i * 0.1 }}
                className="p-6 rounded-[2rem] bg-white/[0.03] border border-white/5 hover:bg-white/[0.06] transition-all group"
              >
                <div className="flex justify-between items-start gap-4">
                  <div>
                    <h4 className="font-bold text-white text-lg mb-1">
                      {p.description}
                    </h4>
                    <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">
                      Detectado {p.frequency}x • Média{" "}
                      {formatCurrency(p.amount)}
                    </p>
                  </div>
                  <Button
                    onClick={() => handleAddReminder(p)}
                    className="h-10 px-4 rounded-xl bg-indigo-500/10 text-indigo-400 hover:bg-indigo-500 hover:text-white transition-all text-[10px] font-black uppercase tracking-widest border border-indigo-500/20"
                  >
                    Agendar
                  </Button>
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      )}

      {/* Wealth Timeline Section */}
      <div className="space-y-6">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-500/10 rounded-xl text-indigo-400">
            <TrendingUp size={20} />
          </div>
          <h3 className="text-xs font-black uppercase tracking-[0.2em] text-slate-400">
            Linha do Tempo <span className="text-white">de Riqueza</span> ⏳
          </h3>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {goals.map((goal) => {
            const remaining = goal.targetAmount - goal.currentAmount;
            const monthsToGoal =
              monthlySurplus > 0
                ? Math.ceil(remaining / (monthlySurplus * 0.5))
                : Infinity; // Assume 50% of surplus goes to this goal

            return (
              <div key={goal.id} className="premium-card p-6 space-y-4">
                <div className="flex justify-between items-center">
                  <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">
                    {goal.name}
                  </span>
                  <Sparkles size={14} className="text-indigo-400/50" />
                </div>
                <div className="space-y-1">
                  <p className="text-sm text-slate-500 font-medium">
                    Estimativa para conclusão:
                  </p>
                  <p className="text-2xl font-black text-white">
                    {monthsToGoal === Infinity
                      ? "???"
                      : monthsToGoal > 12
                      ? `${Math.floor(monthsToGoal / 12)}a ${
                          monthsToGoal % 12
                        }m`
                      : `${monthsToGoal} meses`}
                  </p>
                </div>
                <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
                  <div
                    className="h-full bg-indigo-500"
                    style={{
                      width: `${
                        (goal.currentAmount / goal.targetAmount) * 100
                      }%`,
                    }}
                  />
                </div>
                <p className="text-[10px] text-slate-600 font-bold uppercase">
                  Baseado no seu superavit atual
                </p>
              </div>
            );
          })}

          <div className="premium-card p-6 bg-emerald-500/5 border-emerald-500/20 flex flex-col justify-between">
            <div>
              <h4 className="text-xs font-black text-emerald-400 uppercase tracking-widest mb-1">
                Poder de Liberdade
              </h4>
              <p className="text-[10px] text-slate-400 leading-relaxed">
                Com seus investimentos atuais, você poderia viver por:
              </p>
            </div>
            <div className="py-4">
              <p className="text-4xl font-black text-white">
                {monthlyExpenses > 0 ? Math.floor(totalInvested / (monthlyExpenses / 30)) : 0} <span className="text-lg text-slate-500">dias</span>
              </p>
            </div>
            <p className="text-[8px] text-slate-600 font-bold uppercase italic">
              Fator de Sobrevivência (Baseado no custo de vida atual)
            </p>
          </div>

          <div className="premium-card p-6 bg-indigo-500/10 border-indigo-500/30 flex flex-col justify-between">
            <div>
              <h4 className="text-xs font-black text-white uppercase tracking-widest mb-1">
                Aposentadoria (FIRE)
              </h4>
              <p className="text-[10px] text-slate-400">
                Progresso para viver de renda (Regra dos 4%)
              </p>
            </div>
            <div className="py-4 space-y-2">
              <p className="text-4xl font-black text-white">
                {firePercentage.toFixed(1)}%
              </p>
              <div className="h-2 w-full bg-white/5 rounded-full overflow-hidden border border-white/5">
                <motion.div
                  initial={{ width: 0 }}
                  animate={{ width: `${firePercentage}%` }}
                  className="h-full bg-gradient-to-r from-indigo-500 to-purple-500"
                />
              </div>
            </div>
            <div className="flex justify-between items-center text-[10px] font-bold text-slate-500 uppercase">
              <span>
                Faltam:{" "}
                {yearsToFire === Infinity
                  ? "???"
                  : yearsToFire > 50
                  ? "+50 anos"
                  : `${yearsToFire.toFixed(1)} anos`}
              </span>
            </div>
          </div>
        </div>
      </div>

      {/* Optimization Tips */}
      <div className="premium-card p-8 bg-indigo-600/10 border-indigo-500/20 overflow-hidden relative">
        <div className="absolute top-0 right-0 p-10 opacity-10">
          <PieChart size={120} />
        </div>
        <div className="relative z-10 space-y-6">
          <div className="space-y-2">
            <h3 className="text-xl font-black text-white uppercase tracking-tight">
              Auditoria de <span className="text-indigo-400">Desejos</span>
            </h3>
            <p className="text-sm text-slate-400 max-w-md font-medium">
              Você classificou{" "}
              <span className="text-white font-bold">
                {formatCurrency(wantTotal)}
              </span>{" "}
              como "Desejos" (não-essenciais) em seu histórico.
            </p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-center">
            <div className="space-y-4">
              <div className="p-4 rounded-2xl bg-white/5 border border-white/5 space-y-1">
                <p className="text-[10px] font-bold text-slate-500 uppercase">
                  Custo de Oportunidade (10 anos)
                </p>
                <p className="text-2xl font-black text-indigo-400">
                  <PrivacyValue value={potentialSavings10yr} />
                </p>
              </div>
              <p className="text-[10px] text-slate-500 leading-relaxed italic">
                *Este é o valor que você teria se investisse o total gasto em
                desejos a uma taxa conservadora.
              </p>
            </div>

            <div className="space-y-2">
              <Button 
                onClick={() => onNavigate?.("ai")}
                className="w-full h-12 rounded-2xl bg-indigo-600 hover:bg-indigo-500 font-black text-xs uppercase tracking-widest"
              >
                Otimizar Gastos Agora
              </Button>
              <Button
                variant="ghost"
                onClick={() => onNavigate?.("budget")}
                className="w-full text-slate-500 font-bold text-[10px] uppercase"
              >
                Ver Categoria por Categoria
              </Button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import { useState } from "react";
import type { TabType } from "@/types/navigation";
import { useInvestments } from "@/hooks/useInvestments";
import { useTransactions } from "@/hooks/useTransactions";
import { useDebts } from "@/hooks/useDebts";
import { useAuth } from "@/context/AuthContext";
import { formatCurrency } from "@/lib/formatters";
import { ArrowLeft, Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { HelpButton } from "@/components/ui/HelpButton";
import { AreaTutorialButton } from "@/components/ui/AreaTutorialButton";
import { useFireCalculation } from "@/hooks/useFireCalculation";


interface RetireFireViewProps {
  onBack?: (tab?: TabType) => void;
  onNavigate?: (tab: TabType) => void;
}

export const RetireFireView = ({ onBack, onNavigate }: RetireFireViewProps) => {
  const { user } = useAuth();
  const { totals: invTotals, loading: invLoading } = useInvestments();
  const personal = useTransactions("personal");
  const business = useTransactions("business");
  const { totals: debtTotals, isLoading: debtLoading } = useDebts();

  // ── Loading state ──
  const isLoading = invLoading || personal.isLoading || business.isLoading || debtLoading;

  // ── Real data ──
  const patrimonioAtual = Math.max(0,
    (personal.totals.balance + business.totals.balance + invTotals.currentValue) - debtTotals.totalBalance
  );
  const rendaAtual = personal.totals.income + business.totals.income;

  // ── Controlled state ──
  const [despesa, setDespesa] = useState(() =>
    Math.round((personal.totals.expense || 8000))
  );
  const [aporte, setAporte] = useState(() =>
    Math.round((rendaAtual * 0.2) || 2000)
  );
  const [taxaAnual, setTaxaAnual] = useState(10); // % ao ano

  // ── FIRE calculation (fully reactive) ──
  const WITHDRAWAL_RATE = 0.032; // 3.2% — conservative for Brazil

  const { months, targets } = useFireCalculation({
    currentNetWorth: patrimonioAtual,
    monthlyExpenses: despesa,
    monthlyDeposit: aporte,
    yearlyReturn: taxaAnual,
    withdrawalRate: WITHDRAWAL_RATE
  });

  const meta = targets.base;
  const meses = months.base;

  const anos = (meses / 12).toFixed(1);
  const atingivel = meses < 600;
  const progresoFire = Math.min(100, (patrimonioAtual / meta) * 100);

  // Year of FIRE
  const anoFire = new Date().getFullYear() + Math.round(meses / 12);
  const idadeAtual = (user as any)?.age || 30;
  const idadeFire = idadeAtual + Math.round(meses / 12);

  // Lean FIRE and Fat FIRE — use months from hook (fix: was using undeclared taxaMes)
  const leanMeta = targets.lean;
  const fatMeta = targets.fat;
  const leanMeses = months.lean;
  const fatMeses = months.fat;

  if (isLoading) {
    return (
      <div style={{ paddingTop: "10px", display: "flex", flexDirection: "column", gap: 16 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 20 }}>
          <Button variant="ghost" size="icon" onClick={() => onBack?.()} className="rounded-xl">
            <ArrowLeft size={16} />
          </Button>
          <div style={{ flex: 1 }}>
            <div className="eyebrow">Independência financeira</div>
            <div className="page-title" style={{ margin: 0, fontSize: 22 }}>Calculadora FIRE</div>
          </div>
        </div>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "center", padding: "60px 0", gap: 12, color: "var(--t3)" }}>
          <Loader2 size={20} style={{ animation: "spin 1s linear infinite" }} />
          <span style={{ fontSize: 14 }}>Carregando dados financeiros...</span>
        </div>
      </div>
    );
  }

  return (
    <div style={{ paddingTop: "10px", animation: "fsu 0.26s ease", paddingBottom: "100px" }}>
      {/* Header */}
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 20 }}>
        <Button variant="ghost" size="icon" onClick={() => onBack?.()} className="rounded-xl">
          <ArrowLeft size={16} />
        </Button>
        <div style={{ flex: 1 }}>
          <div className="eyebrow">Independência financeira</div>
          <div className="page-title" style={{ margin: 0, fontSize: 22, display: "flex", alignItems: "center", gap: 8 }}>
            Calculadora FIRE
            <HelpButton tooltipText="Projete sua independência financeira com patrimônio atual, aporte mensal, despesas desejadas e taxa de retorno." />
          </div>
        </div>
        <AreaTutorialButton area="futuro" onNavigate={onNavigate} />
      </div>

      {/* Hero — FIRE result */}
      <div className="hero" style={{ textAlign: "center", padding: "24px 20px" }}>
        <div style={{ fontSize: "10px", color: "var(--t3)", textTransform: "uppercase", letterSpacing: "0.12em", fontWeight: 600, marginBottom: 8 }}>
          {atingivel ? "Data estimada FIRE" : "Meta inalcançável no prazo"}
        </div>
        {atingivel ? (
          <>
            <div style={{ fontSize: 38, fontWeight: 700, color: "var(--t1)", letterSpacing: "-1.5px", fontFamily: "var(--mono)" }}>
              {anoFire}
            </div>
            <div style={{ fontSize: 13, color: "var(--t2)", marginTop: 4 }}>
              {anos} anos · aos {idadeFire} anos de idade
            </div>
          </>
        ) : (
          <div style={{ fontSize: 15, color: "var(--amber)", fontWeight: 600, marginTop: 4 }}>
            Aumente o aporte ou reduza a despesa desejada.
          </div>
        )}

        {/* Progress bar — current vs meta */}
        <div style={{ margin: "16px 0 6px" }}>
          <div className="prog" style={{ height: 10 }}>
            <div className="prog-fill" style={{
              width: `${progresoFire}%`,
              background: "linear-gradient(90deg, var(--blue), var(--purple))",
            }} />
          </div>
        </div>
        <div style={{ display: "flex", justifyContent: "space-between", fontSize: "10px", color: "var(--t3)", fontFamily: "var(--mono)" }}>
          <span>Atual: {formatCurrency(patrimonioAtual)}</span>
          <span>{Math.round(progresoFire)}%</span>
          <span>Meta: {meta >= 1e6 ? `R$ ${(meta / 1e6).toFixed(1)}M` : formatCurrency(meta)}</span>
        </div>
      </div>

      {/* Metrics */}
      <div className="metric-grid" style={{ marginTop: 12 }}>
        <div className="metric">
          <div className="m-label">Taxa de retirada</div>
          <div className="m-val blue mono">{(WITHDRAWAL_RATE * 100).toFixed(1)}%</div>
          <div className="m-delta">Safe — dados históricos BR</div>
        </div>
        <div className="metric">
          <div className="m-label">Patrimônio alvo</div>
          <div className="m-val mono">{meta >= 1e6 ? `R$ ${(meta / 1e6).toFixed(1)}M` : formatCurrency(meta)}</div>
          <div className="m-delta">{Math.round(1 / WITHDRAWAL_RATE)}× despesas anuais</div>
        </div>
        <div className="metric">
          <div className="m-label">Renda passiva</div>
          <div className="m-val green mono">{formatCurrency(despesa)}</div>
          <div className="m-delta">em valores atuais</div>
        </div>
        <div className="metric">
          <div className="m-label">Patrimônio atual</div>
          <div className="m-val mono">{patrimonioAtual >= 1e6 ? `R$ ${(patrimonioAtual / 1e6).toFixed(2)}M` : formatCurrency(patrimonioAtual)}</div>
          <div className="m-delta">patrimônio líquido real</div>
        </div>
      </div>

      {/* Interactive simulator */}
      <div className="sec-hd"><span className="sec-title">Simulador — ajuste sua meta</span></div>
      <div className="card">
        {/* Despesa desejada */}
        <div style={{ marginBottom: 20 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
            <div style={{ fontSize: 13, color: "var(--t1)", fontWeight: 500 }}>Despesa mensal desejada na IF</div>
            <div style={{ fontSize: 15, fontWeight: 700, color: "var(--t1)", fontFamily: "var(--mono)" }}>{formatCurrency(despesa)}</div>
          </div>
          <input type="range" min="2000" max="30000" step="500" value={despesa}
            onChange={e => setDespesa(+e.target.value)}
            style={{ width: "100%", accentColor: "#7B6FFF", cursor: "pointer" }} />
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 9, color: "var(--t3)", marginTop: 2 }}>
            <span>R$ 2.000 (Lean)</span><span>R$ 30.000 (Fat)</span>
          </div>
        </div>

        {/* Aporte mensal */}
        <div style={{ marginBottom: 20 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
            <div style={{ fontSize: 13, color: "var(--t1)", fontWeight: 500 }}>Aporte mensal</div>
            <div style={{ fontSize: 15, fontWeight: 700, color: "var(--t1)", fontFamily: "var(--mono)" }}>{formatCurrency(aporte)}</div>
          </div>
          <input type="range" min="100" max="15000" step="100" value={aporte}
            onChange={e => setAporte(+e.target.value)}
            style={{ width: "100%", accentColor: "#7B6FFF", cursor: "pointer" }} />
          {rendaAtual > 0 && (
            <div style={{ fontSize: 9, color: "var(--t3)", marginTop: 2 }}>
              {Math.round((aporte / rendaAtual) * 100)}% da sua renda atual
            </div>
          )}
        </div>

        {/* Taxa de rendimento */}
        <div style={{ marginBottom: 4 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
            <div style={{ fontSize: 13, color: "var(--t1)", fontWeight: 500 }}>Rentabilidade (a.a.)</div>
            <div style={{ fontSize: 15, fontWeight: 700, color: "var(--t1)", fontFamily: "var(--mono)" }}>{taxaAnual}%</div>
          </div>
          <input type="range" min="1" max="20" step="0.5" value={taxaAnual}
            onChange={e => setTaxaAnual(+e.target.value)}
            style={{ width: "100%", accentColor: "#7B6FFF", cursor: "pointer" }} />
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 9, color: "var(--t3)", marginTop: 2 }}>
            <span>Poupança</span><span>CDI</span><span>Ações BR</span><span>Ações EUA</span>
          </div>
        </div>

        {/* Dynamic result */}
        <div style={{ marginTop: 16, padding: 14, background: "var(--blue3)", borderRadius: 12, border: "1px solid rgba(74,139,255,0.15)" }}>
          <div style={{ fontSize: 10, color: "var(--blue)", textTransform: "uppercase", letterSpacing: "0.06em", fontWeight: 700, marginBottom: 8 }}>
            Resultado com esses parâmetros
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
            <div>
              <div style={{ fontSize: 9, color: "var(--t3)", textTransform: "uppercase", letterSpacing: "0.05em", marginBottom: 3 }}>Patrimônio alvo</div>
              <div style={{ fontSize: 16, fontWeight: 700, color: "var(--t1)", fontFamily: "var(--mono)" }}>
                {meta >= 1e6 ? `R$ ${(meta / 1e6).toFixed(1)}M` : formatCurrency(meta)}
              </div>
            </div>
            <div>
              <div style={{ fontSize: 9, color: "var(--t3)", textTransform: "uppercase", letterSpacing: "0.05em", marginBottom: 3 }}>Anos para FIRE</div>
              <div style={{ fontSize: 16, fontWeight: 700, color: atingivel ? "var(--blue)" : "var(--amber)", fontFamily: "var(--mono)" }}>
                {meses >= 600 ? "> 50 anos" : `${anos} anos`}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* FIRE modalities — using hook values (fix: was using undeclared taxaMes) */}
      <div className="sec-hd"><span className="sec-title">Tipos de FIRE</span></div>
      {[
        {
          em: "🌱", nm: "Lean FIRE",
          desc: `${formatCurrency(Math.round(despesa * 0.6))}/mês`,
          target: leanMeta,
          months: leanMeses,
          color: "var(--green)",
        },
        {
          em: "🔥", nm: "Regular FIRE",
          desc: `${formatCurrency(despesa)}/mês`,
          target: meta,
          months: meses,
          color: "var(--blue)",
          isActive: true,
        },
        {
          em: "💎", nm: "Fat FIRE",
          desc: `${formatCurrency(Math.round(despesa * 1.8))}/mês`,
          target: fatMeta,
          months: fatMeses,
          color: "var(--amber)",
        },
      ].map(({ em, nm, desc, target, months: m, color, isActive }) => {
        const y = (m / 12).toFixed(1);
        return (
          <div key={nm} className="card" style={{
            marginBottom: 10,
            borderColor: isActive ? color : "transparent",
            borderWidth: isActive ? 1.5 : 1,
            borderStyle: "solid",
          }}>
