import { useDrag } from '@use-gesture/react';
import { motion, useAnimation } from 'framer-motion';
import { Trash2 } from 'lucide-react';
import { ReactNode } from 'react';

interface SwipeToDeleteProps {
  children: ReactNode;
  onDelete: () => void;
  className?: string;
}

export function SwipeToDelete({ children, onDelete, className = '' }: SwipeToDeleteProps) {
  const controls = useAnimation();
  
  const bind = useDrag(async ({ active, movement: [x] }) => {
    const trigger = x < -100; // Trigger delete if dragged left more than 100px
    
    if (!active && trigger) {
      await controls.start({ x: -200, opacity: 0 });
      onDelete();
      // Reset after delete animation (optional, depending on list behavior)
    } else {
      controls.start({ x: active ? x : 0, transition: { type: 'spring', stiffness: 300, damping: 30 } });
    }
  }, {
    axis: 'x',
    filterTaps: true,
    from: () => [0, 0],
    bounds: { left: -200, right: 0, top: 0, bottom: 0 },
    rubberband: true
  });

  return (
    <div className={`relative overflow-hidden ${className}`}>
      {/* Background Delete Action */}
      <div className="absolute inset-y-0 right-0 w-24 bg-red-500 flex items-center justify-center rounded-r-xl z-0">
        <Trash2 className="text-white w-6 h-6" />
      </div>

      {/* Foreground Content */}
      <motion.div
        {...(bind() as any)}
        animate={controls}
        className="relative z-10 bg-slate-900 touch-pan-y"
        style={{ touchAction: 'pan-y' }}
      >
        {children}
      </motion.div>
    </div>
  );
}

import { auth } from "@/lib/firebase";
import { Check, CloudOff, Loader2 } from "lucide-react";
import { useEffect, useState } from "react";

type SyncStatus = "synced" | "syncing" | "offline" | "error";

export const SyncIndicator = () => {
  const [status, setStatus] = useState<SyncStatus>("synced");
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    window.addEventListener("online", handleOnline);
    window.addEventListener("offline", handleOffline);

    return () => {
      window.removeEventListener("online", handleOnline);
      window.removeEventListener("offline", handleOffline);
    };
  }, []);

  useEffect(() => {
    if (!isOnline) {
      setStatus("offline");
    } else if (auth.currentUser) {
      setStatus("synced");
    }
  }, [isOnline]);

  // Listen for custom sync events
  useEffect(() => {
    const handleSyncStart = () => setStatus("syncing");
    const handleSyncEnd = () => setStatus("synced");
    const handleSyncError = () => setStatus("error");

    window.addEventListener("sync:start", handleSyncStart);
    window.addEventListener("sync:end", handleSyncEnd);
    window.addEventListener("sync:error", handleSyncError);

    return () => {
      window.removeEventListener("sync:start", handleSyncStart);
      window.removeEventListener("sync:end", handleSyncEnd);
      window.removeEventListener("sync:error", handleSyncError);
    };
  }, []);

  if (!auth.currentUser) return null;

  const statusConfig = {
    synced: {
      icon: Check,
      color: "text-emerald-400",
      bg: "bg-emerald-500/10",
      label: "Sincronizado",
    },
    syncing: {
      icon: Loader2,
      color: "text-indigo-400",
      bg: "bg-indigo-500/10",
      label: "Sincronizando...",
      animate: true,
    },
    offline: {
      icon: CloudOff,
      color: "text-amber-400",
      bg: "bg-amber-500/10",
      label: "Offline",
    },
    error: {
      icon: CloudOff,
      color: "text-rose-400",
      bg: "bg-rose-500/10",
      label: "Erro ao sincronizar",
    },
  };

  const config = statusConfig[status];
  const Icon = config.icon;

  // Don't show anything if synced to reduce noise, unless user hovers or it's crucial
  // Actually, let's keep it minimal: Just the icon
  return (
    <div
      className={`flex items-center justify-center w-8 h-8 rounded-full ${config.bg} border border-white/10 transition-all`}
      title={config.label}
    >
      <Icon
        size={14}
        className={`${config.color} ${(config as any).animate ? "animate-spin" : ""}`}
      />
    </div>
  );
};

