import React, { createContext, useContext, useEffect, useState } from "react";

type Theme = "midnight" | "emerald" | "aura";

interface ThemeContextType {
  theme: Theme;
  setTheme: (theme: Theme) => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider = ({ children }: { children: React.ReactNode }) => {
  const [theme, setTheme] = useState<Theme>(() => {
    const saved = localStorage.getItem("meu_contador_theme");
    return (saved as Theme) || "midnight";
  });

  useEffect(() => {
    const root = window.document.documentElement;
    root.setAttribute("data-theme", theme);
    // Also apply as a class for some tailwind variants if needed
    root.classList.remove("midnight", "emerald", "aura", "dark");
    root.classList.add(theme, "dark");
    localStorage.setItem("meu_contador_theme", theme);
  }, [theme]);

  return (
    <ThemeContext.Provider value={{ theme, setTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error("useTheme must be used within a ThemeProvider");
  }
  return context;
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { api } from '@/lib/api';

interface TourContextType {
  completedTours: string[];
  markTourAsCompleted: (tourId: string) => void;
  hasSeenTour: (tourId: string) => boolean;
  isLoading: boolean;
}

const TourContext = createContext<TourContextType | undefined>(undefined);

export const TourProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [completedTours, setCompletedTours] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const loadTours = async () => {
      try {
        // Tenta carregar do localStorage primeiro para rapidez
        const local = localStorage.getItem('completed_tours');
        if (local) {
          setCompletedTours(JSON.parse(local));
        }

        // Sincroniza com o backend se o usuário estiver logado
        const response = await api.get('/users/preferences') as any;
        if (response.completedTours) {
          const remote = response.completedTours;
          setCompletedTours(remote);
          localStorage.setItem('completed_tours', JSON.stringify(remote));
        } else if (response.data?.completedTours) {
          // Fallback para caso a API retorne envolta em .data
          const remote = response.data.completedTours;
          setCompletedTours(remote);
          localStorage.setItem('completed_tours', JSON.stringify(remote));
        }
      } catch (error) {
        console.error('Erro ao carregar status dos tours:', error);
      } finally {
        setIsLoading(false);
      }
    };

    loadTours();
  }, []);

  const markTourAsCompleted = async (tourId: string) => {
    if (completedTours.includes(tourId)) return;

    const newTours = [...completedTours, tourId];
    setCompletedTours(newTours);
    localStorage.setItem('completed_tours', JSON.stringify(newTours));

    try {
      // Persiste no backend nas preferências do usuário usando PATCH
      await api.patch('/users/preferences', { completedTours: newTours });
    } catch (error) {
      console.warn('Falha ao sincronizar conclusão do tour com o servidor');
    }
  };

  const hasSeenTour = (tourId: string) => completedTours.includes(tourId);

  return (
    <TourContext.Provider value={{ completedTours, markTourAsCompleted, hasSeenTour, isLoading }}>
      {children}
    </TourContext.Provider>
  );
};

export const useTourStatus = () => {
  const context = useContext(TourContext);
  if (!context) {
    throw new Error('useTourStatus deve ser usado dentro de um TourProvider');
  }
  return context;
};

import { api } from "@/lib/api";
import { showError, showSuccess } from "@/lib/toast";
import type { Budget } from "@/types";
import { useEffect, useState, useCallback } from "react";

export const useBudgets = () => {
  const [budgets, setBudgets] = useState<Budget[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchBudgets = useCallback(async () => {
    let cancelled = false; // ← Flag para cleanup
    setLoading(true);
    setError(null);

    try {
      const response = await api.get<any>("/budgets");
      if (!cancelled) { // ← Verifica se componente ainda está montado
        const items = Array.isArray(response) ? response : (response?.items || []);
        setBudgets(items);
      }
    } catch (err) {
      if (!cancelled) {
        setError("Orçamentos indisponíveis. Verifique sua conexão.");
      }
    } finally {
      if (!cancelled) {
        setLoading(false);
      }
    }

    return () => { cancelled = true; }; // ← Cleanup function
  }, []);

  useEffect(() => {
    let cancelled = false;

    const loadData = async () => {
      setLoading(true);
      setError(null);

      try {
        const response = await api.get<any>("/budgets");
        if (!cancelled) {
          const items = Array.isArray(response) ? response : (response?.items || []);
          setBudgets(items);
        }
      } catch (err) {
        if (!cancelled) {
          setError("Orçamentos indisponíveis. Verifique sua conexão.");
        }
      } finally {
        if (!cancelled) {
          setLoading(false);
        }
      }
    };

    loadData();

    return () => { cancelled = true; }; // ← Cleanup!
  }, []);

  const addBudget = async (budget: Omit<Budget, "id" | "spent">) => {
    try {
      const newBudget = await api.post<Budget>("/budgets", budget);
      setBudgets((prev) => [...prev, newBudget]);
      showSuccess("Orçamento definido!");
    } catch (error) {
      showError("Erro ao definir orçamento.");
    }
  };

  const updateBudget = async (id: string, updates: Partial<Budget>) => {
    try {
      const current = budgets.find((b) => b.id === id);
      const newLimit = updates.limit ?? current?.limit ?? 0;
      const newSpent = updates.spent ?? current?.spent ?? 0;

      const updated = await api.put<Budget>(`/budgets/${id}`, { limit: newLimit, spent: newSpent });
      setBudgets((prev) => prev.map((b) => (b.id === id ? updated : b)));
      showSuccess("Orçamento atualizado!");
    } catch (error) {
      showError("Erro ao atualizar orçamento.");
    }
  };

  const deleteBudget = async (id: string) => {
    try {
      await api.delete(`/budgets/${id}`);
      setBudgets((prev) => prev.filter((b) => b.id !== id));
      showSuccess("Orçamento excluído.");
    } catch (error) {
      showError("Erro ao excluir orçamentos.");
    }
  };

  return {
    budgets,
    loading,
    error,
    addBudget,
    updateBudget,
    deleteBudget,
    refresh: fetchBudgets,
  };
};

