  const recurringItems = useMemo((): RecurringItem[] => {
    const items: RecurringItem[] = [];
    const descriptionMap: Record<string, { 
      amounts: number[]; 
      type: 'income' | 'expense';
      category: string;
      dates: number[];
    }> = {};

    personal.allTransactions.forEach(tx => {
      const key = tx.description.toLowerCase().trim();
      if (!descriptionMap[key]) {
        descriptionMap[key] = { 
          amounts: [], 
          type: tx.type,
          category: tx.category,
          dates: []
        };
      }
      descriptionMap[key]!.amounts.push(tx.amount);
      const day = new Date(tx.date).getDate();
      descriptionMap[key]!.dates.push(day);
    });

    Object.entries(descriptionMap).forEach(([desc, data]) => {
      if (data.amounts.length >= 2) {
        const avgAmount = data.amounts.reduce((a, b) => a + b, 0) / data.amounts.length;
        const mostCommonDay = Math.round(
          data.dates.reduce((a, b) => a + b, 0) / data.dates.length
        );

        items.push({
          description: desc.charAt(0).toUpperCase() + desc.slice(1),
          amount: avgAmount,
          type: data.type,
          category: data.category,
          dueDay: mostCommonDay,
          frequency: 'monthly',
        });
      }
    });

    return items.sort((a, b) => a.dueDay - b.dueDay);
  }, [personal.allTransactions]);

  // Generate 30-day cash flow projection
  const cashFlowDays = useMemo((): CashFlowDay[] => {
    const days: CashFlowDay[] = [];
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    let runningBalance = personal.totals.balance;

    const weekdayNames = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];
    const monthNames = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

    for (let i = 0; i < 30; i++) {
      const date = new Date(today);
      date.setDate(date.getDate() + i);

      const dayOfMonth = date.getDate();
      const isWeekend = date.getDay() === 0 || date.getDay() === 6;
      const isToday = i === 0;

      const inflows: CashFlowDay['inflows'] = [];
      const outflows: CashFlowDay['outflows'] = [];

      // Add recurring items
      recurringItems.forEach(item => {
        if (item.dueDay === dayOfMonth) {
          if (item.type === 'income') {
            inflows.push({
              description: item.description,
              amount: item.amount,
              category: item.category,
            });
          } else {
            outflows.push({
              description: item.description,
              amount: item.amount,
              category: item.category,
            });
          }
        }
      });

      // Add budget items (estimated spending)
      if (!isWeekend) {
        budgets.forEach(budget => {
          if (budget.spent < budget.limit) {
            const remaining = budget.limit - budget.spent;
            const daysInMonth = 30;
            const dailyBudget = remaining / daysInMonth;
            if (dailyBudget > 0) {
              outflows.push({
                description: `Orçamento ${budget.category}`,
                amount: dailyBudget,
                category: budget.category,
              });
            }
          }
        });
      }

      // Add goal contributions
      goals.forEach(goal => {
        if (goal.currentAmount < goal.targetAmount && dayOfMonth === 1) {
          const remaining = goal.targetAmount - goal.currentAmount;
          const monthlyContribution = Math.min(remaining, 500); // Assume R$500/month
          outflows.push({
            description: `Meta: ${goal.name}`,
            amount: monthlyContribution,
            category: 'Metas',
          });
        }
      });

      const totalInflow = inflows.reduce((sum, i) => sum + i.amount, 0);
      const totalOutflow = outflows.reduce((sum, o) => sum + o.amount, 0);
      const netFlow = totalInflow - totalOutflow;

      runningBalance += netFlow;

      const isCritical = runningBalance < 0 || (runningBalance < personal.totals.expense * 0.1);

      days.push({
        date: date.toISOString().split('T')[0]!,
        dateFormatted: `${dayOfMonth} ${monthNames[date.getMonth()]}`,
        weekday: weekdayNames[date.getDay()]!,
        inflows,
        outflows,
        netFlow,
        projectedBalance: runningBalance,
        isCritical,
        isToday,
        isWeekend,
      });
    }

    return days;
  }, [personal.totals, recurringItems, budgets, goals]);

  // Calculate summary
  const summary = useMemo((): CashFlowSummary => {
    const currentBalance = personal.totals.balance;
    const lastDay = cashFlowDays[cashFlowDays.length - 1];
    const projectedBalance30Days = lastDay?.projectedBalance ?? currentBalance;

    const totalInflows30Days = cashFlowDays.reduce(
      (sum, day) => sum + day.inflows.reduce((s, i) => s + i.amount, 0),
      0
    );

    const totalOutflows30Days = cashFlowDays.reduce(
      (sum, day) => sum + day.outflows.reduce((s, o) => s + o.amount, 0),
      0
    );

    const criticalDays = cashFlowDays.filter(d => d.isCritical).length;
    const positiveDays = cashFlowDays.filter(d => d.netFlow > 0).length;
    const negativeDays = cashFlowDays.filter(d => d.netFlow < 0).length;

    const averageDailyFlow = (totalInflows30Days - totalOutflows30Days) / 30;

    const nextIncomeDay = cashFlowDays.find(day => day.inflows.length > 0);
    const nextIncomeDate = nextIncomeDay?.date ?? null;

    const committedNext7Days = cashFlowDays
      .slice(0, 7)
      .reduce((sum, day) => sum + day.outflows.reduce((s, o) => s + o.amount, 0), 0);

    const safeToSpend = Math.max(0, currentBalance - committedNext7Days);

    // Calculate burn rate (days until balance reaches zero)
    let burnRate = Infinity;
    if (averageDailyFlow < 0) {
      burnRate = Math.floor(currentBalance / Math.abs(averageDailyFlow));
    }

    return {
      currentBalance,
      projectedBalance30Days,
      totalInflows30Days,
      totalOutflows30Days,
      safeToSpend,
      committedNext7Days,
      nextIncomeDate,
      criticalDays,
      positiveDays,
      negativeDays,
      averageDailyFlow,
      burnRate,
    };
  }, [cashFlowDays, personal.totals.balance]);

  const upcomingCommitments = useMemo((): UpcomingCommitment[] => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const next30 = new Date(today);
    next30.setDate(next30.getDate() + 30);

    const reminderCommitments: UpcomingCommitment[] = reminders
      .filter(r => !r.isPaid)
      .map(r => ({
        id: `reminder-${r.id}`,
        title: r.name,
        amount: r.amount,
        date: r.dueDate,
        source: 'reminder' as const,
        category: r.category,
      }))
      .filter(item => {
        const d = new Date(item.date);
        return d >= today && d <= next30;
      });

    const provisaoCommitments: UpcomingCommitment[] = provisoes
      .map((p: any, index: number) => {
        const currentYear = today.getFullYear();
        let dueDate = new Date(currentYear, Number(p.mes || 1) - 1, 1);
        if (dueDate < today) dueDate = new Date(currentYear + 1, Number(p.mes || 1) - 1, 1);
        const missing = Math.max(0, Number(p.valorAnual || 0) - Number(p.acumulado || 0));
        return {
          id: `provisao-${p.id || index}`,
          title: p.nome || 'Provisão',
          amount: missing,
          date: dueDate.toISOString().split('T')[0]!,
          source: 'provisao' as const,
          category: 'Provisões',
        };
      })
      .filter(item => item.amount > 0)
      .filter(item => {
        const d = new Date(item.date);
        return d >= today && d <= next30;
      });

    const goalCommitments: UpcomingCommitment[] = goals
      .filter(goal => goal.currentAmount < goal.targetAmount)
      .map(goal => ({
        id: `goal-${goal.id}`,
        title: `Meta: ${goal.name}`,
        amount: Math.min(goal.targetAmount - goal.currentAmount, 500),
        date: new Date(today.getFullYear(), today.getMonth() + 1, 1).toISOString().split('T')[0]!,
        source: 'goal' as const,
        category: 'Metas',
      }));

    return [...reminderCommitments, ...provisaoCommitments, ...goalCommitments]
      .sort((a, b) => a.date.localeCompare(b.date))
      .slice(0, 10);
  }, [goals, provisoes, reminders]);

  // Get upcoming bills (next 7 days)
  const upcomingBills = useMemo(() => {
    return cashFlowDays
      .slice(0, 7)
      .filter(day => day.outflows.length > 0)
      .flatMap(day => 
        day.outflows.map(o => ({
          ...o,
          date: day.dateFormatted,
          weekday: day.weekday,
          isToday: day.isToday,
        }))
      )
      .sort((a, b) => a.isToday ? -1 : b.isToday ? 1 : 0);
  }, [cashFlowDays]);

  // Get insights
  const insights = useMemo(() => {
    const result: string[] = [];

    if (summary.criticalDays > 0) {
      result.push(`⚠️ Você tem ${summary.criticalDays} dias críticos nos próximos 30 dias. Planeje-se!`);
    }

    if (summary.safeToSpend < summary.currentBalance * 0.35) {
      result.push(`🛡️ Seu saldo realmente seguro para gastar hoje é ${new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(summary.safeToSpend)}.`);
    }

    if (summary.burnRate < 90 && summary.burnRate !== Infinity) {
      result.push(`🔥 Com o ritmo atual, seu saldo dura apenas ${summary.burnRate} dias.`);
    }

    if (summary.averageDailyFlow < 0) {
      result.push(`📉 Seu fluxo diário médio é negativo: R$ ${Math.abs(summary.averageDailyFlow).toFixed(2)}/dia.`);
    }

    if (summary.positiveDays > summary.negativeDays) {
      result.push(`✅ ${summary.positiveDays} dias positivos vs ${summary.negativeDays} negativos. Continue assim!`);
    }

    const hasSalary = recurringItems.some(i => 
      i.description.toLowerCase().includes('salário') || 
      i.description.toLowerCase().includes('salario')
    );

    if (!hasSalary) {
      result.push(`💡 Não detectamos salário recorrente. Registre sua renda fixa para melhor projeção.`);
    }

    return result;
  }, [summary, recurringItems]);

  return {
    cashFlowDays,
    summary,
    recurringItems,
    upcomingBills,
    upcomingCommitments,
    insights,
  };
}

import { api } from "@/lib/api";
import { showError, showSuccess } from "@/lib/toast";
import { Debt } from "@/types";
import { useEffect, useMemo, useState, useCallback } from "react";

export const useDebts = () => {
  const [debts, setDebts] = useState<Debt[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchDebts = useCallback(async () => {
    let cancelled = false; // ← Flag para cleanup
    setIsLoading(true);
    setError(null);

    try {
      const response = await api.get<any>("/debts");
      if (!cancelled) { // ← Verifica se componente ainda está montado
        const items = Array.isArray(response) ? response : (response?.items || []);
        setDebts(items);
      }
    } catch (err) {
      if (!cancelled) {
        console.error("Debts API Error:", err);
        setError("Dívidas indisponíveis no momento. Verifique sua conexão.");
      }
    } finally {
      if (!cancelled) {
        setIsLoading(false);
      }
    }

    return () => { cancelled = true; }; // ← Cleanup function
  }, []);

  useEffect(() => {
    let cancelled = false;

    const loadData = async () => {
      setIsLoading(true);
      setError(null);

      try {
        const response = await api.get<any>("/debts");
        if (!cancelled) {
          const items = Array.isArray(response) ? response : (response?.items || []);
          setDebts(items);
        }
      } catch (err) {
        if (!cancelled) {
          console.error("Debts API Error:", err);
          setError("Dívidas indisponíveis no momento. Verifique sua conexão.");
        }
      } finally {
        if (!cancelled) {
          setIsLoading(false);
        }
      }
    };

    loadData();

    return () => { cancelled = true; }; // ← Cleanup!
  }, []);

  const addDebt = async (debtData: Omit<Debt, "id">) => {
    try {
      const newDebt = await api.post<Debt>("/debts", debtData);
      setDebts((prev) => [...prev, newDebt]);
      showSuccess("Dívida adicionada com sucesso!");
    } catch (error) {
      showError("Erro ao adicionar dívida.");
    }
  };

  const updateDebt = async (id: string, debtData: Partial<Debt>) => {
    try {
      const updatedDebt = await api.put<Debt>(`/debts/${id}`, debtData);
      setDebts((prev) => prev.map((d) => (d.id === id ? updatedDebt : d)));
      showSuccess("Dívida atualizada!");
    } catch (error) {
      showError("Erro ao atualizar dívida.");
    }
  };

  const deleteDebt = async (id: string) => {
    if (window.confirm("Deseja excluir esta dívida?")) {
      try {
        await api.delete(`/debts/${id}`);
        setDebts((prev) => prev.filter((d) => d.id !== id));
        showSuccess("Dívida excluída!");
      } catch (error) {
        showError("Erro ao excluir dívida.");
      }
    }
  };

  const totals = useMemo(() => {
    const totalBalance = debts.reduce((sum, d) => sum + d.balance, 0);
    const totalMinPayment = debts.reduce((sum, d) => sum + d.minPayment, 0);
    return { totalBalance, totalMinPayment };
  }, [debts]);

  return {
    debts,
    isLoading,
    error,
    addDebt,
    updateDebt,
    deleteDebt,
    totals,
    refresh: fetchDebts,
  };
};

import { useState, useEffect, useCallback } from "react";
import { ACADEMY_CONTEXT_SIGNALS, ACADEMY_MATURITY_STAGES, ACADEMY_MOMENTS, ACADEMY_RITUALS, EDUCATION_MODULES, getLessonAssociatedFeature, getLessonBehaviorGoal, getLessonMaturityStage, getLessonOutcomeType, getLessonTriggerEvents, type Lesson } from "@/data/educationData";
import { showError } from "@/lib/toast";

export interface EducationState {
  completedModules: string[];
  lessonStepProgress: Record<string, number>;
  lessonLastSeenAt: Record<string, string>;
  lessonReviewDueAt: Record<string, string>;
  contextualReinforcements: Record<string, number>;
  xp: number;
  streak: number;
  lastActiveDate: string | null;
}

const DEFAULT_STATE: EducationState = {
  completedModules: [],
  lessonStepProgress: {},
  lessonLastSeenAt: {},
  lessonReviewDueAt: {},
  contextualReinforcements: {},
  xp: 0,
  streak: 0,
  lastActiveDate: null,
};

interface ModuleProgress {
  completedSteps: number;
  totalSteps: number;
  progressPct: number;
  isCompleted: boolean;
  hasStarted: boolean;
  checkpointLabel: string;
}

interface EducationProfileInput {
  hasDebts?: boolean;
  hasEmergencyFund?: boolean;
  financialGoal?: string;
  riskProfile?: string;
  employmentType?: string;
  currentWorkspaceId?: string | null;
  debtBalance?: number;
  goalsCount?: number;
  hasInvestments?: boolean;
}

interface ContextualRecommendation {
  lesson: Lesson | null;
  reason: string;
  actionLabel: string;
  outcome: string;
}

interface ReviewRecommendation {
  lesson: Lesson | null;
  dueAt: string | null;
  reason: string;
}

interface ContextSignalRecommendation {
  signal: (typeof ACADEMY_CONTEXT_SIGNALS)[number] | null;
  lesson: Lesson | null;
  actionLabel: string;
}

const REVIEW_INTERVAL_DAYS = [1, 3, 7, 14, 30];

const normalizeDate = (date: Date) => {
  const normalized = new Date(date);
  normalized.setHours(0, 0, 0, 0);
  return normalized;
};

const addDays = (date: Date, days: number) => {
  const next = new Date(date);
  next.setDate(next.getDate() + days);
  return next;
};

export const useEducation = (profile?: EducationProfileInput) => {
  const [state, setState] = useState<EducationState>(DEFAULT_STATE);
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);

  useEffect(() => {
    setIsLoading(true);
    setError(null);
    try {
      const saved = localStorage.getItem("mc_education");
      if (saved) {
        const parsed = JSON.parse(saved);
        // Simple streak logic
        const targetState = { ...DEFAULT_STATE, ...parsed };

        if (targetState.lastActiveDate) {
          const last = new Date(targetState.lastActiveDate);
          const today = new Date();
          const diffDays = Math.floor((today.getTime() - last.getTime()) / (1000 * 3600 * 24));

          if (diffDays > 1) {
            targetState.streak = 0; // lost streak
          } else if (diffDays === 1) {
            targetState.streak += 1;
            targetState.lastActiveDate = today.toISOString();
          }
        } else {
          targetState.streak = 1;
          targetState.lastActiveDate = new Date().toISOString();
        }

        setState(targetState);
        localStorage.setItem("mc_education", JSON.stringify(targetState));
      } else {
        const init = { ...DEFAULT_STATE, lastActiveDate: new Date().toISOString(), streak: 1 };
        setState(init);
        localStorage.setItem("mc_education", JSON.stringify(init));
      }
    } catch (e: any) {
      console.error(e);
      setError("Erro interno ao carregar o seu avanço educacional: " + e.message);
      showError("Não foi possível carregar as aulas.");
      setState(DEFAULT_STATE);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const completeModule = useCallback((moduleId: string) => {
    try {
      setError(null);
      setState((prev) => {
        if (prev.completedModules.includes(moduleId)) return prev;

        const mod = EDUCATION_MODULES.find(m => m.id === moduleId);
        const reward = mod?.xp || 50;
        const totalSteps = mod?.passos.length || 0;
        const nowIso = new Date().toISOString();
        const reinforcementCount = (prev.contextualReinforcements[moduleId] || 0) + 1;
        const reviewInterval: number = REVIEW_INTERVAL_DAYS[Math.max(0, Math.min(reinforcementCount - 1, REVIEW_INTERVAL_DAYS.length - 1))] ?? 1;

        const newState = {
          ...prev,
          completedModules: [...prev.completedModules, moduleId],
          lessonStepProgress: {
            ...prev.lessonStepProgress,
            [moduleId]: totalSteps,
          },
          lessonLastSeenAt: {
            ...prev.lessonLastSeenAt,
            [moduleId]: nowIso,
          },
          lessonReviewDueAt: {
            ...prev.lessonReviewDueAt,
            [moduleId]: addDays(new Date(), reviewInterval).toISOString(),
          },
          contextualReinforcements: {
            ...prev.contextualReinforcements,
            [moduleId]: reinforcementCount,
          },
          xp: prev.xp + reward,
          lastActiveDate: nowIso,
        };

        localStorage.setItem("mc_education", JSON.stringify(newState));
        return newState;
      });
    } catch (e: any) {
      const msg = "Erro crítico ao tentar aprovar sua aula: " + e.message;
      console.error(msg);
      setError(msg);
      showError("Falha ao salvar progresso educativo!");
    }
  }, []);

  const saveLessonProgress = useCallback((moduleId: string, completedSteps: number) => {
    try {
      setError(null);
      setState((prev) => {
        const mod = EDUCATION_MODULES.find(m => m.id === moduleId);
        const totalSteps = mod?.passos.length || 0;
        const safeCompletedSteps = Math.max(0, Math.min(completedSteps, totalSteps));
        const previousCompletedSteps = prev.lessonStepProgress[moduleId] || 0;

        if (safeCompletedSteps <= previousCompletedSteps) {
          return prev;
        }

        const nextCompletedModules =
          safeCompletedSteps >= totalSteps && totalSteps > 0 && !prev.completedModules.includes(moduleId)
            ? [...prev.completedModules, moduleId]
            : prev.completedModules;
        const nowIso = new Date().toISOString();

        const newState = {
          ...prev,
          completedModules: nextCompletedModules,
          lessonStepProgress: {
            ...prev.lessonStepProgress,
            [moduleId]: safeCompletedSteps,
          },
          lessonLastSeenAt: {
            ...prev.lessonLastSeenAt,
            [moduleId]: nowIso,
          },
          lastActiveDate: nowIso,
        };

        localStorage.setItem("mc_education", JSON.stringify(newState));
        return newState;
      });
    } catch (e: any) {
      const msg = "Erro ao salvar checkpoint da aula: " + e.message;
      console.error(msg);
      setError(msg);
    }
  }, []);

  const isModuleCompleted = useCallback((moduleId: string) => state.completedModules.includes(moduleId), [state.completedModules]);

  const getModuleProgress = useCallback((moduleId: string): ModuleProgress => {
    const module = EDUCATION_MODULES.find((item) => item.id === moduleId);
    const totalSteps = module?.passos.length || 0;
    const completedSteps = Math.max(0, Math.min(state.lessonStepProgress[moduleId] || 0, totalSteps));
    const isCompleted = state.completedModules.includes(moduleId) || (totalSteps > 0 && completedSteps >= totalSteps);
    const hasStarted = completedSteps > 0;
    const progressPct = totalSteps > 0 ? Math.round((completedSteps / totalSteps) * 100) : 0;

    return {
      completedSteps,
      totalSteps,
      progressPct,
      isCompleted,
      hasStarted,
      checkpointLabel: isCompleted
        ? "Módulo concluído"
        : hasStarted
          ? `Checkpoint salvo · passo ${Math.min(completedSteps + 1, totalSteps)}/${totalSteps}`
          : "Ainda não iniciado",
    };
  }, [state.completedModules, state.lessonStepProgress]);

  const getProgressPct = useCallback(() => {
    const totalSteps = EDUCATION_MODULES.reduce((acc, module) => acc + module.passos.length, 0);
    const completedSteps = EDUCATION_MODULES.reduce((acc, module) => {
      const moduleProgress = state.lessonStepProgress[module.id] || 0;
      return acc + Math.min(moduleProgress, module.passos.length);
    }, 0);

    return totalSteps === 0 ? 0 : Math.round((completedSteps / totalSteps) * 100);
  }, [state.lessonStepProgress]);

  const getNextRecommendedLesson = useCallback((preferredTrailId?: string) => {
    if (preferredTrailId) {
      const preferredLesson = EDUCATION_MODULES.find(
        (module) => module.trilha === preferredTrailId && !state.completedModules.includes(module.id)
      );

      if (preferredLesson) return preferredLesson;
    }

    return EDUCATION_MODULES.find((module) => !state.completedModules.includes(module.id)) || null;
  }, [state.completedModules]);

  const getReviewRecommendation = useCallback((): ReviewRecommendation => {
    const today = normalizeDate(new Date());

    const dueLesson = EDUCATION_MODULES
      .filter((lesson) => state.completedModules.includes(lesson.id))
      .map((lesson) => ({ lesson, dueAt: state.lessonReviewDueAt[lesson.id] }))
      .filter((item) => !!item.dueAt)
      .sort((a, b) => new Date(a.dueAt || 0).getTime() - new Date(b.dueAt || 0).getTime())
      .find((item) => normalizeDate(new Date(item.dueAt || new Date())).getTime() <= today.getTime());

    if (!dueLesson) {
      return {
        lesson: null,
        dueAt: null,
        reason: 'Nenhuma revisão crítica vencida agora. Siga a próxima lição ou mantenha o ritual financeiro.',
      };
    }

    return {
      lesson: dueLesson.lesson,
      dueAt: dueLesson.dueAt || null,
      reason: 'Seu cérebro retém melhor quando revê o conceito no momento certo. Esta revisão está vencida.',
    };
  }, [state.completedModules, state.lessonReviewDueAt]);

  const getContextualRecommendation = useCallback((): ContextualRecommendation => {
    const activeTriggers: string[] = [];

    if (profile?.hasDebts) activeTriggers.push('fatura_alta', 'divida_cara');
    if ((profile?.debtBalance || 0) > 0) activeTriggers.push('divida_cara');
    if (!profile?.hasEmergencyFund) activeTriggers.push('sem_reserva', 'mes_apertado');
    if (profile?.employmentType && ['autonomo', 'freelancer', 'pj', 'mei'].includes(profile.employmentType)) {
      activeTriggers.push('aumento_de_renda', 'organizar_rotina');
    }
    if (profile?.currentWorkspaceId && profile.currentWorkspaceId !== 'personal') {
      activeTriggers.push('familia_dependente', 'organizar_rotina');
    }
    if (profile?.financialGoal === 'invest' || profile?.financialGoal === 'retire') {
      activeTriggers.push('primeiro_aporte', 'planejamento_aposentadoria');
    }
    if ((profile?.goalsCount || 0) > 0) {
      activeTriggers.push('iniciar_planejamento');
    }
    if (profile?.hasInvestments && !profile?.hasEmergencyFund) {
      activeTriggers.push('sem_reserva', 'primeiro_aporte');
    }

    const incompleteLessons = EDUCATION_MODULES.filter((module) => !state.completedModules.includes(module.id));

    const scoredLessons = incompleteLessons.map((lesson) => {
      const triggerScore = getLessonTriggerEvents(lesson).filter((trigger) => activeTriggers.includes(trigger)).length;
      const stage = getLessonMaturityStage(lesson);
      const maturityScore = ['sobreviver', 'estabilizar', 'proteger', 'organizar'].includes(stage) ? 3 : 1;
      const businessBoost = (profile?.employmentType && ['autonomo', 'freelancer', 'pj', 'mei'].includes(profile.employmentType) && ['contabilidade', 'tributario'].includes(getLessonOutcomeType(lesson))) ? 3 : 0;
      const protectionBoost = (!profile?.hasEmergencyFund && ['divida', 'reserva', 'caixa'].includes(getLessonOutcomeType(lesson))) ? 4 : 0;

      return {
        lesson,
        score: triggerScore * 5 + maturityScore + businessBoost + protectionBoost,
      };
    }).sort((a, b) => b.score - a.score);

    const firstLessonMatch = scoredLessons[0];
    const contextMatch = (firstLessonMatch && firstLessonMatch.score > 0) ? firstLessonMatch.lesson : null;

    const fallback = incompleteLessons[0] || null;
    const selected = contextMatch || fallback;

    if (!selected) {
      return {
        lesson: null,
        reason: 'Você concluiu a jornada principal da Academia.',
        actionLabel: 'Revisar conteúdos avançados',
        outcome: 'maestria',
      };
    }

    const outcome = getLessonOutcomeType(selected);

    const reason = contextMatch
      ? 'Recomendação baseada no seu momento financeiro atual.'
      : 'Próximo passo sugerido para manter evolução consistente.';

    const actionLabel = outcome === 'divida'
      ? 'Corrigir antes que vire juro'
      : outcome === 'reserva'
        ? 'Proteger sua base'
        : outcome === 'contabilidade' || outcome === 'tributario'
          ? 'Organizar operação e impostos'
          : 'Avançar na jornada';

    return {
      lesson: selected,
      reason,
      actionLabel,
      outcome,
    };
  }, [profile?.currentWorkspaceId, profile?.debtBalance, profile?.employmentType, profile?.financialGoal, profile?.goalsCount, profile?.hasDebts, profile?.hasEmergencyFund, profile?.hasInvestments, state.completedModules]);

  const getCurrentMoment = useCallback(() => {
    const contextual = getContextualRecommendation();
    const recommendedLesson = contextual.lesson;

    if (recommendedLesson) {
      const directMoment = ACADEMY_MOMENTS.find((moment) => moment.lessonIds.includes(recommendedLesson.id));
      if (directMoment) return directMoment;

      const byOutcome = ACADEMY_MOMENTS.find((moment) => moment.outcomeFocus.includes(getLessonOutcomeType(recommendedLesson)));
      if (byOutcome) return byOutcome;
    }

    return ACADEMY_MOMENTS[0];
  }, [getContextualRecommendation]);

  const getCurrentRituals = useCallback(() => {
    const contextual = getContextualRecommendation();
    const rituals = [...ACADEMY_RITUALS];

    if (contextual.lesson && ['contabilidade', 'tributario'].includes(getLessonOutcomeType(contextual.lesson))) {
      return rituals.reverse();
    }

    return rituals;
  }, [getContextualRecommendation]);

  const getContextSignalRecommendation = useCallback((): ContextSignalRecommendation => {
    const activeTriggers: string[] = [];

    if (profile?.hasDebts) activeTriggers.push('fatura_alta', 'divida_cara');
    if ((profile?.debtBalance || 0) > 0) activeTriggers.push('divida_cara');
    if (!profile?.hasEmergencyFund) activeTriggers.push('sem_reserva', 'mes_apertado');
    if (profile?.employmentType && ['autonomo', 'freelancer', 'pj', 'mei'].includes(profile.employmentType)) {
      activeTriggers.push('negocio_sem_separacao', 'imposto_sem_reserva', 'organizar_rotina');
    }
    if (profile?.hasInvestments || profile?.financialGoal === 'invest' || profile?.financialGoal === 'retire') {
      activeTriggers.push('primeiro_aporte', 'diversificacao');
    }

    const signal = ACADEMY_CONTEXT_SIGNALS.find((item) => item.eventKeys.some((key) => activeTriggers.includes(key))) || null;
    const lesson = signal ? EDUCATION_MODULES.find((item) => item.id === signal.primaryLessonId) || null : null;

    return {
      signal,
      lesson,
      actionLabel: lesson ? 'Abrir aula acionada' : 'Seguir jornada',
    };
  }, [profile?.debtBalance, profile?.employmentType, profile?.financialGoal, profile?.hasDebts, profile?.hasEmergencyFund, profile?.hasInvestments]);

  const getJourneyStage = useCallback(() => {
    const completedStages = EDUCATION_MODULES
      .filter((lesson) => state.completedModules.includes(lesson.id))
      .map((lesson) => getLessonMaturityStage(lesson));

    if (!completedStages.includes('sobreviver')) {
      return {
        id: 'fundacao',
        title: 'Sobreviver ao Brasil',
        description: 'Aprenda a proteger caixa, fatura, reserva mínima e decisões urgentes do mês.',
      };
    }

    if (!completedStages.includes('organizar')) {
      return {
        id: 'construcao',
        title: 'Organizar e estabilizar',
        description: 'Construa rotina, provisões, disciplina e leitura real do dinheiro.',
      };
    }

    if (!completedStages.includes('crescer')) {
      return {
        id: 'expansao',
        title: 'Crescer com inteligência',
        description: 'Com base pronta, avance para diversificação, renda ativa e patrimônio.',
      };
    }

    return {
      id: 'maestria',
      title: 'Blindar e perpetuar',
      description: 'Aprofunde proteção patrimonial, sucessão, FIRE e decisões de longo prazo.',
    };
  }, [state.completedModules]);

  const getMaturityRoadmap = useCallback(() => {
    return ACADEMY_MATURITY_STAGES.map((stage) => {
      const lessons = EDUCATION_MODULES.filter((lesson) => getLessonMaturityStage(lesson) === stage.id);
      const completed = lessons.filter((lesson) => state.completedModules.includes(lesson.id)).length;
      const progressPct = lessons.length ? Math.round((completed / lessons.length) * 100) : 0;

      return {
        ...stage,
        lessons: lessons.length,
        completed,
        progressPct,
        topOutcome: lessons[0] ? getLessonOutcomeType(lessons[0]) : 'caixa',
      };
    });
  }, [state.completedModules]);

  const getTutorContext = useCallback(() => {
    const recommendation = getContextualRecommendation();
    const signal = getContextSignalRecommendation();
    const currentMoment = getCurrentMoment();
    const journeyStage = getJourneyStage();

    return {
      currentMoment,
      journeyStage,
      recommendation,
      contextSignal: signal,
      learningFocus: recommendation.lesson
        ? {
            title: recommendation.lesson.title,
            outcome: getLessonOutcomeType(recommendation.lesson),
            behaviorGoal: getLessonBehaviorGoal(recommendation.lesson),
            feature: getLessonAssociatedFeature(recommendation.lesson),
          }
        : null,
    };
  }, [getContextSignalRecommendation, getContextualRecommendation, getCurrentMoment, getJourneyStage]);

  return {
    state,
    error,
    isLoading,
    completeModule,
    saveLessonProgress,
    isModuleCompleted,
    getModuleProgress,
    getProgressPct,
    getNextRecommendedLesson,
    getContextualRecommendation,
    getReviewRecommendation,
    getCurrentMoment,
    getCurrentRituals,
    getContextSignalRecommendation,
    getJourneyStage,
    getMaturityRoadmap,
    getTutorContext,
  };
};

import { useTransactions } from "@/hooks/useTransactions";
import { loadBudgets } from "@/lib/storage";
import { useMemo } from "react";

export interface FinancialAlert {
  id: string;
  type: "warning" | "danger" | "info" | "success";
  title: string;
  message: string;
  action?: string;
}

export const useFinancialAlerts = () => {
  const { transactions, totals, categoryData } = useTransactions("personal");
  const budgets = useMemo(() => loadBudgets(), []);

  const alerts = useMemo(() => {
    const list: FinancialAlert[] = [];

    // 1. Budget Alerts
    budgets.forEach(budget => {
      const categoryTotal = categoryData.find(c => c.name === budget.category)?.despesas || 0;
      const usage = (categoryTotal / budget.limit) * 100;

      if (usage >= 100) {
        list.push({
          id: `budget-over-${budget.category}`,
          type: "danger",
          title: "Orçamento Excedido!",
          message: `Você ultrapassou o limite de ${budget.category}. Considere pausar gastos nessa categoria.`,
        });
      } else if (usage >= 80) {
        list.push({
          id: `budget-near-${budget.category}`,
          type: "warning",
          title: "Alerta de Orçamento",
          message: `Você atingiu ${usage.toFixed(0)}% do limite de ${budget.category}.`,
        });
      }
    });

    // 2. Balance / Deficit Alerts
    if (totals.expense > totals.income && totals.income > 0) {
      list.push({
        id: "deficit-alert",
        type: "danger",
        title: "Atenção: Déficit Mensal",
        message: "Seus gastos este mês superaram sua renda. Recomendo auditar seus 'Desejos' imediatamente.",
      });
    }

    // 3. Savings Rate Logic
    const savingsRate = totals.income > 0 ? (totals.balance / totals.income) * 100 : 0;
    if (savingsRate >= 20) {
      list.push({
        id: "savings-star",
        type: "success",
        title: "Desempenho Estelar!",
        message: `Sua taxa de poupança está em ${savingsRate.toFixed(0)}%. Você está no caminho da liberdade financeira.`,
      });
    } else if (savingsRate < 5 && totals.income > 0) {
       list.push({
         id: "savings-low",
         type: "info",
         title: "Dica do Contador",
         message: "Sua taxa de poupança está abaixo de 5%. Tente automatizar um investimento de pelo menos 10% no início do mês.",
       });
    }

    return list;
  }, [transactions, totals, categoryData, budgets]);

  return { alerts };
};

import { api } from "@/lib/api";
import { showError, showSuccess } from "@/lib/toast";
import type { SavingsGoal } from "@/types";
import { useEffect, useState, useCallback } from "react";

export const useGoals = () => {
  const [goals, setGoals] = useState<SavingsGoal[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchGoals = useCallback(async () => {
    let cancelled = false; // ← Flag para cleanup
    setLoading(true);
    setError(null);

    try {
      const response = await api.get<any>("/goals");
      if (!cancelled) { // ← Verifica se componente ainda está montado
        const items = Array.isArray(response) ? response : (response?.items || []);
        setGoals(items);
      }
    } catch (err) {
      if (!cancelled) {
        setError("Metas de economia indisponíveis. Verifique sua conexão.");
      }
    } finally {
      if (!cancelled) {
        setLoading(false);
      }
    }

    return () => { cancelled = true; }; // ← Cleanup function
  }, []);

  useEffect(() => {
    let cancelled = false;

    const loadData = async () => {
      setLoading(true);
      setError(null);

      try {
        const response = await api.get<any>("/goals");
        if (!cancelled) {
          const items = Array.isArray(response) ? response : (response?.items || []);
          setGoals(items);
        }
      } catch (err) {
        if (!cancelled) {
          setError("Metas de economia indisponíveis. Verifique sua conexão.");
        }
      } finally {
        if (!cancelled) {
          setLoading(false);
        }
      }
    };

    loadData();

    return () => { cancelled = true; }; // ← Cleanup!
  }, []);

  const addGoal = async (goal: Omit<SavingsGoal, "id">) => {
    try {
      const newGoal = await api.post<SavingsGoal>("/goals", goal);
      setGoals((prev) => [...prev, newGoal]);
      showSuccess("Meta criada!");
    } catch (error) {
      showError("Erro ao criar meta.");
    }
  };

  const updateGoalProgress = async (id: string, currentAmount: number) => {
    try {
      await api.patch(`/goals/${id}`, { currentAmount });
      setGoals((prev) =>
        prev.map((g) => (g.id === id ? { ...g, currentAmount } : g))
      );
    } catch (error) {
      showError("Erro ao atualizar progresso.");
    }
  };

  const editGoal = async (id: string, updates: Partial<SavingsGoal>) => {
    try {
      await api.patch(`/goals/${id}`, updates);
      setGoals((prev) =>
        prev.map((g) => (g.id === id ? { ...g, ...updates } : g))
      );
      showSuccess("Meta atualizada!");
    } catch (error) {
      showError("Erro ao atualizar meta.");
    }
  };

  const deleteGoal = async (id: string) => {
    try {
      await api.delete(`/goals/${id}`);
      setGoals((prev) => prev.filter((g) => g.id !== id));
      showSuccess("Meta removida.");
    } catch (error) {
      showError("Erro ao remover meta.");
    }
  };

  return {
    goals,
    loading,
    error,
    addGoal,
    updateGoalProgress,
    editGoal,
    deleteGoal,
    refresh: fetchGoals,
  };
};

import { api } from "@/lib/api";
import { getStockQuote } from "@/lib/api/brapi";
import { showError, showSuccess } from "@/lib/toast";
import { logAction } from "@/lib/audit-service";
import type {
  Dividend,
  Investment,
  InvestmentWithRelations,
  TaxIndicator,
  Currency,
} from "@/types";
import { useAuth } from "@/context/AuthContext";
import { useEffect, useState, useCallback } from "react";

export const useInvestments = () => {
  const { setGlobalLoading, user } = useAuth();
  const currentWorkspaceId = user?.currentWorkspaceId || user?.uid || "";
  const [assets, setAssets] = useState<Investment[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchInvestments = useCallback(async () => {
    setLoading(true);
    setGlobalLoading(true);
    setError(null);

    try {
      const response = await api.get<any>("/investments");
      const items = Array.isArray(response) ? response : (response?.items || []);
      setAssets(items);
    } catch (err) {
      console.error("Investments API Error:", err);
      setError("Investimentos indisponíveis no momento. Tente novamente mais tarde.");
    } finally {
      setLoading(false);
      setGlobalLoading(false);
    }
  }, [setGlobalLoading]);

  useEffect(() => {
    fetchInvestments();
  }, [fetchInvestments]);

  const addAsset = async (asset: Omit<Investment, "id" | "lastUpdate">) => {
    try {
      const newAsset = await api.post<Investment>("/investments", asset);
      setAssets((prev) => [...prev, newAsset]);
      
      if (currentWorkspaceId) {
        logAction(currentWorkspaceId, "CREATE_INVESTMENT", `Novo Ativo: ${asset.ticker} (${asset.amount} un)`);
      }
      
      showSuccess("Ativo cadastrado com sucesso!");
    } catch (error) {
      showError("Erro ao cadastrar ativo.");
    }
  };

  const deleteAsset = async (id: string) => {
    try {
      const asset = assets.find(a => a.id === id);
      await api.delete(`/investments/${id}`);
      setAssets((prev) => prev.filter((a) => a.id !== id));
      
      if (currentWorkspaceId && asset) {
        logAction(currentWorkspaceId, "DELETE_TRANSACTION", `Removido Ativo: ${asset.ticker}`);
      }
      
      showSuccess("Ativo removido.");
    } catch (error) {
      showError("Erro ao remover ativo.");
    }
  };

  const addDividend = async (investmentId: string, dividend: Omit<Dividend, "id" | "assetId" | "assetTicker">) => {
    try {
      await api.post(`/investments/${investmentId}/dividends`, dividend);
      await fetchInvestments(); // Refresh to get updated nested data
      showSuccess("Provento registrado!");
    } catch (error) {
      showError("Erro ao registrar provento.");
    }
  };

  const deleteDividend = async (investmentId: string, dividendId: string) => {
    try {
      await api.delete(`/investments/${investmentId}/dividends/${dividendId}`);
      await fetchInvestments();
      showSuccess("Provento removido!");
    } catch (error) {
      showError("Erro ao remover provento.");
    }
  };

  const addSale = async (investmentId: string, sale: { amount: number; price: number; date: string }) => {
    try {
      await api.post(`/investments/${investmentId}/sales`, sale);
      await fetchInvestments(); // Refresh to get updated quantity
      
      const asset = assets.find(a => a.id === investmentId);
      if (currentWorkspaceId && asset) {
        logAction(currentWorkspaceId, "SALE_INVESTMENT", `Venda: ${asset.ticker} (${sale.amount} un)`);
      }
      
      showSuccess("Venda registrada!");
    } catch (error) {
      showError("Erro ao registrar venda.");
    }
  };

  const getTaxIndicators = (
    convert: (amount: number, from: Currency, to: Currency) => number
  ): TaxIndicator[] => {
    // Collect all sales from all assets
    const allSales = (assets as InvestmentWithRelations[]).flatMap(
      (a) => a.sales ?? []
    );

    const monthlySales = allSales.reduce((acc, curr) => {
      const valueInBRL = convert(curr.totalValue, curr.currency || "BRL", "BRL");
      const month = new Date(curr.date).toISOString().substring(0, 7);
      acc[month] = (acc[month] || 0) + valueInBRL;
      return acc;
    }, {} as Record<string, number>);

    return Object.entries(monthlySales).map(([month, total]) => ({
      month,
      totalStockSales: total as number,
      isOverLimit: (total as number) > 20000,
      estimatedTax: (total as number) > 20000 ? (total as number) * 0.15 : 0,
    }));
  };

  const updateAsset = async (id: string, updates: Partial<Investment>) => {
    try {
      const updated = await api.put<Investment>(`/investments/${id}`, updates);
      setAssets((prev) => prev.map((a) => (a.id === id ? updated : a)));
      showSuccess("Ativo atualizado!");
    } catch (error) {
      showError("Erro ao atualizar ativo.");
    }
  };

  const syncPrices = async (
    token: string = ""
  ) => {
    if (!token || token === "YOUR_TOKEN_HERE") {
      showError("API Key necessária.");
      return;
    }

    setLoading(true);
    try {
      const updatedAssets = await Promise.all(
        assets.map(async (asset) => {
          if (asset.type === "stock" || asset.type === "fii") {
            const quote = await getStockQuote(asset.ticker, token);
            if (quote) {
              return {
                ...asset,
                currentPrice: quote.regularMarketPrice,
                name: quote.shortName || asset.name,
              };
            }
          }
          return asset;
        })
      );

      // In a real enterprise app, we'd send these updates to the backend
      // For now, we update local state and notify success
      setAssets(updatedAssets);
      showSuccess("Cotações atualizadas!");
    } catch (e) {
      showError("Erro ao sincronizar preços.");
    } finally {
      setLoading(false);
    }
  };

  const totals = {
    currentValue: assets.reduce(
      (sum, a) => sum + (a.currentPrice || a.averagePrice) * a.amount,
      0
    ),
    totalInvested: assets.reduce(
      (sum, a) => sum + a.averagePrice * a.amount,
      0
    ),
    totalDividends: (assets as InvestmentWithRelations[]).reduce(
      (sum, a) => sum + (a.dividends ?? []).reduce((s, d) => s + d.amount, 0),
      0
    ),
  };

  const dividends = (assets as InvestmentWithRelations[]).flatMap((a) =>
    (a.dividends || []).map((d) => ({
      ...d,
      assetId: a.id.toString(),
      assetTicker: a.ticker,
    }))
  );

  return {
    assets,
    loading,
    error,
    totals,
    addAsset,
    deleteAsset,
    addDividend,
    addSale,
    updateAsset,
    getTaxIndicators,
    syncPrices,
    dividends,
    deleteDividend,
  };
};

import { api } from "@/lib/api";
import { showError, showSuccess } from "@/lib/toast";
import type { Invoice } from "@/types";
import { useEffect, useState, useCallback } from "react";

export const useInvoices = () => {
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchInvoices = useCallback(async () => {
    let cancelled = false;
    setIsLoading(true);
    setError(null);
    try {
      const response = await api.get<any>("/invoices");
      const items = Array.isArray(response) ? response : (response?.items || []);
      if (!cancelled) setInvoices(items);
    } catch (err) {
      if (!cancelled) {
        setError("Falha ao carregar as notas fiscais.");
        showError("Falha ao carregar as notas fiscais.");
      }
    } finally {
      if (!cancelled) setIsLoading(false);
    }
    return () => { cancelled = true; };
  }, []);

  useEffect(() => {
    const cancel = fetchInvoices();
    return () => { cancel.then(c => c()); };
  }, [fetchInvoices]);

  const addInvoice = useCallback(async (invoice: Omit<Invoice, "id">) => {
    try {
      setError(null);
      // Backend automatically creates the invoice with a UUID and parses the date
      const newInvoice = await api.post<Invoice>("/invoices", invoice);
      setInvoices(prev => [...prev, newInvoice]);
      showSuccess(`Nota Fiscal ${invoice.number} cadastrada!`);
    } catch (error) {
      const msg = "Erro ao cadastrar nota fiscal.";
      setError(msg);
      showError(msg);
    }
  }, []);

  const updateInvoice = useCallback(async (id: string, updates: Partial<Invoice>) => {
    try {
      setError(null);
      const updatedInvoice = await api.put<Invoice>(`/invoices/${id}`, updates);
      setInvoices(prev => prev.map(inv => inv.id === id ? updatedInvoice : inv));
      showSuccess("Nota Fiscal atualizada.");
    } catch (error) {
      const msg = "Erro ao atualizar a nota fiscal.";
      setError(msg);
      showError(msg);
    }
  }, []);

  const deleteInvoice = useCallback(async (id: string) => {
    if (window.confirm("Deseja realmente excluir esta nota?")) {
      try {
        setError(null);
        await api.delete(`/invoices/${id}`);
        setInvoices(prev => prev.filter(inv => inv.id !== id));
        showSuccess("Nota Fiscal excluída.");
      } catch (error) {
        const msg = "Erro crítico ao excluir a nota fiscal.";
        setError(msg);
        showError(msg);
      }
    }
  }, []);

  return {
    invoices,
    isLoading,
    error,
    addInvoice,
    updateInvoice,
    deleteInvoice,
    refresh: fetchInvoices
  };
};

