    let cancelled = false; // ← Flag para cleanup
    setIsLoading(true);
    setError(null);

    try {
      const data = await pluggyCircuitBreaker.call(
        async () => api.get<PaginatedConnectionsResponse>('/open-finance/connections'),
        () => ({ items: [], total: 0, page: 1, limit: 20, totalPages: 0 })
      );
      if (!cancelled) { // ← Verifica se componente ainda está montado
        setConnections(data.items);
      }
    } catch (err: any) {
      if (!cancelled) {
        console.error('Error fetching bank connections:', err);
        setError(err.message || 'Erro ao carregar conexões bancárias');
      }
    } finally {
      if (!cancelled) {
        setIsLoading(false);
      }
    }

    return () => { cancelled = true; }; // ← Cleanup function
  }, []);

  const getConnectToken = async (itemId?: string) => {
    try {
      const url = itemId ? `/open-finance/token?itemId=${itemId}` : '/open-finance/token';
      const data = await pluggyCircuitBreaker.call(
        async () => api.get<{ accessToken: string }>(url),
        () => { throw new Error('Pluggy temporariamente indisponível'); }
      );
      return data.accessToken;
    } catch (err: any) {
      console.error('Error getting connect token:', err);
      throw new Error(err.message || 'Erro ao gerar token do Pluggy');
    }
  };

  const forceSync = async (itemId: string) => {
    try {
      await api.post(`/open-finance/sync/${itemId}`, {});
      await fetchConnections(); // Refresh
      return true;
    } catch (err: any) {
      console.error('Error syncing connection:', err);
      throw new Error(err.message || 'Erro ao forçar sincronização');
    }
  };

  return {
    connections,
    isLoading,
    error,
    fetchConnections,
    getConnectToken,
    forceSync
  };
};

import { api } from "@/lib/api";
import { showError, showSuccess } from "@/lib/toast";
import { logAction } from "@/lib/audit-service";
import { useAuth } from "@/context/AuthContext";
import type {
  CategoryChartData,
  ChartDataItem,
  MonthlyData,
  Transaction,
  TransactionFormData,
} from "@/types";
import { useEffect, useMemo, useState, useCallback } from "react";

export const useTransactions = (
  scope: "personal" | "business" = "personal"
) => {
  const { user } = useAuth();
  const currentWorkspaceId = user?.currentWorkspaceId || user?.uid || "";
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [filter, setFilter] = useState<"all" | "income" | "expense">("all");
  const [dateFilter, setDateFilter] = useState<string>("month");
  const [searchTerm, setSearchTerm] = useState("");
  const [error, setError] = useState<string | null>(null);

  const fetchTransactions = useCallback(async () => {
    if (!user) return; // Don't fetch if not logged in

    let cancelled = false; // ← Flag para cleanup
    setIsLoading(true);
    setError(null);

    try {
      const response = await api.get<any>(`/transactions?scope=${scope}`);
      if (!cancelled) { // ← Verifica se componente ainda está montado
        const items = Array.isArray(response) ? response : (response?.items || []);
        setTransactions(items);
      }
    } catch (err) {
      if (!cancelled) {
        console.error("Transactions API Error:", err);
        setError("Não foi possível conectar ao servidor. Verifique sua conexão.");
      }
    } finally {
      if (!cancelled) {
        setIsLoading(false);
      }
    }

    return () => { cancelled = true; }; // ← Cleanup function
  }, [scope, user]);

  useEffect(() => {
    let cancelled = false;

    const loadData = async () => {
      if (!user) {
        setIsLoading(false);
        return;
      }

      setIsLoading(true);
      setError(null);

      try {
        const response = await api.get<any>(`/transactions?scope=${scope}`);
        if (!cancelled) {
          const items = Array.isArray(response) ? response : (response?.items || []);
          setTransactions(items);
        }
      } catch (err) {
        if (!cancelled) {
          console.error("Transactions API Error:", err);
          setError("Não foi possível conectar ao servidor. Verifique sua conexão.");
        }
      } finally {
        if (!cancelled) {
          setIsLoading(false);
        }
      }
    };

    loadData();

    const handleRefresh = () => { loadData(); };
    window.addEventListener("transaction-updated", handleRefresh);

    return () => { 
      cancelled = true; 
      window.removeEventListener("transaction-updated", handleRefresh);
    }; // ← Cleanup!
  }, [scope, user?.uid]);

  const addTransaction = async (formData: TransactionFormData) => {
    try {
      const payload = {
        ...formData,
        amount: parseFloat(formData.amount),
        scope: formData.scope || scope,
      };
      const newTransaction = await api.post<Transaction>("/transactions", payload);
      setTransactions((prev) => [newTransaction, ...prev]);

      if (currentWorkspaceId) {
        logAction(currentWorkspaceId, "CREATE_TRANSACTION", `${payload.type === 'income' ? 'Receita' : 'Despesa'}: ${payload.description} (R$ ${payload.amount})`);
      }

      showSuccess("Transação adicionada com sucesso!");
      return newTransaction;
    } catch (error) {
      showError("Erro ao adicionar transação. Verifique o servidor.");
      throw error;
    }
  };

  const updateTransaction = async (id: string, formData: TransactionFormData) => {
    try {
      const payload = {
        ...formData,
        amount: parseFloat(formData.amount),
        scope: formData.scope || scope,
      };
      const updatedTransaction = await api.put<Transaction>(`/transactions/${id}`, payload);
      setTransactions((prev) =>
        prev.map((t) => (t.id === id ? updatedTransaction : t))
      );

      if (currentWorkspaceId) {
        logAction(currentWorkspaceId, "UPDATE_TRANSACTION", `Editado: ${payload.description}`);
      }

      showSuccess("Transação atualizada com sucesso!");
    } catch (error) {
      showError("Erro ao atualizar transação.");
    }
  };

  const deleteTransaction = async (id: string) => {
    if (window.confirm("Deseja realmente excluir esta transação?")) {
      try {
        const deleted = transactions.find(t => t.id === id);
        await api.delete(`/transactions/${id}`);
        setTransactions((prev) => prev.filter((t) => t.id !== id));

        if (currentWorkspaceId && deleted) {
          logAction(currentWorkspaceId, "DELETE_TRANSACTION", `Removido: ${deleted.description}`);
        }

        showSuccess("Transação excluída com sucesso!");
      } catch (error) {
        showError("Erro ao excluir transação.");
      }
    }
  };

  const filteredTransactions = useMemo(() => {
    let filtered = [...transactions];

    if (filter !== "all") {
      filtered = filtered.filter((t) => t.type === filter);
    }

    if (dateFilter !== "all") {
      const now = new Date();
      const startDate = new Date();

      if (dateFilter === "today") {
        startDate.setHours(0, 0, 0, 0);
      } else if (dateFilter === "week") {
        startDate.setDate(now.getDate() - 7);
      } else if (dateFilter === "month") {
        startDate.setMonth(now.getMonth() - 1);
      } else if (dateFilter === "year") {
        startDate.setFullYear(now.getFullYear() - 1);
      }

      filtered = filtered.filter((t) => new Date(t.date) >= startDate);
    }

    if (searchTerm) {
      filtered = filtered.filter(
        (t) =>
          t.description.toLowerCase().includes(searchTerm.toLowerCase()) ||
          t.category.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    return filtered.sort(
      (a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()
    );
  }, [transactions, filter, dateFilter, searchTerm]);

  const totals = useMemo(() => {
    const income = filteredTransactions
      .filter((t) => t.type === "income")
      .reduce((sum, t) => sum + t.amount, 0);
    const expense = filteredTransactions
      .filter((t) => t.type === "expense")
      .reduce((sum, t) => sum + t.amount, 0);
    return { income, expense, balance: income - expense };
  }, [filteredTransactions]);

  const categoryData = useMemo((): CategoryChartData[] => {
    const categoryTotals: Record<string, { income: number; expense: number }> =
      {};

    filteredTransactions.forEach((t) => {
      if (!categoryTotals[t.category]) {
        categoryTotals[t.category] = { income: 0, expense: 0 };
      }
      if (t.type === "income") {
        const entry = categoryTotals[t.category];
        if (entry) entry.income += t.amount;
      } else {
        const entry = categoryTotals[t.category];
        if (entry) entry.expense += t.amount;
      }
    });

    return Object.entries(categoryTotals).map(([name, values]) => ({
      name,
      receitas: values.income,
      despesas: values.expense,
    }));
  }, [filteredTransactions]);

  const getPieChartData = (type: "income" | "expense"): ChartDataItem[] => {
    const filtered = filteredTransactions.filter((t) => t.type === type);
    const categoryTotals: Record<string, number> = {};

    filtered.forEach((t) => {
      categoryTotals[t.category] = (categoryTotals[t.category] || 0) + t.amount;
    });

    return Object.entries(categoryTotals)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value);
  };

  const monthlyTrend = useMemo((): MonthlyData[] => {
    const monthlyData: Record<string, MonthlyData> = {};

    transactions.forEach((t) => {
      const date = new Date(t.date);
      const monthKey =
        date.getFullYear() + "-" + String(date.getMonth() + 1).padStart(2, "0");

      if (!monthlyData[monthKey]) {
        monthlyData[monthKey] = { month: monthKey, receitas: 0, despesas: 0 };
      }

      if (t.type === "income") {
        const entry = monthlyData[monthKey];
        if (entry) entry.receitas += t.amount;
      } else {
        const entry = monthlyData[monthKey];
        if (entry) entry.despesas += t.amount;
      }
    });

    return Object.values(monthlyData)
      .sort((a, b) => a.month.localeCompare(b.month))
      .slice(-6);
  }, [transactions]);

  return {
    transactions,
    allTransactions: transactions,
    filteredTransactions,
    isLoading,
    filter,
    setFilter,
    dateFilter,
    setDateFilter,
    searchTerm,
    setSearchTerm,
    addTransaction,
    updateTransaction,
    deleteTransaction,
    totals,
    categoryData,
    getPieChartData,
    monthlyTrend,
    error,
    refresh: fetchTransactions,
  };
};

import { useEffect } from 'react';
import { logger } from '@/lib/logger';

interface WebVitalsMetric {
  name: string;
  value: number;
  rating: 'good' | 'needs-improvement' | 'poor';
  delta: number;
  id: string;
}

const thresholds = {
  CLS: { good: 0.1, poor: 0.25 },
  FID: { good: 100, poor: 300 },
  FCP: { good: 1800, poor: 3000 },
  LCP: { good: 2500, poor: 4000 },
  TTFB: { good: 800, poor: 1800 },
  INP: { good: 200, poor: 500 },
};

function getRating(name: string, value: number): 'good' | 'needs-improvement' | 'poor' {
  const threshold = thresholds[name as keyof typeof thresholds];
  if (!threshold) return 'good';
  
  if (value <= threshold.good) return 'good';
  if (value <= threshold.poor) return 'needs-improvement';
  return 'poor';
}

function sendToAnalytics(metric: WebVitalsMetric) {
  // Log in development
  if (import.meta.env.DEV) {
    const emoji = metric.rating === 'good' ? '✅' : metric.rating === 'needs-improvement' ? '⚠️' : '❌';
    logger.info(`${emoji} Web Vital: ${metric.name}`, {
      value: Math.round(metric.value),
      rating: metric.rating,
    });
  }

  if (!import.meta.env.DEV) {
    // Simulated Google Analytics / Mixpanel event
    console.debug(`[Analytics] Web Vital: ${metric.name}`, metric.value);
  }
  // gtag('event', metric.name, {
  //   value: Math.round(metric.value),
  //   metric_rating: metric.rating,
  //   metric_delta: Math.round(metric.delta),
  // });
}

export function useWebVitals() {
  useEffect(() => {
    // Dynamically import web-vitals to avoid bundling if not used
    import('web-vitals').then(({ onCLS, onFID, onFCP, onLCP, onTTFB, onINP }) => {
      const handleMetric = (metric: any) => {
        const webVitalsMetric: WebVitalsMetric = {
          name: metric.name,
          value: metric.value,
          rating: getRating(metric.name, metric.value),
          delta: metric.delta,
          id: metric.id,
        };
        sendToAnalytics(webVitalsMetric);
      };

