// ============= Full Backup =============
export const exportFullBackup = () => {
  const backup = {
    transactions: loadTransactions(),
    budgets: loadBudgets(),
    goals: loadGoals(),
    reminders: loadReminders(),
    invoices: loadInvoices(),
    cashFlow: loadCashFlow(),
    investments: loadInvestments(),
    profile: loadProfile(),
    timestamp: new Date().toISOString(),
    version: "1.0",
  };

  const dataStr = JSON.stringify(backup, null, 2);
  const dataBlob = new Blob([dataStr], { type: "application/json" });
  const url = URL.createObjectURL(dataBlob);
  const link = document.createElement("a");
  link.href = url;
  link.download = `meu-contador-backup-${
    new Date().toISOString().split("T")[0]
  }.json`;
  link.click();
  URL.revokeObjectURL(url);
};

export const importFullBackup = (file: File): Promise<void> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const backup = JSON.parse(event.target?.result as string);

        // Basic validation
        if (!backup.timestamp || !backup.version) {
          reject(new Error("Arquivo de backup inválido"));
          return;
        }

        // Restore all keys
        if (backup.transactions) saveTransactions(backup.transactions);
        if (backup.budgets) saveBudgets(backup.budgets);
        if (backup.goals) saveGoals(backup.goals);
        if (backup.reminders) saveReminders(backup.reminders);
        if (backup.invoices) saveInvoices(backup.invoices);
        if (backup.cashFlow) saveCashFlow(backup.cashFlow);
        if (backup.investments) saveInvestments(backup.investments);
        if (backup.profile) saveProfile(backup.profile);

        resolve();
      } catch (error) {
        reject(new Error("Erro ao processar arquivo de backup"));
      }
    };
    reader.readAsText(file);
  });
};

import React, { useState, useEffect, createContext, useCallback } from 'react';

interface Toast {
  id: string;
  message: string;
  type: 'success' | 'error' | 'loading' | 'info';
  duration?: number;
}

interface ToastContextType {
  toasts: Toast[];
  addToast: (toast: Omit<Toast, 'id'>) => string;
  removeToast: (id: string) => void;
}

const ToastContext = createContext<ToastContextType | undefined>(undefined);

let toastCallback: ((toast: Omit<Toast, 'id'>) => string) | null = null;

export const ToastProvider: React.FC<{ children?: React.ReactNode }> = ({ children }) => {
  const [toasts, setToasts] = useState<Toast[]>([]);

  const addToast = useCallback((toast: Omit<Toast, 'id'>) => {
    const id = crypto.randomUUID();
    const newToast = { ...toast, id };

    setToasts(prev => [...prev, newToast]);

    // Auto remove after duration
    const duration = toast.duration ?? (toast.type === 'error' ? 5000 : 3000);
    if (toast.type !== 'loading') {
      setTimeout(() => {
        setToasts(prev => prev.filter(t => t.id !== id));
      }, duration);
    }

    return id;
  }, []);

  const removeToast = useCallback((id: string) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  // Register global callback
  useEffect(() => {
    toastCallback = addToast;
    return () => {
      toastCallback = null;
    };
  }, [addToast]);

  return (
    <ToastContext.Provider value={{ toasts, addToast, removeToast }}>
      {children}
      <ToastContainer toasts={toasts} onRemove={removeToast} />
    </ToastContext.Provider>
  );
};

const ToastContainer: React.FC<{ toasts: Toast[]; onRemove: (id: string) => void }> = ({ toasts, onRemove }) => {
  if (toasts.length === 0) return null;

  return (
    <div style={{
      position: 'fixed',
      bottom: 80,
      right: 16,
      zIndex: 9999,
      display: 'flex',
      flexDirection: 'column',
      gap: 8,
      maxWidth: 320,
    }}>
      {toasts.map(toast => (
        <div
          key={toast.id}
          onClick={() => onRemove(toast.id)}
          style={{
            padding: '12px 16px',
            borderRadius: 12,
            background: toast.type === 'error' ? 'rgba(255,79,110,0.95)' :
                       toast.type === 'success' ? 'rgba(0,217,145,0.95)' :
                       toast.type === 'loading' ? 'rgba(74,139,255,0.95)' :
                       'rgba(255,255,255,0.95)',
            color: toast.type === 'info' ? '#0a0f1a' : '#fff',
            fontSize: 13,
            fontWeight: 500,
            boxShadow: '0 8px 32px rgba(0,0,0,0.3)',
            cursor: 'pointer',
            animation: 'slideIn 0.3s ease-out',
            backdropFilter: 'blur(8px)',
          }}
        >
          {toast.type === 'loading' && '⏳ '}
          {toast.type === 'success' && '✅ '}
          {toast.type === 'error' && '❌ '}
          {toast.type === 'info' && 'ℹ️ '}
          {toast.message}
        </div>
      ))}
      <style>{`
        @keyframes slideIn {
          from {
            opacity: 0;
            transform: translateX(100%);
          }
          to {
            opacity: 1;
            transform: translateX(0);
          }
        }
      `}</style>
    </div>
  );
};

// Helper function to get the callback
const getToastCallback = () => {
  if (!toastCallback) {
    console.warn('ToastProvider not mounted, falling back to console');
    return null;
  }
  return toastCallback;
};

export const showSuccess = (message: any) => {
  const callback = getToastCallback();
  if (callback) {
    callback({ message: String(message), type: 'success' });
  } else {
    console.log("✅ [Toast Success]:", message);
  }
};

export const showError = (message: any) => {
  const callback = getToastCallback();
  if (callback) {
    callback({ message: String(message), type: 'error' });
  } else {
    console.error("❌ [Toast Error]:", message);
  }
};

export const showLoading = (message: any) => {
  const callback = getToastCallback();
  if (callback) {
    return callback({ message: String(message), type: 'loading', duration: 0 });
  } else {
    console.log("⏳ [Toast Loading]:", message);
    return crypto.randomUUID();
  }
};

export const dismissToast = (toastId: any) => {
  // The auto-removal handles this, but we can trigger immediate removal if needed
  console.log(" dismissToast called for:", toastId);
};

export const showPromise = async (promise: Promise<any>, messages: { loading: string; success: string; error: string }) => {
  const loadingId = showLoading(messages.loading);

  try {
    const result = await promise;
    dismissToast(loadingId);
    showSuccess(messages.success);
    return result;
  } catch (error) {
    dismissToast(loadingId);
    showError(messages.error);
    throw error;
  }
};
